    pub fn pin_host_value(&mut self, value: JsValue) -> u64 {
        let handle = self.next_host_pin_id;
        self.next_host_pin_id += 1;
        self.host_pins.insert(handle, value);
        handle
    }

    pub fn unpin_host_value(&mut self, handle: u64) -> Option<JsValue> {
        self.host_pins.remove(&handle)
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn register_module_cache_root_candidate(&mut self, value: JsValue) -> u64 {
        let handle = self.next_module_cache_root_candidate_id;
        self.next_module_cache_root_candidate_id = self
            .next_module_cache_root_candidate_id
            .checked_add(1)
            .expect("module root candidate handle overflow");
        self.module_cache_root_candidates.insert(handle, value);
        handle
    }

    #[cfg_attr(not(test), allow(dead_code))]
    pub(crate) fn release_module_cache_root_candidate(&mut self, handle: u64) -> Option<JsValue> {
        self.module_cache_root_candidates.remove(&handle)
    }

    fn clear_module_cache_root_candidates(&mut self) {
        self.module_cache_root_candidates.clear();
    }

    pub fn clear_module_cache(&mut self) {
        let handles: Vec<u64> = self
            .module_records
            .values()
            .filter_map(|record| record.root_candidate_handle)
            .collect();
        for handle in handles {
            let _ = self.release_module_cache_root_candidate(handle);
        }
        self.module_records.clear();
        self.module_evaluation_order.clear();
    }

