    fn add_collection_entries_from_iterable(
        &mut self,
        collection: JsValue,
        iterable: JsValue,
        adder: JsValue,
        mode: CollectionAddMode,
        realm: &Realm,
    ) -> Result<(), VmError> {
        let iterator_record = self.create_for_of_runtime_iterator_record(iterable, realm)?;
        loop {
            let step =
                self.execute_object_for_of_step(std::slice::from_ref(&iterator_record), realm)?;
            let done = self
                .get_property_from_receiver(step.clone(), "done", realm)
                .map(|value| self.is_truthy(&value))?;
            if done {
                break;
            }
            let next = match self.get_property_from_receiver(step, "value", realm) {
                Ok(value) => value,
                Err(err) => {
                    let _ = self
                        .execute_object_for_of_close(std::slice::from_ref(&iterator_record), realm);
                    return Err(err);
                }
            };
            let call_result = match mode {
                CollectionAddMode::Map | CollectionAddMode::WeakMap => {
                    if !Self::is_object_like_value(&next) {
                        Err(VmError::TypeError(match mode {
                            CollectionAddMode::Map => "Map iterable entries must be object",
                            CollectionAddMode::WeakMap => "WeakMap iterable entries must be object",
                            _ => unreachable!(),
                        }))
                    } else {
                        let key = self.get_property_from_receiver(next.clone(), "0", realm);
                        let value = self.get_property_from_receiver(next, "1", realm);
                        match (key, value) {
                            (Ok(key), Ok(value)) => {
                                if matches!(mode, CollectionAddMode::WeakMap) {
                                    self.require_weak_collection_object_key(&key, "WeakMap")?;
                                }
                                self.execute_callable(
                                    adder.clone(),
                                    Some(collection.clone()),
                                    vec![key, value],
                                    realm,
                                    false,
                                )
                                .map(|_| ())
                            }
                            (Err(err), _) | (_, Err(err)) => Err(err),
                        }
                    }
                }
                CollectionAddMode::Set | CollectionAddMode::WeakSet => {
                    if matches!(mode, CollectionAddMode::WeakSet) {
                        self.require_weak_collection_object_key(&next, "WeakSet")?;
                    }
                    self.execute_callable(
                        adder.clone(),
                        Some(collection.clone()),
                        vec![next],
                        realm,
                        false,
                    )
                    .map(|_| ())
                }
            };
            if let Err(err) = call_result {
                let _ =
                    self.execute_object_for_of_close(std::slice::from_ref(&iterator_record), realm);
                return Err(err);
            }
        }
        Ok(())
    }

    fn create_proxy_object(
        &mut self,
        target: JsValue,
        handler: JsValue,
    ) -> Result<JsValue, VmError> {
        if !Self::is_object_like_value(&target) {
            return Err(VmError::TypeError("Proxy target must be object"));
        }
        if !Self::is_object_like_value(&handler) {
            return Err(VmError::TypeError("Proxy handler must be object"));
        }
        let object = self.create_object_value();
        let object_id = match object {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let target_proto = self.get_prototype_of_value(&target)?;
        let (prototype, prototype_value) = match target_proto {
            JsValue::Object(proto_id) => (Some(proto_id), None),
            JsValue::Null => (None, None),
            other => (None, Some(other)),
        };
        {
            let proxy = self
                .objects
                .get_mut(&object_id)
                .ok_or(VmError::UnknownObject(object_id))?;
            proxy.prototype = prototype;
            proxy.prototype_value = prototype_value;
            proxy.is_proxy_object = true;
            proxy
                .properties
                .insert(PROXY_OBJECT_MARKER_KEY.to_string(), JsValue::Bool(true));
            proxy
                .properties
                .insert(PROXY_TARGET_KEY.to_string(), target.clone());
            proxy
                .properties
                .insert(PROXY_HANDLER_KEY.to_string(), handler.clone());
            proxy
                .properties
                .insert(PROXY_REVOKED_KEY.to_string(), JsValue::Bool(false));
            for key in [
                PROXY_OBJECT_MARKER_KEY,
                PROXY_TARGET_KEY,
                PROXY_HANDLER_KEY,
                PROXY_REVOKED_KEY,
            ] {
                proxy.property_attributes.insert(
                    key.to_string(),
                    PropertyAttributes {
                        writable: false,
                        enumerable: false,
                        configurable: false,
                    },
                );
            }
        }
        // Minimal ownKeys forwarding for Object.assign baseline:
        // mirror listed keys from the target as own data properties.
        let empty_realm = Realm::default();
        let own_keys_trap =
            self.get_property_from_receiver(handler.clone(), "ownKeys", &empty_realm)?;
        let (mirrored_keys, own_keys_from_trap) = if matches!(own_keys_trap, JsValue::Undefined) {
            (self.collect_own_property_keys(&target, false)?, false)
        } else {
            if !Self::is_callable_value(&own_keys_trap) {
                return Err(VmError::TypeError("Proxy ownKeys trap must be callable"));
            }
            let trap_result = self.execute_callable(
                own_keys_trap,
                Some(handler.clone()),
                vec![target.clone()],
                &empty_realm,
                false,
            )?;
            let trap_length = match &trap_result {
                JsValue::Object(array_id) => self.array_length(*array_id)?,
                _ => 0usize,
            };
            let mut keys = Vec::new();
            for index in 0..trap_length {
                let key_value = self.get_property_from_receiver(
                    trap_result.clone(),
                    &index.to_string(),
                    &empty_realm,
                )?;
                keys.push(self.coerce_to_string(&key_value));
            }
            (keys, true)
        };
        let mut mirrored = Vec::new();
        for key in mirrored_keys.iter().cloned() {
            if matches!(
                key.as_str(),
                PROXY_OBJECT_MARKER_KEY | PROXY_TARGET_KEY | PROXY_HANDLER_KEY | PROXY_REVOKED_KEY
            ) {
                continue;
            }
            let value = self.get_property_from_receiver(target.clone(), &key, &empty_realm)?;
            mirrored.push((key, value));
        }
        let proxy = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        for (key, value) in mirrored {
            proxy.properties.insert(key.clone(), value);
            proxy
                .property_attributes
                .entry(key)
                .or_insert(PropertyAttributes {
                    writable: true,
                    enumerable: true,
                    configurable: true,
                });
        }
        if own_keys_from_trap {
            proxy.properties.insert(
                PROXY_OWN_KEYS_ORDER_KEY.to_string(),
                JsValue::String(mirrored_keys.join("\u{1F}")),
            );
            proxy.property_attributes.insert(
                PROXY_OWN_KEYS_ORDER_KEY.to_string(),
                PropertyAttributes {
                    writable: false,
                    enumerable: false,
                    configurable: false,
                },
            );
        }
        Ok(JsValue::Object(object_id))
    }

    fn execute_proxy_constructor(
        &mut self,
        args: &[JsValue],
        called_with_new: bool,
    ) -> Result<JsValue, VmError> {
        if !called_with_new {
            return Err(VmError::TypeError("Proxy constructor requires 'new'"));
        }
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let handler = args.get(1).cloned().unwrap_or(JsValue::Undefined);
        self.create_proxy_object(target, handler)
    }

    fn execute_promise_constructor(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let executor = args.first().cloned().unwrap_or(JsValue::Undefined);
        if !Self::is_callable_value(&executor) {
            return Err(VmError::TypeError("Promise executor must be callable"));
        }
        let object_id = self.create_pending_promise()?;
        let resolve = self.create_host_function_value(HostFunction::FunctionPrototype);
        let reject = self.create_host_function_value(HostFunction::FunctionPrototype);
        let _ = self.execute_callable(
            executor,
            Some(JsValue::Undefined),
            vec![resolve, reject],
            realm,
            caller_strict,
        )?;
        Ok(JsValue::Object(object_id))
    }

    fn execute_promise_then(
        &mut self,
        args: &[JsValue],
        _realm: &Realm,
        _caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let source_promise_id = self.promise_object_id_from_this_arg(args.first())?;
        let on_fulfilled = args.get(1).cloned().unwrap_or(JsValue::Undefined);
        let on_rejected = args.get(2).cloned().unwrap_or(JsValue::Undefined);
        let reaction = PromiseReaction {
            kind: PromiseReactionKind::Then {
                on_fulfilled: Self::normalize_promise_handler(on_fulfilled),
                on_rejected: Self::normalize_promise_handler(on_rejected),
            },
            result_promise_id: self.create_pending_promise()?,
        };
        if let Some(settlement) = self.promise_settlement_from_object(source_promise_id)? {
            let mut hooks = NoopPromiseJobHostHooks;
            self.enqueue_promise_reaction_job(settlement, reaction.clone(), &mut hooks)?;
        } else {
            self.pending_promise_records
                .entry(source_promise_id)
                .or_default()
                .reactions
                .push(reaction.clone());
        }
        Ok(JsValue::Object(reaction.result_promise_id))
    }

    fn execute_promise_catch(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let then_args = vec![
            args.first().cloned().unwrap_or(JsValue::Undefined),
            JsValue::Undefined,
            args.get(1).cloned().unwrap_or(JsValue::Undefined),
        ];
        self.execute_promise_then(&then_args, realm, caller_strict)
    }

    fn execute_promise_finally(
        &mut self,
        args: &[JsValue],
        _realm: &Realm,
        _caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let source_promise_id = self.promise_object_id_from_this_arg(args.first())?;
        let on_finally = args.get(1).cloned().unwrap_or(JsValue::Undefined);
        let reaction = PromiseReaction {
            kind: PromiseReactionKind::Finally {
                on_finally: Self::normalize_promise_handler(on_finally),
            },
            result_promise_id: self.create_pending_promise()?,
        };
        if let Some(settlement) = self.promise_settlement_from_object(source_promise_id)? {
            let mut hooks = NoopPromiseJobHostHooks;
            self.enqueue_promise_reaction_job(settlement, reaction.clone(), &mut hooks)?;
        } else {
            self.pending_promise_records
                .entry(source_promise_id)
                .or_default()
                .reactions
                .push(reaction.clone());
        }
        Ok(JsValue::Object(reaction.result_promise_id))
    }

    fn normalize_promise_handler(value: JsValue) -> Option<JsValue> {
        if Self::is_callable_value(&value) {
            Some(value)
        } else {
            None
        }
    }

    fn promise_object_id_from_this_arg(
        &self,
        this_value: Option<&JsValue>,
    ) -> Result<ObjectId, VmError> {
        let Some(JsValue::Object(object_id)) = this_value else {
            return Err(VmError::TypeError(
                "Promise.prototype method called on incompatible receiver",
            ));
        };
        if !self
            .objects
            .get(object_id)
            .and_then(|object| object.properties.get("__promiseTag"))
            .is_some_and(|value| matches!(value, JsValue::Bool(true)))
        {
            return Err(VmError::TypeError(
                "Promise.prototype method called on incompatible receiver",
            ));
        }
        Ok(*object_id)
    }

    fn create_promise_object(&mut self) -> Result<ObjectId, VmError> {
        if self.promise_prototype_id.is_none() {
            let _ = self.promise_prototype_value();
        }
        let object = self.create_object_value();
        let object_id = match object {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let target = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        target.prototype = self.promise_prototype_id;
        target.prototype_value = None;
        target
            .properties
            .insert("__promiseTag".to_string(), JsValue::Bool(true));
        target.properties.insert(
            "__asyncState".to_string(),
            JsValue::String("pending".to_string()),
        );
        target
            .properties
            .insert("__asyncResult".to_string(), JsValue::Undefined);
        Ok(object_id)
    }

    fn create_pending_promise(&mut self) -> Result<ObjectId, VmError> {
        let object_id = self.create_promise_object()?;
        self.pending_promise_records.entry(object_id).or_default();
        Ok(object_id)
    }

    fn promise_settlement_from_object(
        &self,
        object_id: ObjectId,
    ) -> Result<Option<PromiseSettlement>, VmError> {
        let object = self
            .objects
            .get(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        let Some(JsValue::String(state)) = object.properties.get("__asyncState") else {
            return Ok(None);
        };
        let result = object
            .properties
            .get("__asyncResult")
            .cloned()
            .unwrap_or(JsValue::Undefined);
        match state.as_str() {
            "fulfilled" => Ok(Some(PromiseSettlement::Fulfilled(result))),
            "rejected" => Ok(Some(PromiseSettlement::Rejected(result))),
            _ => Ok(None),
        }
    }

    fn write_promise_settlement(
        &mut self,
        object_id: ObjectId,
        settlement: &PromiseSettlement,
    ) -> Result<(), VmError> {
        let object = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        match settlement {
            PromiseSettlement::Fulfilled(value) => {
                object.properties.insert(
                    "__asyncState".to_string(),
                    JsValue::String("fulfilled".to_string()),
                );
                object
                    .properties
                    .insert("__asyncResult".to_string(), value.clone());
            }
            PromiseSettlement::Rejected(reason) => {
                object.properties.insert(
                    "__asyncState".to_string(),
                    JsValue::String("rejected".to_string()),
                );
                object
                    .properties
                    .insert("__asyncResult".to_string(), reason.clone());
            }
        }
        Ok(())
    }

    fn create_async_settled_promise(
        &mut self,
        fulfilled: bool,
        result: JsValue,
    ) -> Result<JsValue, VmError> {
        let object_id = self.create_promise_object()?;
        let settlement = if fulfilled {
            PromiseSettlement::Fulfilled(result)
        } else {
            PromiseSettlement::Rejected(result)
        };
        self.write_promise_settlement(object_id, &settlement)?;
        Ok(JsValue::Object(object_id))
    }

    fn call_promise_hook(
        &mut self,
        hooks: &mut dyn PromiseJobHostHooks,
        hook: PromiseHook<'_>,
    ) -> Result<(), VmError> {
        if self.promise_job_queue.callback_in_progress {
            return Err(VmError::TypeError(
                TYPE_ERROR_PROMISE_JOB_CALLBACK_INTERACTION,
            ));
        }
        self.promise_job_queue.callback_in_progress = true;
        let error_token = match &hook {
            PromiseHook::Enqueue(_) => TYPE_ERROR_PROMISE_JOB_ON_ENQUEUE_FAILED,
            PromiseHook::DrainStart(_) => TYPE_ERROR_PROMISE_JOB_ON_DRAIN_START_FAILED,
            PromiseHook::DrainEnd(_) => TYPE_ERROR_PROMISE_JOB_ON_DRAIN_END_FAILED,
        };
        let callback_result = match hook {
            PromiseHook::Enqueue(pending_jobs) => hooks.on_enqueue(pending_jobs),
            PromiseHook::DrainStart(pending_jobs) => hooks.on_drain_start(pending_jobs),
            PromiseHook::DrainEnd(report) => hooks.on_drain_end(report),
        };
        self.promise_job_queue.callback_in_progress = false;
        if callback_result.is_err() {
            return Err(VmError::TypeError(error_token));
        }
        Ok(())
    }

    fn enqueue_promise_job(
        &mut self,
        job: PromiseJob,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        if self.promise_job_queue.callback_in_progress {
            return Err(VmError::TypeError(
                TYPE_ERROR_PROMISE_JOB_CALLBACK_INTERACTION,
            ));
        }
        self.promise_job_queue.jobs.push_back(job);
        let pending_jobs = self.promise_job_queue.jobs.len();
        if let Err(err) = self.call_promise_hook(hooks, PromiseHook::Enqueue(pending_jobs)) {
            if let Some(rolled_back) = self.promise_job_queue.jobs.pop_back() {
                self.release_job_capture_handles(rolled_back.capture_handles);
            }
            return Err(err);
        }
        Ok(())
    }

    fn enqueue_promise_reaction_job(
        &mut self,
        settlement: PromiseSettlement,
        reaction: PromiseReaction,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        let mut capture_handles = Vec::new();
        capture_handles.push(
            self.register_pending_job_root_candidate(JsValue::Object(reaction.result_promise_id)),
        );
        match &settlement {
            PromiseSettlement::Fulfilled(value) | PromiseSettlement::Rejected(value) => {
                capture_handles.push(self.register_pending_job_root_candidate(value.clone()));
            }
        }
        match &reaction.kind {
            PromiseReactionKind::Then {
                on_fulfilled,
                on_rejected,
            } => {
                if let Some(handler) = on_fulfilled {
                    capture_handles.push(self.register_pending_job_root_candidate(handler.clone()));
                }
                if let Some(handler) = on_rejected {
                    capture_handles.push(self.register_pending_job_root_candidate(handler.clone()));
                }
            }
            PromiseReactionKind::Finally { on_finally } => {
                if let Some(handler) = on_finally {
                    capture_handles.push(self.register_pending_job_root_candidate(handler.clone()));
                }
            }
        }
        self.enqueue_promise_job(
            PromiseJob {
                kind: PromiseJobKind::Reaction {
                    settlement,
                    reaction,
                },
                capture_handles,
            },
            hooks,
        )
    }

    fn execute_promise_job(
        &mut self,
        job: PromiseJob,
        realm: &Realm,
        caller_strict: bool,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        let result = match job.kind {
            PromiseJobKind::HostCapture => Ok(()),
            PromiseJobKind::Reaction {
                settlement,
                reaction,
            } => {
                self.execute_promise_reaction_job(settlement, reaction, realm, caller_strict, hooks)
            }
        };
        self.release_job_capture_handles(job.capture_handles);
        result
    }

    fn execute_promise_reaction_job(
        &mut self,
        settlement: PromiseSettlement,
        reaction: PromiseReaction,
        realm: &Realm,
        caller_strict: bool,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        match reaction.kind {
            PromiseReactionKind::Then {
                on_fulfilled,
                on_rejected,
            } => self.apply_then_reaction(
                settlement,
                (on_fulfilled, on_rejected),
                reaction.result_promise_id,
                realm,
                caller_strict,
                hooks,
            ),
            PromiseReactionKind::Finally { on_finally } => self.apply_finally_reaction(
                settlement,
                on_finally,
                reaction.result_promise_id,
                realm,
                caller_strict,
                hooks,
            ),
        }
    }

    fn apply_then_reaction(
        &mut self,
        settlement: PromiseSettlement,
        handlers: PromiseHandlers,
        result_promise_id: ObjectId,
        realm: &Realm,
        caller_strict: bool,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        let (on_fulfilled, on_rejected) = handlers;
        let next_settlement = match settlement {
            PromiseSettlement::Fulfilled(value) => {
                if let Some(handler) = on_fulfilled {
                    match self.execute_callable(
                        handler,
                        Some(JsValue::Undefined),
                        vec![value],
                        realm,
                        caller_strict,
                    ) {
                        Ok(next) => PromiseSettlement::Fulfilled(next),
                        Err(err) => {
                            let Some(rejection) =
                                self.promise_rejection_from_runtime_error(err.clone())
                            else {
                                return Err(err);
                            };
                            PromiseSettlement::Rejected(rejection)
                        }
                    }
                } else {
                    PromiseSettlement::Fulfilled(value)
                }
            }
            PromiseSettlement::Rejected(reason) => {
                if let Some(handler) = on_rejected {
                    match self.execute_callable(
                        handler,
                        Some(JsValue::Undefined),
                        vec![reason],
                        realm,
                        caller_strict,
                    ) {
                        Ok(next) => PromiseSettlement::Fulfilled(next),
                        Err(err) => {
                            let Some(rejection) =
                                self.promise_rejection_from_runtime_error(err.clone())
                            else {
                                return Err(err);
                            };
                            PromiseSettlement::Rejected(rejection)
                        }
                    }
                } else {
                    PromiseSettlement::Rejected(reason)
                }
            }
        };
        self.settle_promise_with_hooks(result_promise_id, next_settlement, hooks)
    }

    fn apply_finally_reaction(
        &mut self,
        settlement: PromiseSettlement,
        on_finally: Option<JsValue>,
        result_promise_id: ObjectId,
        realm: &Realm,
        caller_strict: bool,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        let next_settlement = if let Some(handler) = on_finally {
            match self.execute_callable(
                handler,
                Some(JsValue::Undefined),
                Vec::new(),
                realm,
                caller_strict,
            ) {
                Ok(finally_value) => {
                    if let Some(rejection) =
                        self.promise_rejection_from_finally_value(&finally_value)?
                    {
                        PromiseSettlement::Rejected(rejection)
                    } else {
                        settlement
                    }
                }
                Err(err) => {
                    let Some(rejection) = self.promise_rejection_from_runtime_error(err.clone())
                    else {
                        return Err(err);
                    };
                    PromiseSettlement::Rejected(rejection)
                }
            }
        } else {
            settlement
        };
        self.settle_promise_with_hooks(result_promise_id, next_settlement, hooks)
    }

    fn promise_rejection_from_runtime_error(&mut self, err: VmError) -> Option<JsValue> {
        match self.classify_vm_error(err) {
            VmError::UncaughtException(exception) => Some(exception),
            other => self.runtime_error_exception_value(&other),
        }
    }

    fn promise_rejection_from_finally_value(
        &self,
        value: &JsValue,
    ) -> Result<Option<JsValue>, VmError> {
        let JsValue::Object(object_id) = value else {
            return Ok(None);
        };
        let Some(settlement) = self.promise_settlement_from_object(*object_id)? else {
            return Ok(None);
        };
        match settlement {
            PromiseSettlement::Rejected(reason) => Ok(Some(reason)),
            PromiseSettlement::Fulfilled(_) => Ok(None),
        }
    }

    fn settle_promise_with_hooks(
        &mut self,
        promise_id: ObjectId,
        settlement: PromiseSettlement,
        hooks: &mut dyn PromiseJobHostHooks,
    ) -> Result<(), VmError> {
        if self.promise_settlement_from_object(promise_id)?.is_some() {
            return Ok(());
        }
        self.write_promise_settlement(promise_id, &settlement)?;
        if let Some(record) = self.pending_promise_records.remove(&promise_id) {
            for reaction in record.reactions {
                self.enqueue_promise_reaction_job(settlement.clone(), reaction, hooks)?;
            }
        }
        Ok(())
    }

    fn release_job_capture_handles(&mut self, handles: Vec<u64>) {
        for handle in handles {
            let _ = self.release_pending_job_root_candidate(handle);
        }
    }

    fn execute_uint8_array_constructor(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let length = args
            .first()
            .map(|value| self.to_number(value))
            .filter(|value| value.is_finite() && *value >= 0.0)
            .unwrap_or(0.0)
            .floor() as usize;
        if self.uint8_array_prototype_id.is_none() {
            let _ = self.uint8_array_prototype_value();
        }
        let object = self.create_object_value();
        let object_id = match object {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let target = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        target.prototype = self.uint8_array_prototype_id;
        target.prototype_value = None;
        target
            .properties
            .insert("__uint8ArrayTag".to_string(), JsValue::Bool(true));
        target
            .properties
            .insert("length".to_string(), JsValue::Number(length as f64));
        target.property_attributes.insert(
            "length".to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: false,
            },
        );
        target
            .properties
            .insert("byteLength".to_string(), JsValue::Number(length as f64));
        target.property_attributes.insert(
            "byteLength".to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: false,
            },
        );
        for index in 0..length {
            let key = index.to_string();
            target.properties.insert(key.clone(), JsValue::Number(0.0));
            target.property_attributes.insert(
                key,
                PropertyAttributes {
                    writable: true,
                    enumerable: true,
                    configurable: false,
                },
            );
        }
        Ok(JsValue::Object(object_id))
    }

    fn execute_object_create(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let (prototype, prototype_value) =
            self.parse_prototype_value(args.first().cloned().unwrap_or(JsValue::Undefined))?;

        let object = self.create_object_value();
        let object_id = match object {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let target = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        target.prototype = prototype;
        target.prototype_value = prototype_value;
        if !matches!(args.get(1), None | Some(JsValue::Undefined)) {
            let descriptors = self.coerce_object_for_object_builtins(
                args.get(1).cloned().unwrap_or(JsValue::Undefined),
                "Object.create properties must be coercible",
            )?;
            let define_args = [JsValue::Object(object_id), descriptors];
            let _ = self.execute_object_define_properties(&define_args, realm)?;
        }
        Ok(JsValue::Object(object_id))
    }

    fn execute_object_assign(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.assign target must be coercible",
        )?;

        for source in args.iter().skip(1).cloned() {
            if matches!(source, JsValue::Null | JsValue::Undefined) {
                continue;
            }
            let source_object = self.coerce_object_for_object_builtins(
                source,
                "Object.assign source must be coercible",
            )?;
            let keys = self.collect_own_property_keys(&source_object, true)?;

            for key in keys {
                let value = self.get_property_from_receiver(source_object.clone(), &key, realm)?;
                self.ensure_assign_target_writable(&target, &key)?;
                let _ = self.set_property_on_receiver(target.clone(), key, value, realm)?;
            }
        }
        Ok(target)
    }

    fn coerce_object_for_object_builtins(
        &mut self,
        value: JsValue,
        null_undefined_error: &'static str,
    ) -> Result<JsValue, VmError> {
        match value {
            JsValue::Null | JsValue::Undefined => Err(VmError::TypeError(null_undefined_error)),
            value @ (JsValue::Object(_)
            | JsValue::Function(_)
            | JsValue::NativeFunction(_)
            | JsValue::HostFunction(_)) => Ok(value),
            primitive @ (JsValue::Number(_) | JsValue::Bool(_) | JsValue::String(_)) => {
                Ok(self.box_primitive_receiver(primitive))
            }
            _ => Ok(self.create_object_value()),
        }
    }

    fn collect_own_property_keys(
        &self,
        value: &JsValue,
        enumerable_only: bool,
    ) -> Result<Vec<String>, VmError> {
        match value {
            JsValue::Object(object_id) => {
                let object = self
                    .objects
                    .get(object_id)
                    .ok_or(VmError::UnknownObject(*object_id))?;
                if self.has_object_marker(*object_id, PROXY_OBJECT_MARKER_KEY)? {
                    if let Some(JsValue::String(order)) =
                        object.properties.get(PROXY_OWN_KEYS_ORDER_KEY)
                    {
                        let mut keys = if order.is_empty() {
                            Vec::new()
                        } else {
                            order.split('\u{1F}').map(|key| key.to_string()).collect()
                        };
                        if enumerable_only {
                            keys.retain(|key| {
                                object
                                    .property_attributes
                                    .get(key)
                                    .map(|attrs| attrs.enumerable)
                                    .unwrap_or(true)
                            });
                        }
                        return Ok(keys);
                    }
                }
                Ok(Self::collect_own_property_keys_from_object(
                    object,
                    enumerable_only,
                ))
            }
            JsValue::Function(closure_id) => {
                let mut object = self
                    .closure_objects
                    .get(closure_id)
                    .cloned()
                    .unwrap_or_default();
                object
                    .properties
                    .entry("length".to_string())
                    .or_insert(JsValue::Undefined);
                object
                    .property_attributes
                    .entry("length".to_string())
                    .or_insert(PropertyAttributes {
                        writable: false,
                        enumerable: false,
                        configurable: true,
                    });
                if let Ok(is_arrow) = self.closure_is_arrow(*closure_id) {
                    if !is_arrow && !self.closure_has_no_prototype(*closure_id) {
                        object
                            .properties
                            .entry("prototype".to_string())
                            .or_insert(JsValue::Undefined);
                        object
                            .property_attributes
                            .entry("prototype".to_string())
                            .or_insert(PropertyAttributes {
                                writable: true,
                                enumerable: false,
                                configurable: false,
                            });
                    }
                }
                Ok(Self::collect_own_property_keys_from_object(
                    &object,
                    enumerable_only,
                ))
            }
            JsValue::HostFunction(host_id) => {
                let mut object = self
                    .host_function_objects
                    .get(host_id)
                    .cloned()
                    .unwrap_or_default();
                if !self.host_function_objects.contains_key(host_id) {
                    for key in [
                        "length",
                        "call",
                        "apply",
                        "bind",
                        "toString",
                        "valueOf",
                        "hasOwnProperty",
                        "constructor",
                    ] {
                        object
                            .properties
                            .entry(key.to_string())
                            .or_insert(JsValue::Undefined);
                        object.property_attributes.entry(key.to_string()).or_insert(
                            PropertyAttributes {
                                writable: key != "length",
                                enumerable: false,
                                configurable: true,
                            },
                        );
                    }
                }
                Ok(Self::collect_own_property_keys_from_object(
                    &object,
                    enumerable_only,
                ))
            }
            JsValue::NativeFunction(native) => {
                let mut object = self
                    .native_function_objects
                    .get(native)
                    .cloned()
                    .unwrap_or_default();
                const NATIVE_DEFAULT_KEYS: &[&str] = &[
                    "defineProperty",
                    "defineProperties",
                    "keys",
                    "entries",
                    "values",
                    "getOwnPropertyNames",
                    "create",
                    "assign",
                    "setPrototypeOf",
                    "preventExtensions",
                    "__forInKeys",
                    "__forOfValues",
                    "__forOfIterator",
                    "__forOfStep",
                    "__forOfClose",
                    "__getTemplateObject",
                    "__tdzMarker",
                    "getOwnPropertyDescriptor",
                    "getOwnPropertyDescriptors",
                    "getPrototypeOf",
                    "isExtensible",
                    "isSealed",
                    "isFrozen",
                    "is",
                    "seal",
                    "freeze",
                    "toString",
                    "valueOf",
                    "isArray",
                    "from",
                    "of",
                    "parse",
                    "UTC",
                    "revocable",
                    "fromCharCode",
                    "NaN",
                    "POSITIVE_INFINITY",
                    "NEGATIVE_INFINITY",
                    "MAX_VALUE",
                    "MIN_VALUE",
                    "MAX_SAFE_INTEGER",
                    "MIN_SAFE_INTEGER",
                    "iterator",
                    "asyncIterator",
                    "hasInstance",
                    "isConcatSpreadable",
                    "match",
                    "matchAll",
                    "replace",
                    "search",
                    "species",
                    "split",
                    "toPrimitive",
                    "toStringTag",
                    "unscopables",
                    "sameValue",
                    "notSameValue",
                    "throws",
                    "compareArray",
                    "prototype",
                    "name",
                    "length",
                    "constructor",
                ];
                for key in NATIVE_DEFAULT_KEYS {
                    if !self.native_function_has_own_property_runtime(*native, key) {
                        continue;
                    }
                    object
                        .properties
                        .entry((*key).to_string())
                        .or_insert(JsValue::Undefined);
                    object
                        .property_attributes
                        .entry((*key).to_string())
                        .or_insert_with(|| {
                            self.native_function_default_property_attributes(*native, key)
                                .unwrap_or(PropertyAttributes {
                                    writable: true,
                                    enumerable: false,
                                    configurable: true,
                                })
                        });
                }
                Ok(Self::collect_own_property_keys_from_object(
                    &object,
                    enumerable_only,
                ))
            }
            _ => Err(VmError::TypeError("property keys target must be object")),
        }
    }

    fn collect_own_property_keys_from_object(
        object: &JsObject,
        enumerable_only: bool,
    ) -> Vec<String> {
        let mut all_keys = BTreeSet::new();
        all_keys.extend(object.properties.keys().cloned());
        all_keys.extend(object.getters.keys().cloned());
        all_keys.extend(object.setters.keys().cloned());

        let mut index_keys: Vec<(usize, String)> = Vec::new();
        let mut string_keys = Vec::new();
        for key in all_keys {
            let enumerable = object
                .property_attributes
                .get(&key)
                .map(|attrs| attrs.enumerable)
                .unwrap_or(true);
            if enumerable_only && !enumerable {
                continue;
            }
            if let Some(index) = Self::canonical_array_index(&key) {
                index_keys.push((index, key));
            } else {
                string_keys.push(key);
            }
        }
        index_keys.sort_by_key(|(index, _)| *index);
        let mut keys = Vec::with_capacity(index_keys.len() + string_keys.len());
        keys.extend(index_keys.into_iter().map(|(_, key)| key));
        keys.extend(string_keys);
        keys
    }

    fn own_property_is_enumerable(
        &self,
        target: &JsValue,
        property: &str,
    ) -> Result<bool, VmError> {
        match target {
            JsValue::Object(object_id) => {
                let object = self
                    .objects
                    .get(object_id)
                    .ok_or(VmError::UnknownObject(*object_id))?;
                if !(object.properties.contains_key(property)
                    || object.getters.contains_key(property)
                    || object.setters.contains_key(property))
                {
                    return Ok(false);
                }
                Ok(object
                    .property_attributes
                    .get(property)
                    .map(|attrs| attrs.enumerable)
                    .unwrap_or(true))
            }
            JsValue::Function(closure_id) => {
                if let Some(object) = self.closure_objects.get(closure_id) {
                    if object.properties.contains_key(property)
                        || object.getters.contains_key(property)
                        || object.setters.contains_key(property)
                    {
                        return Ok(object
                            .property_attributes
                            .get(property)
                            .map(|attrs| attrs.enumerable)
                            .unwrap_or(true));
                    }
                }
                Ok(false)
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(host_id) {
                    return Err(VmError::UnknownHostFunction(*host_id));
                }
                if let Some(object) = self.host_function_objects.get(host_id) {
                    if object.properties.contains_key(property)
                        || object.getters.contains_key(property)
                        || object.setters.contains_key(property)
                    {
                        return Ok(object
                            .property_attributes
                            .get(property)
                            .map(|attrs| attrs.enumerable)
                            .unwrap_or(true));
                    }
                }
                Ok(false)
            }
            JsValue::NativeFunction(native) => {
                if let Some(object) = self.native_function_objects.get(native) {
                    if object.properties.contains_key(property)
                        || object.getters.contains_key(property)
                        || object.setters.contains_key(property)
                    {
                        return Ok(object
                            .property_attributes
                            .get(property)
                            .map(|attrs| attrs.enumerable)
                            .unwrap_or(true));
                    }
                }
                Ok(false)
            }
            _ => Ok(false),
        }
    }

    fn ensure_assign_target_writable(
        &self,
        target: &JsValue,
        property: &str,
    ) -> Result<(), VmError> {
        let target_object = match target {
            JsValue::Object(object_id) => {
                if property == "length"
                    && self
                        .boxed_primitive_value(*object_id)
                        .is_some_and(|value| matches!(value, JsValue::String(_)))
                {
                    return Err(VmError::TypeError("cannot assign to readonly property"));
                }
                self.objects
                    .get(object_id)
                    .cloned()
                    .ok_or(VmError::UnknownObject(*object_id))?
            }
            JsValue::Function(closure_id) => {
                if property == "length" && !self.closure_has_own_property(*closure_id, "length") {
                    return Err(VmError::TypeError("cannot assign to readonly property"));
                }
                self.closure_objects
                    .get(closure_id)
                    .cloned()
                    .unwrap_or_default()
            }
            JsValue::HostFunction(host_id) => {
                if property == "length"
                    && self
                        .host_function_objects
                        .get(host_id)
                        .is_none_or(|object| {
                            object
                                .property_attributes
                                .get("length")
                                .map(|attrs| !attrs.writable)
                                .unwrap_or(true)
                        })
                {
                    return Err(VmError::TypeError("cannot assign to readonly property"));
                }
                self.host_function_objects
                    .get(host_id)
                    .cloned()
                    .unwrap_or_default()
            }
            JsValue::NativeFunction(native) => {
                if property == "length"
                    && self.native_function_has_own_property_runtime(*native, "length")
                    && !self.native_function_is_property_writable(*native, "length")
                {
                    return Err(VmError::TypeError("cannot assign to readonly property"));
                }
                self.native_function_objects
                    .get(native)
                    .cloned()
                    .unwrap_or_default()
            }
            _ => return Ok(()),
        };

        if let Some(setter) = target_object.setters.get(property) {
            if !matches!(setter, JsValue::Undefined) {
                return Ok(());
            }
            return Err(VmError::TypeError("cannot assign to readonly property"));
        }
        if target_object.getters.contains_key(property) {
            return Err(VmError::TypeError("cannot assign to readonly property"));
        }
        if target_object.properties.contains_key(property) {
            let writable = target_object
                .property_attributes
                .get(property)
                .map(|attrs| attrs.writable)
                .unwrap_or(true);
            if !writable {
                return Err(VmError::TypeError("cannot assign to readonly property"));
            }
            return Ok(());
        }
        if !target_object.extensible {
            return Err(VmError::TypeError("cannot assign to non-extensible target"));
        }
        Ok(())
    }

    fn execute_object_set_prototype_of(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);

        let (prototype, prototype_value) =
            self.parse_prototype_value(args.get(1).cloned().unwrap_or(JsValue::Undefined))?;

        if matches!(target, JsValue::Null | JsValue::Undefined) {
            return Err(VmError::TypeError(
                "Object.setPrototypeOf target must be object",
            ));
        }
        if !Self::is_object_like_value(&target) {
            return Ok(target);
        }
        if self.prototype_would_create_cycle(&target, prototype, prototype_value.clone())? {
            return Err(VmError::TypeError(
                "Object.setPrototypeOf would create a prototype cycle",
            ));
        }

        match target {
            JsValue::Object(target_id) => {
                let object = self
                    .objects
                    .get_mut(&target_id)
                    .ok_or(VmError::UnknownObject(target_id))?;
                let unchanged =
                    object.prototype == prototype && object.prototype_value == prototype_value;
                if !object.extensible && !unchanged {
                    return Err(VmError::TypeError(
                        "Object.setPrototypeOf target must be extensible",
                    ));
                }
                object.prototype = prototype;
                object.prototype_value = prototype_value.clone();
                Ok(JsValue::Object(target_id))
            }
            JsValue::Function(closure_id) => {
                if !self.closures.contains_key(&closure_id) {
                    return Err(VmError::UnknownClosure(closure_id));
                }
                let closure_object = self.closure_objects.entry(closure_id).or_default();
                let unchanged = closure_object.prototype == prototype
                    && closure_object.prototype_value == prototype_value;
                if !closure_object.extensible && !unchanged {
                    return Err(VmError::TypeError(
                        "Object.setPrototypeOf target must be extensible",
                    ));
                }
                closure_object.prototype = prototype;
                closure_object.prototype_value = prototype_value.clone();
                closure_object.prototype_overridden = true;
                Ok(JsValue::Function(closure_id))
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(&host_id) {
                    return Err(VmError::UnknownHostFunction(host_id));
                }
                let host_object = self.host_function_objects.entry(host_id).or_default();
                let unchanged = host_object.prototype == prototype
                    && host_object.prototype_value == prototype_value;
                if !host_object.extensible && !unchanged {
                    return Err(VmError::TypeError(
                        "Object.setPrototypeOf target must be extensible",
                    ));
                }
                host_object.prototype = prototype;
                host_object.prototype_value = prototype_value;
                host_object.prototype_overridden = true;
                Ok(JsValue::HostFunction(host_id))
            }
            JsValue::NativeFunction(native) => {
                let native_object = self.native_function_objects.entry(native).or_default();
                let unchanged = native_object.prototype == prototype
                    && native_object.prototype_value == prototype_value;
                if !native_object.extensible && !unchanged {
                    return Err(VmError::TypeError(
                        "Object.setPrototypeOf target must be extensible",
                    ));
                }
                native_object.prototype = prototype;
                native_object.prototype_value = prototype_value;
                native_object.prototype_overridden = true;
                Ok(JsValue::NativeFunction(native))
            }
            _ => Ok(target),
        }
    }

    fn prototype_would_create_cycle(
        &mut self,
        target: &JsValue,
        prototype: Option<ObjectId>,
        prototype_value: Option<JsValue>,
    ) -> Result<bool, VmError> {
        let mut current = if let Some(id) = prototype {
            JsValue::Object(id)
        } else if let Some(value) = prototype_value {
            value
        } else {
            return Ok(false);
        };
        let mut guard = 0usize;
        while Self::is_object_like_value(&current) {
            if self.same_value(&current, target) {
                return Ok(true);
            }
            current = self.get_prototype_of_value(&current)?;
            guard += 1;
            if guard > 1024 {
                break;
            }
        }
        Ok(false)
    }

    fn parse_prototype_value(
        &self,
        value: JsValue,
    ) -> Result<(Option<ObjectId>, Option<JsValue>), VmError> {
        match value {
            JsValue::Object(object_id) => Ok((Some(object_id), None)),
            JsValue::Null => Ok((None, None)),
            JsValue::Function(_) | JsValue::NativeFunction(_) | JsValue::HostFunction(_) => {
                Ok((None, Some(value)))
            }
            _ => Err(VmError::TypeError(
                "Object prototype may only be an Object or null",
            )),
        }
    }

    fn prototype_components_of_value(
        &self,
        value: &JsValue,
    ) -> Option<(Option<ObjectId>, Option<JsValue>)> {
        match value {
            JsValue::Object(object_id) => self
                .objects
                .get(object_id)
                .map(|object| (object.prototype, object.prototype_value.clone())),
            JsValue::Function(closure_id) => self
                .closure_objects
                .get(closure_id)
                .map(|object| (object.prototype, object.prototype_value.clone())),
            JsValue::HostFunction(host_id) => self
                .host_function_objects
                .get(host_id)
                .map(|object| (object.prototype, object.prototype_value.clone())),
            _ => None,
        }
    }

    fn apply_prototype_components_to_value(
        &mut self,
        value: &JsValue,
        prototype: Option<ObjectId>,
        prototype_value: Option<JsValue>,
    ) {
        match value {
            JsValue::Object(object_id) => {
                if let Some(object) = self.objects.get_mut(object_id) {
                    object.prototype = prototype;
                    object.prototype_value = prototype_value;
                }
            }
            JsValue::Function(closure_id) => {
                let object = self.closure_objects.entry(*closure_id).or_default();
                object.prototype = prototype;
                object.prototype_value = prototype_value;
                object.prototype_overridden = true;
            }
            JsValue::HostFunction(host_id) => {
                let object = self.host_function_objects.entry(*host_id).or_default();
                object.prototype = prototype;
                object.prototype_value = prototype_value;
                object.prototype_overridden = true;
            }
            _ => {}
        }
    }

    fn execute_date_constructor(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let timestamp = if args.is_empty() {
            SystemTime::now()
                .duration_since(UNIX_EPOCH)
                .map(|duration| duration.as_millis() as f64)
                .unwrap_or(0.0)
        } else if args.len() == 1 {
            match args.first().cloned().unwrap_or(JsValue::Undefined) {
                JsValue::String(text) => Self::time_clip(
                    self.parse_date_string_baseline(text.trim())
                        .unwrap_or(f64::NAN),
                ),
                value => {
                    Self::time_clip(self.coerce_number_runtime(value, realm, caller_strict)?)
                }
            }
        } else {
            self.date_utc_from_components(args, realm, caller_strict)?
        };
        let local_components = if timestamp.is_nan() {
            None
        } else {
            Some(Self::utc_date_parts_from_timestamp(timestamp))
        };
        let object = self.create_object_value();
        let object_id = match object {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let to_string = self.create_host_function_value(HostFunction::DateToString(object_id));
        let value_of = self.create_host_function_value(HostFunction::DateValueOf(object_id));
        if self.date_prototype_id.is_none() {
            let _ = self.date_prototype_value();
        }
        let target = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        target.prototype = self.date_prototype_id;
        target.prototype_value = None;
        target
            .properties
            .insert(DATE_OBJECT_MARKER_KEY.to_string(), JsValue::Bool(true));
        target
            .properties
            .insert(DATE_VALUE_KEY.to_string(), JsValue::Number(timestamp));
        target.properties.insert("toString".to_string(), to_string);
        target.properties.insert("valueOf".to_string(), value_of);
        target.properties.insert(
            "constructor".to_string(),
            JsValue::NativeFunction(NativeFunction::DateConstructor),
        );
        target.property_attributes.insert(
            DATE_OBJECT_MARKER_KEY.to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: false,
            },
        );
        target.property_attributes.insert(
            DATE_VALUE_KEY.to_string(),
            PropertyAttributes {
                writable: true,
                enumerable: false,
                configurable: false,
            },
        );
        if let Some((year, month, day)) = local_components {
            target
                .properties
                .insert("__dateYear".to_string(), JsValue::Number(year as f64));
            target
                .properties
                .insert("__dateMonth".to_string(), JsValue::Number(month as f64));
            target
                .properties
                .insert("__dateDay".to_string(), JsValue::Number(day as f64));
        } else {
            target.properties.remove("__dateYear");
            target.properties.remove("__dateMonth");
            target.properties.remove("__dateDay");
        }
        Ok(JsValue::Object(object_id))
    }

    fn parse_property_descriptor(
        &mut self,
        descriptor: JsValue,
        realm: &Realm,
    ) -> Result<PropertyDescriptorTuple, VmError> {
        let descriptor = match descriptor {
            value @ (JsValue::Object(_)
            | JsValue::Function(_)
            | JsValue::NativeFunction(_)
            | JsValue::HostFunction(_)) => value,
            _ => return Err(VmError::TypeError("property descriptor must be object")),
        };
        let has_value = self.has_property_on_receiver(&descriptor, "value", realm)?;
        let desc_value = if has_value {
            self.get_property_from_receiver(descriptor.clone(), "value", realm)?
        } else {
            JsValue::Undefined
        };
        let has_get = self.has_property_on_receiver(&descriptor, "get", realm)?;
        let desc_get = if has_get {
            self.get_property_from_receiver(descriptor.clone(), "get", realm)?
        } else {
            JsValue::Undefined
        };
        if has_get && !matches!(desc_get, JsValue::Undefined) && !Self::is_callable_value(&desc_get)
        {
            return Err(VmError::TypeError("getter must be callable or undefined"));
        }
        let has_set = self.has_property_on_receiver(&descriptor, "set", realm)?;
        let desc_set = if has_set {
            self.get_property_from_receiver(descriptor.clone(), "set", realm)?
        } else {
            JsValue::Undefined
        };
        if has_set && !matches!(desc_set, JsValue::Undefined) && !Self::is_callable_value(&desc_set)
        {
            return Err(VmError::TypeError("setter must be callable or undefined"));
        }
        let desc_writable = if self.has_property_on_receiver(&descriptor, "writable", realm)? {
            let writable =
                self.get_property_from_receiver(descriptor.clone(), "writable", realm)?;
            Some(self.is_truthy(&writable))
        } else {
            None
        };
        let desc_enumerable = if self.has_property_on_receiver(&descriptor, "enumerable", realm)? {
            let enumerable =
                self.get_property_from_receiver(descriptor.clone(), "enumerable", realm)?;
            Some(self.is_truthy(&enumerable))
        } else {
            None
        };
        let desc_configurable =
            if self.has_property_on_receiver(&descriptor, "configurable", realm)? {
                let configurable =
                    self.get_property_from_receiver(descriptor, "configurable", realm)?;
                Some(self.is_truthy(&configurable))
            } else {
                None
            };
        if (has_get || has_set) && (has_value || desc_writable.is_some()) {
            return Err(VmError::TypeError(
                "cannot have setter/getter and value or writable",
            ));
        }
        Ok((
            has_value,
            desc_value,
            has_get,
            desc_get,
            has_set,
            desc_set,
            desc_writable,
            desc_enumerable,
            desc_configurable,
        ))
    }

    fn materialize_property_descriptor(&mut self, descriptor: &PropertyDescriptorTuple) -> JsValue {
        let (has_value, value, has_get, get, has_set, set, writable, enumerable, configurable) =
            descriptor;
        let mut entries = Vec::new();
        if *has_value {
            entries.push(("value", value.clone()));
        }
        if *has_get {
            entries.push(("get", get.clone()));
        }
        if *has_set {
            entries.push(("set", set.clone()));
        }
        if let Some(writable) = *writable {
            entries.push(("writable", JsValue::Bool(writable)));
        }
        if let Some(enumerable) = *enumerable {
            entries.push(("enumerable", JsValue::Bool(enumerable)));
        }
        if let Some(configurable) = *configurable {
            entries.push(("configurable", JsValue::Bool(configurable)));
        }
        self.create_descriptor_object(entries)
    }

    fn execute_object_define_property(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let property = self.coerce_to_property_key_runtime(
            args.get(1).cloned().unwrap_or(JsValue::Undefined),
            realm,
            false,
        )?;
        let (
            has_value,
            desc_value,
            has_get,
            desc_get,
            has_set,
            desc_set,
            desc_writable,
            desc_enumerable,
            desc_configurable,
        ) = self
            .parse_property_descriptor(args.get(2).cloned().unwrap_or(JsValue::Undefined), realm)?;
        if let Some(JsValue::HostFunction(host_id)) = args.first() {
            if Some(*host_id) == self.function_prototype_host_id && property == "prototype" {
                if has_get {
                    self.function_prototype_prototype_getter =
                        if matches!(desc_get, JsValue::Undefined) {
                            None
                        } else {
                            Some(desc_get)
                        };
                }
                return Ok(JsValue::HostFunction(*host_id));
            }
        }

        enum DefinePropertyTarget {
            Object(ObjectId),
            Function(u64),
            HostFunction(u64),
            NativeFunction(NativeFunction),
        }

        let target = match args.first() {
            Some(JsValue::Object(id)) => DefinePropertyTarget::Object(*id),
            Some(JsValue::Function(closure_id)) => {
                if !self.closures.contains_key(closure_id) {
                    return Err(VmError::UnknownClosure(*closure_id));
                }
                DefinePropertyTarget::Function(*closure_id)
            }
            Some(JsValue::HostFunction(host_id)) => {
                if !self.host_functions.contains_key(host_id) {
                    return Err(VmError::UnknownHostFunction(*host_id));
                }
                DefinePropertyTarget::HostFunction(*host_id)
            }
            Some(JsValue::NativeFunction(native)) => DefinePropertyTarget::NativeFunction(*native),
            _ => {
                return Err(VmError::TypeError(
                    "Object.defineProperty target must be object",
                ));
            }
        };
        if let DefinePropertyTarget::Object(target_id) = &target {
            self.mark_packet_b_prototype_chain_maybe_indexed(*target_id, &property);
        }
        let mut target_object = match target {
            DefinePropertyTarget::Object(target_id) => self
                .objects
                .get(&target_id)
                .cloned()
                .ok_or(VmError::UnknownObject(target_id))?,
            DefinePropertyTarget::Function(closure_id) => self
                .closure_objects
                .get(&closure_id)
                .cloned()
                .unwrap_or_default(),
            DefinePropertyTarget::HostFunction(host_id) => self
                .host_function_objects
                .get(&host_id)
                .cloned()
                .unwrap_or_default(),
            DefinePropertyTarget::NativeFunction(native) => self
                .native_function_objects
                .get(&native)
                .cloned()
                .unwrap_or_default(),
        };
        let target_is_array = match &target {
            DefinePropertyTarget::Object(target_id) => {
                self.is_array_length_tracking_object(*target_id)?
            }
            _ => false,
        };
        let mut pending_array_length_update: Option<(JsValue, Option<bool>)> = None;
        {
            let (
                current_data_value,
                current_get,
                current_set,
                current_attributes,
                mapped_binding_id,
            ) = {
                (
                    target_object.properties.get(&property).cloned(),
                    target_object.getters.get(&property).cloned(),
                    target_object.setters.get(&property).cloned(),
                    target_object.property_attributes.get(&property).copied(),
                    target_object.argument_mappings.get(&property).copied(),
                )
            };

            let current_is_data = current_data_value.is_some();
            let current_is_accessor = current_get.is_some() || current_set.is_some();
            let current_attributes = current_attributes.unwrap_or(if current_is_accessor {
                PropertyAttributes {
                    writable: false,
                    enumerable: true,
                    configurable: true,
                }
            } else {
                PropertyAttributes::default()
            });
            if !target_object.extensible && !current_is_data && !current_is_accessor {
                return Err(VmError::TypeError(
                    "cannot define property on non-extensible object",
                ));
            }
            if target_is_array {
                if let Some(index) = Self::canonical_array_index(&property) {
                    let current_length = target_object
                        .properties
                        .get("length")
                        .map(|value| self.to_number(value))
                        .unwrap_or(0.0)
                        .max(0.0) as usize;
                    if index >= current_length {
                        let length_writable = target_object
                            .property_attributes
                            .get("length")
                            .is_none_or(|attributes| attributes.writable);
                        if !length_writable {
                            return Err(VmError::TypeError(
                                "cannot define array index when length is non-writable",
                            ));
                        }
                    }
                }
            }

            if (current_is_data || current_is_accessor) && !current_attributes.configurable {
                if desc_configurable == Some(true) {
                    return Err(VmError::TypeError(
                        "cannot redefine non-configurable property",
                    ));
                }
                if let Some(enumerable) = desc_enumerable {
                    if enumerable != current_attributes.enumerable {
                        return Err(VmError::TypeError(
                            "cannot redefine non-configurable property",
                        ));
                    }
                }

                if current_is_data {
                    if has_get || has_set {
                        return Err(VmError::TypeError(
                            "cannot redefine non-configurable property",
                        ));
                    }
                    if !current_attributes.writable {
                        if desc_writable == Some(true) {
                            return Err(VmError::TypeError(
                                "cannot redefine non-configurable property",
                            ));
                        }
                        if has_value {
                            if let Some(current_value) = current_data_value.as_ref() {
                                if !self.same_value(current_value, &desc_value) {
                                    return Err(VmError::TypeError(
                                        "cannot redefine non-configurable property",
                                    ));
                                }
                            }
                        }
                    }
                } else {
                    if has_value || desc_writable.is_some() {
                        return Err(VmError::TypeError(
                            "cannot redefine non-configurable property",
                        ));
                    }
                    if has_get {
                        let current_get = current_get.unwrap_or(JsValue::Undefined);
                        if !self.same_value(&current_get, &desc_get) {
                            return Err(VmError::TypeError(
                                "cannot redefine non-configurable property",
                            ));
                        }
                    }
                    if has_set {
                        let current_set = current_set.unwrap_or(JsValue::Undefined);
                        if !self.same_value(&current_set, &desc_set) {
                            return Err(VmError::TypeError(
                                "cannot redefine non-configurable property",
                            ));
                        }
                    }
                }
            }

            let mut remove_mapping = false;
            if has_get || has_set {
                target_object.properties.remove(&property);
                if has_get {
                    target_object
                        .getters
                        .insert(property.clone(), desc_get.clone());
                }
                if has_set {
                    target_object
                        .setters
                        .insert(property.clone(), desc_set.clone());
                }
                let attributes = target_object
                    .property_attributes
                    .entry(property.clone())
                    .or_insert(PropertyAttributes {
                        writable: false,
                        enumerable: false,
                        configurable: false,
                    });
                attributes.writable = false;
                if let Some(enumerable) = desc_enumerable {
                    attributes.enumerable = enumerable;
                } else if !current_is_data && !current_is_accessor {
                    attributes.enumerable = false;
                }
                if let Some(configurable) = desc_configurable {
                    attributes.configurable = configurable;
                } else if !current_is_data && !current_is_accessor {
                    attributes.configurable = false;
                }
                remove_mapping = true;
            } else {
                let defines_data = has_value || desc_writable.is_some();
                if defines_data {
                    target_object.getters.remove(&property);
                    target_object.setters.remove(&property);
                }
                if has_value {
                    if property == "length" && target_is_array {
                        pending_array_length_update = Some((desc_value.clone(), desc_writable));
                    } else {
                        target_object
                            .properties
                            .insert(property.clone(), desc_value.clone());
                    }
                } else if defines_data && current_is_accessor {
                    target_object
                        .properties
                        .insert(property.clone(), JsValue::Undefined);
                } else if !current_is_data && !current_is_accessor {
                    target_object
                        .properties
                        .entry(property.clone())
                        .or_insert(JsValue::Undefined);
                }

                let attributes = target_object
                    .property_attributes
                    .entry(property.clone())
                    .or_insert(PropertyAttributes {
                        writable: false,
                        enumerable: false,
                        configurable: false,
                    });
                if !current_is_data && !current_is_accessor {
                    attributes.writable = desc_writable.unwrap_or(false);
                    attributes.enumerable = desc_enumerable.unwrap_or(false);
                    attributes.configurable = desc_configurable.unwrap_or(false);
                } else {
                    if let Some(writable) = desc_writable {
                        attributes.writable = writable;
                    }
                    if let Some(enumerable) = desc_enumerable {
                        attributes.enumerable = enumerable;
                    }
                    if let Some(configurable) = desc_configurable {
                        attributes.configurable = configurable;
                    }
                }
                if desc_writable == Some(false) {
                    remove_mapping = true;
                }
            }

            if has_value {
                if let Some(binding_id) = mapped_binding_id {
                    if let Some(binding) = self.binding_mut(binding_id) {
                        binding.value = desc_value;
                    }
                }
            }
            if remove_mapping {
                if !has_get && !has_set && !has_value {
                    if let Some(binding_id) = mapped_binding_id {
                        if let Some(binding) = self.binding(binding_id) {
                            target_object
                                .properties
                                .insert(property.clone(), binding.value.clone());
                        }
                    }
                }
                target_object.argument_mappings.remove(&property);
            }
        }

        match target {
            DefinePropertyTarget::Object(target_id) => {
                if target_is_array {
                    if let Some(index) = Self::canonical_array_index(&property) {
                        let current_length = target_object.array_length.unwrap_or_else(|| {
                            target_object
                                .properties
                                .get("length")
                                .map(|value| self.to_number(value))
                                .unwrap_or(0.0)
                                .max(0.0) as usize
                        });
                        if index >= current_length {
                            Self::set_object_array_length(&mut target_object, index + 1);
                        }
                    }
                }
                let object = self
                    .objects
                    .get_mut(&target_id)
                    .ok_or(VmError::UnknownObject(target_id))?;
                *object = target_object;
                if let Some((array_length_value, length_writable)) = pending_array_length_update {
                    let requested_length =
                        self.coerce_valid_array_length_or_throw(array_length_value, realm, false)?;
                    if length_writable == Some(false) {
                        if let Some(object) = self.objects.get_mut(&target_id) {
                            let attributes = object
                                .property_attributes
                                .entry("length".to_string())
                                .or_default();
                            attributes.writable = true;
                        }
                    }
                    let result = self.set_array_length_property(target_id, requested_length, true);
                    if let Some(length_writable) = length_writable {
                        let apply_descriptor_writable =
                            result.is_ok() || matches!(&result, Err(VmError::TypeError(_)));
                        if let Some(object) = self.objects.get_mut(&target_id) {
                            if apply_descriptor_writable {
                                let attributes = object
                                    .property_attributes
                                    .entry("length".to_string())
                                    .or_default();
                                attributes.writable = length_writable;
                            }
                        }
                    }
                    result?;
                }
                Ok(JsValue::Object(target_id))
            }
            DefinePropertyTarget::Function(closure_id) => {
                self.closure_objects.insert(closure_id, target_object);
                Ok(JsValue::Function(closure_id))
            }
            DefinePropertyTarget::HostFunction(host_id) => {
                self.host_function_objects.insert(host_id, target_object);
                Ok(JsValue::HostFunction(host_id))
            }
            DefinePropertyTarget::NativeFunction(native) => {
                self.native_function_objects.insert(native, target_object);
                self.native_function_deleted
                    .remove(&(native, property.clone()));
                Ok(JsValue::NativeFunction(native))
            }
        }
    }

    fn execute_object_keys(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.keys target must be object",
        )?;
        let snapshot = self.collect_own_property_keys(&target, false)?;
        let mut keys = Vec::new();
        for key in snapshot {
            if !self.has_own_property(&target, &key)? {
                continue;
            }
            if !self.own_property_is_enumerable(&target, &key)? {
                continue;
            }
            keys.push(key);
        }
        self.create_array_from_string_keys(keys)
    }

    fn execute_object_entries(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.entries target must be object",
        )?;
        let snapshot = self.collect_own_property_keys(&target, false)?;
        let mut entries = Vec::with_capacity(snapshot.len());
        for key in snapshot {
            if !self.has_own_property(&target, &key)? {
                continue;
            }
            if !self.own_property_is_enumerable(&target, &key)? {
                continue;
            }
            let value = self.get_property_from_receiver(target.clone(), &key, realm)?;
            let entry = self.create_array_from_values(vec![JsValue::String(key), value])?;
            entries.push(entry);
        }
        self.create_array_from_values(entries)
    }

    fn execute_object_values(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.values target must be object",
        )?;
        let snapshot = self.collect_own_property_keys(&target, false)?;
        let mut values = Vec::with_capacity(snapshot.len());
        for key in snapshot {
            if !self.has_own_property(&target, &key)? {
                continue;
            }
            if !self.own_property_is_enumerable(&target, &key)? {
                continue;
            }
            values.push(self.get_property_from_receiver(target.clone(), &key, realm)?);
        }
        self.create_array_from_values(values)
    }

    fn execute_object_get_own_property_names(
        &mut self,
        args: &[JsValue],
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.getOwnPropertyNames target must be object",
        )?;
        let mut keys = self.collect_own_property_keys(&target, false)?;
        keys.retain(|key| key != BOXED_PRIMITIVE_VALUE_KEY);
        self.create_array_from_string_keys(keys)
    }

    fn execute_object_define_properties(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        if !Self::is_object_like_value(&target) {
            return Err(VmError::TypeError(
                "Object.defineProperties target must be object",
            ));
        }
        let descriptors = self.coerce_object_for_object_builtins(
            args.get(1).cloned().unwrap_or(JsValue::Undefined),
            "Object.defineProperties descriptors must be object",
        )?;
        let descriptor_keys = self.collect_own_property_keys(&descriptors, true)?;
        let mut normalized_descriptors = Vec::with_capacity(descriptor_keys.len());
        for property_name in descriptor_keys {
            let descriptor =
                self.get_property_from_receiver(descriptors.clone(), &property_name, realm)?;
            let parsed = self.parse_property_descriptor(descriptor, realm)?;
            let normalized = self.materialize_property_descriptor(&parsed);
            normalized_descriptors.push((property_name, normalized));
        }
        for (property_name, descriptor) in normalized_descriptors {
            let define_args = [target.clone(), JsValue::String(property_name), descriptor];
            let _ = self.execute_object_define_property(&define_args, realm)?;
        }
        Ok(target)
    }

    fn execute_object_for_in_keys(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let keys = match target {
            value if Self::is_object_like_value(&value) => self.collect_for_in_keys(value)?,
            JsValue::Null | JsValue::Undefined => Vec::new(),
            _ => Vec::new(),
        };
        self.create_array_from_string_keys(keys)
    }

    fn execute_object_for_of_values(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let values = self.collect_for_of_values(target, realm)?;
        self.create_array_from_values(values)
    }

    fn execute_object_for_of_iterator(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        match target {
            JsValue::String(value) => {
                self.create_for_of_snapshot_record(self.js_string_iterator_values(&value))
            }
            JsValue::Object(object_id) => {
                self.create_for_of_runtime_iterator_record(JsValue::Object(object_id), realm)
            }
            JsValue::Null | JsValue::Undefined => {
                Err(VmError::TypeError("for-of expects iterable"))
            }
            primitive => {
                let boxed = self.box_primitive_receiver(primitive);
                self.create_for_of_runtime_iterator_record(boxed, realm)
            }
        }
    }

    fn execute_object_for_of_step(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let record = args.first().cloned().unwrap_or(JsValue::Undefined);
        let record_id = match record {
            JsValue::Object(id) => id,
            _ => {
                return Err(VmError::TypeError(
                    "for-of step expects iterator record object",
                ));
            }
        };
        let is_snapshot = self
            .objects
            .get(&record_id)
            .and_then(|object| object.properties.get("__forOfSnapshot"))
            .is_some_and(|value| matches!(value, JsValue::Bool(true)));
        if is_snapshot {
            let (values_id, index) = {
                let object = self
                    .objects
                    .get(&record_id)
                    .ok_or(VmError::UnknownObject(record_id))?;
                let values_id = match object.properties.get("__forOfValues") {
                    Some(JsValue::Object(id)) => *id,
                    _ => return self.create_for_of_step_result(true, JsValue::Undefined),
                };
                let index = object
                    .properties
                    .get("__forOfIndex")
                    .map(|value| self.to_number(value))
                    .unwrap_or(0.0)
                    .max(0.0) as usize;
                (values_id, index)
            };
            let length = self.array_length(values_id)?;
            if index >= length {
                return self.create_for_of_step_result(true, JsValue::Undefined);
            }
            let value = self.get_object_property(values_id, &index.to_string(), realm)?;
            let object = self
                .objects
                .get_mut(&record_id)
                .ok_or(VmError::UnknownObject(record_id))?;
            object.properties.insert(
                "__forOfIndex".to_string(),
                JsValue::Number((index + 1) as f64),
            );
            return self.create_for_of_step_result(false, value);
        }

        let (iterator, next_method) = {
            let object = self
                .objects
                .get(&record_id)
                .ok_or(VmError::UnknownObject(record_id))?;
            let iterator =
                object
                    .properties
                    .get("__forOfIterator")
                    .cloned()
                    .ok_or(VmError::TypeError(
                        "for-of iterator record missing iterator",
                    ))?;
            let next_method = object
                .properties
                .get("__forOfNext")
                .cloned()
                .ok_or(VmError::TypeError("for-of iterator record missing next"))?;
            (iterator, next_method)
        };
        let step_value = self.execute_callable(
            next_method,
            Some(iterator.clone()),
            Vec::new(),
            realm,
            false,
        )?;
        if !Self::is_object_like_value(&step_value) {
            return Err(VmError::TypeError(
                "for-of iterator next must return object",
            ));
        }
        let done = self
            .get_property_from_receiver(step_value.clone(), "done", realm)
            .map(|value| self.is_truthy(&value))?;
        if done {
            return self.create_for_of_step_result(true, JsValue::Undefined);
        }
        let value = self.get_property_from_receiver(step_value, "value", realm)?;
        self.create_for_of_step_result(false, value)
    }

    fn execute_object_for_of_close(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let record = args.first().cloned().unwrap_or(JsValue::Undefined);
        let record_id = match record {
            JsValue::Object(id) => id,
            _ => {
                return Err(VmError::TypeError(
                    "for-of close expects iterator record object",
                ));
            }
        };
        let is_snapshot = self
            .objects
            .get(&record_id)
            .and_then(|object| object.properties.get("__forOfSnapshot"))
            .is_some_and(|value| matches!(value, JsValue::Bool(true)));
        if is_snapshot {
            return Ok(JsValue::Undefined);
        }
        let iterator = self
            .objects
            .get(&record_id)
            .and_then(|object| object.properties.get("__forOfIterator"))
            .cloned()
            .ok_or(VmError::TypeError(
                "for-of iterator record missing iterator",
            ))?;
        let return_method = self.get_property_from_receiver(iterator.clone(), "return", realm)?;
        if matches!(return_method, JsValue::Undefined | JsValue::Null) {
            return Ok(JsValue::Undefined);
        }
        if !Self::is_callable_value(&return_method) {
            return Err(VmError::TypeError(
                "for-of iterator return must be callable",
            ));
        }
        let result =
            self.execute_callable(return_method, Some(iterator), Vec::new(), realm, false)?;
        if !matches!(result, JsValue::Undefined) && !Self::is_object_like_value(&result) {
            return Err(VmError::TypeError(
                "for-of iterator return must return object",
            ));
        }
        Ok(JsValue::Undefined)
    }

    fn create_for_of_runtime_iterator_record(
        &mut self,
        target: JsValue,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let iterator_method =
            self.get_property_from_receiver(target.clone(), "Symbol.iterator", realm)?;
        if matches!(iterator_method, JsValue::Undefined | JsValue::Null) {
            return Err(VmError::TypeError("for-of expects iterable"));
        }
        if !Self::is_callable_value(&iterator_method) {
            return Err(VmError::TypeError("for-of expects iterable"));
        }
        let iterator =
            self.execute_callable(iterator_method, Some(target), Vec::new(), realm, false)?;
        if !Self::is_object_like_value(&iterator) {
            return Err(VmError::TypeError("for-of iterator must return object"));
        }
        let next_method = self.get_property_from_receiver(iterator.clone(), "next", realm)?;
        if !Self::is_callable_value(&next_method) {
            return Err(VmError::TypeError("for-of iterator next must be callable"));
        }
        let record = self.create_object_value();
        let record_id = match record {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let object = self
            .objects
            .get_mut(&record_id)
            .ok_or(VmError::UnknownObject(record_id))?;
        object
            .properties
            .insert("__forOfSnapshot".to_string(), JsValue::Bool(false));
        object
            .properties
            .insert("__forOfIterator".to_string(), iterator);
        object
            .properties
            .insert("__forOfNext".to_string(), next_method);
        Ok(JsValue::Object(record_id))
    }

    fn create_for_of_snapshot_record(&mut self, values: Vec<JsValue>) -> Result<JsValue, VmError> {
        let values_array = self.create_array_from_values(values)?;
        let record = self.create_object_value();
        let record_id = match record {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let object = self
            .objects
            .get_mut(&record_id)
            .ok_or(VmError::UnknownObject(record_id))?;
        object
            .properties
            .insert("__forOfSnapshot".to_string(), JsValue::Bool(true));
        object
            .properties
            .insert("__forOfValues".to_string(), values_array);
        object
            .properties
            .insert("__forOfIndex".to_string(), JsValue::Number(0.0));
        Ok(JsValue::Object(record_id))
    }

    fn create_for_of_step_result(
        &mut self,
        done: bool,
        value: JsValue,
    ) -> Result<JsValue, VmError> {
        let step = self.create_object_value();
        let step_id = match step {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let object = self
            .objects
            .get_mut(&step_id)
            .ok_or(VmError::UnknownObject(step_id))?;
        object
            .properties
            .insert("done".to_string(), JsValue::Bool(done));
        object.properties.insert("value".to_string(), value);
        Ok(JsValue::Object(step_id))
    }

    fn collect_for_in_keys(&mut self, start: JsValue) -> Result<Vec<String>, VmError> {
        let mut keys = Vec::new();
        let mut seen = BTreeSet::new();
        let mut current = start;
        while Self::is_object_like_value(&current) {
            let own_keys = self.collect_own_property_keys(&current, false)?;
            for key in own_keys {
                let enumerable = match &current {
                    JsValue::Object(object_id) => self
                        .objects
                        .get(object_id)
                        .and_then(|object| object.property_attributes.get(&key))
                        .map(|attributes| attributes.enumerable)
                        .unwrap_or(true),
                    JsValue::Function(closure_id) => self
                        .closure_objects
                        .get(closure_id)
                        .and_then(|object| object.property_attributes.get(&key))
                        .map(|attributes| attributes.enumerable)
                        .unwrap_or(true),
                    JsValue::HostFunction(host_id) => self
                        .host_function_objects
                        .get(host_id)
                        .and_then(|object| object.property_attributes.get(&key))
                        .map(|attributes| attributes.enumerable)
                        .unwrap_or(true),
                    JsValue::NativeFunction(_) => false,
                    _ => false,
                };
                let is_new = seen.insert(key.clone());
                if is_new && enumerable {
                    keys.push(key);
                }
            }
            current = self.get_prototype_of_value(&current)?;
        }
        Ok(keys)
    }

    fn collect_for_of_values(
        &mut self,
        target: JsValue,
        realm: &Realm,
    ) -> Result<Vec<JsValue>, VmError> {
        match target {
            JsValue::Object(object_id) => {
                let length = self.array_length(object_id)?;
                let mut values = Vec::with_capacity(length);
                for index in 0..length {
                    let property = index.to_string();
                    values.push(self.get_object_property(object_id, &property, realm)?);
                }
                Ok(values)
            }
            JsValue::String(value) => Ok(value
                .chars()
                .map(|ch| JsValue::String(ch.to_string()))
                .collect()),
            _ => Ok(Vec::new()),
        }
    }

    fn create_array_from_string_keys(&mut self, keys: Vec<String>) -> Result<JsValue, VmError> {
        self.create_array_from_values(keys.into_iter().map(JsValue::String).collect())
    }

    fn create_array_from_values(&mut self, values: Vec<JsValue>) -> Result<JsValue, VmError> {
        let array = self.create_array_value();
        let array_id = match array {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let array_object = self
            .objects
            .get_mut(&array_id)
            .ok_or(VmError::UnknownObject(array_id))?;
        for (index, value) in values.iter().enumerate() {
            let index_key = index.to_string();
            array_object
                .properties
                .insert(index_key.clone(), value.clone());
            array_object
                .property_attributes
                .entry(index_key)
                .or_default();
        }
        Self::set_object_array_length(array_object, values.len());
        array_object.property_attributes.insert(
            "length".to_string(),
            PropertyAttributes {
                writable: true,
                enumerable: false,
                configurable: false,
            },
        );
        Ok(JsValue::Object(array_id))
    }

    fn execute_object_get_own_property_descriptor(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.getOwnPropertyDescriptor target must be object",
        )?;
        let property = self.coerce_to_property_key_runtime(
            args.get(1).cloned().unwrap_or(JsValue::Undefined),
            realm,
            false,
        )?;
        match target {
            JsValue::Object(target_id) => {
                self.execute_object_get_own_property_descriptor_for_object(target_id, &property)
            }
            JsValue::Function(closure_id) => {
                self.execute_object_get_own_property_descriptor_for_function(closure_id, &property)
            }
            JsValue::NativeFunction(native) => {
                self.execute_object_get_own_property_descriptor_for_native(native, &property)
            }
            JsValue::HostFunction(host_id) => {
                self.execute_object_get_own_property_descriptor_for_host(host_id, &property)
            }
            _ => unreachable!(),
        }
    }

    fn execute_object_get_own_property_descriptors(
        &mut self,
        args: &[JsValue],
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.getOwnPropertyDescriptors target must be object",
        )?;
        let mut keys = self.collect_own_property_keys(&target, false)?;
        keys.retain(|key| key != BOXED_PRIMITIVE_VALUE_KEY);
        let mut descriptors = Vec::new();
        for key in keys {
            let descriptor = self.execute_object_get_own_property_descriptor(
                &[target.clone(), JsValue::String(key.clone())],
                realm,
            )?;
            if !matches!(descriptor, JsValue::Undefined) {
                descriptors.push((key, descriptor));
            }
        }

        let result = self.create_object_value();
        let result_id = match result {
            JsValue::Object(object_id) => object_id,
            _ => unreachable!(),
        };
        let object = self
            .objects
            .get_mut(&result_id)
            .ok_or(VmError::UnknownObject(result_id))?;
        for (key, descriptor) in descriptors {
            object.properties.insert(key.clone(), descriptor);
            object.property_attributes.entry(key).or_default();
        }
        Ok(JsValue::Object(result_id))
    }

    fn execute_object_get_own_property_descriptor_for_object(
        &mut self,
        target_id: ObjectId,
        property: &str,
    ) -> Result<JsValue, VmError> {
        let (data_value, getter_value, setter_value, attributes, is_arguments_like) = {
            let object = self
                .objects
                .get(&target_id)
                .ok_or(VmError::UnknownObject(target_id))?;
            (
                object.properties.get(property).cloned(),
                object.getters.get(property).cloned(),
                object.setters.get(property).cloned(),
                object.property_attributes.get(property).copied(),
                object.properties.contains_key("callee")
                    && object.properties.contains_key("length"),
            )
        };

        if let Some(value) = data_value {
            let attributes = attributes.unwrap_or(PropertyAttributes {
                writable: true,
                enumerable: !(is_arguments_like && matches!(property, "length" | "callee")),
                configurable: true,
            });
            return Ok(self.create_descriptor_object(vec![
                ("value", value),
                ("writable", JsValue::Bool(attributes.writable)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }
        if getter_value.is_some() || setter_value.is_some() {
            let attributes = attributes.unwrap_or(PropertyAttributes {
                writable: false,
                enumerable: true,
                configurable: true,
            });
            return Ok(self.create_descriptor_object(vec![
                ("get", getter_value.unwrap_or(JsValue::Undefined)),
                ("set", setter_value.unwrap_or(JsValue::Undefined)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }

        if let Some(JsValue::String(value)) = self.boxed_primitive_value(target_id) {
            if property == "length" {
                return Ok(self.create_descriptor_object(vec![
                    (
                        "value",
                        JsValue::Number(Self::utf16_code_unit_length(&value) as f64),
                    ),
                    ("writable", JsValue::Bool(false)),
                    ("enumerable", JsValue::Bool(false)),
                    ("configurable", JsValue::Bool(false)),
                ]));
            }
            if let Some(index) = Self::canonical_array_index(property) {
                if let Some(ch) = value.chars().nth(index) {
                    return Ok(self.create_descriptor_object(vec![
                        ("value", JsValue::String(ch.to_string())),
                        ("writable", JsValue::Bool(false)),
                        ("enumerable", JsValue::Bool(true)),
                        ("configurable", JsValue::Bool(false)),
                    ]));
                }
            }
        }

        if self.regexp_prototype_id == Some(target_id)
            && matches!(property, "source" | "global" | "ignoreCase" | "multiline")
        {
            let getter = self.create_host_function_value(HostFunction::ObjectValueOf);
            return Ok(self.create_descriptor_object(vec![
                ("get", getter),
                ("set", JsValue::Undefined),
                ("enumerable", JsValue::Bool(false)),
                ("configurable", JsValue::Bool(true)),
            ]));
        }

        let should_synthesize_data_descriptor = self.global_object_id == Some(target_id)
            && matches!(
                property,
                "decodeURI" | "decodeURIComponent" | "encodeURI" | "encodeURIComponent"
            )
            || self.array_prototype_id == Some(target_id)
                && matches!(
                    property,
                    "push"
                        | "pop"
                        | "shift"
                        | "unshift"
                        | "splice"
                        | "copyWithin"
                        | "toLocaleString"
                        | "indexOf"
                        | "lastIndexOf"
                        | "every"
                        | "fill"
                        | "find"
                        | "findIndex"
                        | "some"
                        | "forEach"
                        | "map"
                        | "filter"
                        | "reduceRight"
                        | "slice"
                )
            || self.string_prototype_id == Some(target_id)
                && matches!(
                    property,
                    "concat"
                        | "slice"
                        | "toLocaleLowerCase"
                        | "toLocaleUpperCase"
                        | "localeCompare"
                )
            || self.number_prototype_id == Some(target_id)
                && matches!(property, "toLocaleString" | "toPrecision")
            || self.date_prototype_id == Some(target_id)
                && matches!(
                    property,
                    "getTimezoneOffset"
                        | "toTimeString"
                        | "toDateString"
                        | "toLocaleDateString"
                        | "toLocaleTimeString"
                        | "toISOString"
                        | "toJSON"
                )
            || self.object_prototype_id == Some(target_id)
                && matches!(
                    property,
                    "hasOwnProperty" | "isPrototypeOf" | "propertyIsEnumerable"
                );

        if should_synthesize_data_descriptor {
            let empty_realm = Realm::default();
            let value = self.get_object_property(target_id, property, &empty_realm)?;
            return Ok(self.create_descriptor_object(vec![
                ("value", value),
                ("writable", JsValue::Bool(true)),
                ("enumerable", JsValue::Bool(false)),
                ("configurable", JsValue::Bool(true)),
            ]));
        }
        Ok(JsValue::Undefined)
    }

    fn execute_object_get_own_property_descriptor_for_function(
        &mut self,
        closure_id: u64,
        property: &str,
    ) -> Result<JsValue, VmError> {
        if !self.closures.contains_key(&closure_id) {
            return Err(VmError::UnknownClosure(closure_id));
        }

        let (data_value, getter_value, setter_value, attributes) = self
            .closure_objects
            .get(&closure_id)
            .map(|object| {
                (
                    object.properties.get(property).cloned(),
                    object.getters.get(property).cloned(),
                    object.setters.get(property).cloned(),
                    object.property_attributes.get(property).copied(),
                )
            })
            .unwrap_or((None, None, None, None));

        if let Some(value) = data_value {
            let attributes = attributes.unwrap_or(PropertyAttributes::default());
            return Ok(self.create_descriptor_object(vec![
                ("value", value),
                ("writable", JsValue::Bool(attributes.writable)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }
        if getter_value.is_some() || setter_value.is_some() {
            let attributes = attributes.unwrap_or(PropertyAttributes {
                writable: false,
                enumerable: true,
                configurable: true,
            });
            return Ok(self.create_descriptor_object(vec![
                ("get", getter_value.unwrap_or(JsValue::Undefined)),
                ("set", setter_value.unwrap_or(JsValue::Undefined)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }

        if property == "length" {
            let closure = self
                .closures
                .get(&closure_id)
                .ok_or(VmError::UnknownClosure(closure_id))?;
            let function = closure
                .functions
                .get(closure.function_id)
                .ok_or(VmError::UnknownFunction(closure.function_id))?;
            return Ok(self.create_descriptor_object(vec![
                ("value", JsValue::Number(function.length as f64)),
                ("writable", JsValue::Bool(false)),
                ("enumerable", JsValue::Bool(false)),
                ("configurable", JsValue::Bool(true)),
            ]));
        }

        if property == "prototype"
            && !self.closure_is_arrow(closure_id)?
            && !self.closure_has_no_prototype(closure_id)
        {
            let prototype_value = self.get_or_create_function_prototype_property(closure_id)?;
            return Ok(self.create_descriptor_object(vec![
                ("value", prototype_value),
                ("writable", JsValue::Bool(true)),
                ("enumerable", JsValue::Bool(false)),
                ("configurable", JsValue::Bool(false)),
            ]));
        }

        Ok(JsValue::Undefined)
    }

    fn execute_object_get_own_property_descriptor_for_native(
        &mut self,
        native: NativeFunction,
        property: &str,
    ) -> Result<JsValue, VmError> {
        if let Some(object) = self.native_function_objects.get(&native).cloned() {
            let data_value = object.properties.get(property).cloned();
            let getter_value = object.getters.get(property).cloned();
            let setter_value = object.setters.get(property).cloned();
            let attributes = object.property_attributes.get(property).copied();
            if let Some(value) = data_value {
                let attributes = attributes.unwrap_or(PropertyAttributes::default());
                return Ok(self.create_descriptor_object(vec![
                    ("value", value),
                    ("writable", JsValue::Bool(attributes.writable)),
                    ("enumerable", JsValue::Bool(attributes.enumerable)),
                    ("configurable", JsValue::Bool(attributes.configurable)),
                ]));
            }
            if getter_value.is_some() || setter_value.is_some() {
                let attributes = attributes.unwrap_or(PropertyAttributes {
                    writable: false,
                    enumerable: true,
                    configurable: true,
                });
                return Ok(self.create_descriptor_object(vec![
                    ("get", getter_value.unwrap_or(JsValue::Undefined)),
                    ("set", setter_value.unwrap_or(JsValue::Undefined)),
                    ("enumerable", JsValue::Bool(attributes.enumerable)),
                    ("configurable", JsValue::Bool(attributes.configurable)),
                ]));
            }
        }
        if self
            .native_function_deleted
            .contains(&(native, property.to_string()))
        {
            return Ok(JsValue::Undefined);
        }
        if !self.native_function_has_own_property(native, property) {
            return Ok(JsValue::Undefined);
        }
        let value = self.get_native_function_property(native, property);
        let attributes = self
            .native_function_default_property_attributes(native, property)
            .unwrap_or(PropertyAttributes {
                writable: true,
                enumerable: false,
                configurable: true,
            });
        Ok(self.create_descriptor_object(vec![
            ("value", value),
            ("writable", JsValue::Bool(attributes.writable)),
            ("enumerable", JsValue::Bool(attributes.enumerable)),
            ("configurable", JsValue::Bool(attributes.configurable)),
        ]))
    }

    fn execute_object_get_own_property_descriptor_for_host(
        &mut self,
        host_id: u64,
        property: &str,
    ) -> Result<JsValue, VmError> {
        if !self.host_functions.contains_key(&host_id) {
            return Err(VmError::UnknownHostFunction(host_id));
        }

        let (data_value, getter_value, setter_value, attributes) = self
            .host_function_objects
            .get(&host_id)
            .map(|object| {
                (
                    object.properties.get(property).cloned(),
                    object.getters.get(property).cloned(),
                    object.setters.get(property).cloned(),
                    object.property_attributes.get(property).copied(),
                )
            })
            .unwrap_or((None, None, None, None));

        if let Some(value) = data_value {
            let attributes = attributes.unwrap_or(PropertyAttributes::default());
            return Ok(self.create_descriptor_object(vec![
                ("value", value),
                ("writable", JsValue::Bool(attributes.writable)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }
        if getter_value.is_some() || setter_value.is_some() {
            let attributes = attributes.unwrap_or(PropertyAttributes {
                writable: false,
                enumerable: true,
                configurable: true,
            });
            return Ok(self.create_descriptor_object(vec![
                ("get", getter_value.unwrap_or(JsValue::Undefined)),
                ("set", setter_value.unwrap_or(JsValue::Undefined)),
                ("enumerable", JsValue::Bool(attributes.enumerable)),
                ("configurable", JsValue::Bool(attributes.configurable)),
            ]));
        }

        if self.host_function_objects.contains_key(&host_id)
            && matches!(property, "length" | "name")
        {
            return Ok(JsValue::Undefined);
        }

        if !Self::host_function_has_default_property(property) {
            return Ok(JsValue::Undefined);
        }

        let empty_realm = Realm::default();
        let value = self.get_host_function_property(host_id, property, &empty_realm)?;
        Ok(self.create_descriptor_object(vec![
            ("value", value),
            ("writable", JsValue::Bool(true)),
            ("enumerable", JsValue::Bool(false)),
            ("configurable", JsValue::Bool(true)),
        ]))
    }

    fn execute_object_get_prototype_of(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = self.coerce_object_for_object_builtins(
            args.first().cloned().unwrap_or(JsValue::Undefined),
            "Object.getPrototypeOf target must be object",
        )?;
        self.get_prototype_of_value(&target)
    }

    fn object_proxy_slots(
        &self,
        object_id: ObjectId,
    ) -> Result<Option<(JsValue, JsValue)>, VmError> {
        if !self.has_object_marker(object_id, PROXY_OBJECT_MARKER_KEY)? {
            return Ok(None);
        }
        let object = self
            .objects
            .get(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        if object
            .properties
            .get(PROXY_REVOKED_KEY)
            .is_some_and(|value| matches!(value, JsValue::Bool(true)))
        {
            return Err(VmError::TypeError("Proxy has been revoked"));
        }
        let target = object
            .properties
            .get(PROXY_TARGET_KEY)
            .cloned()
            .unwrap_or(JsValue::Undefined);
        let handler = object
            .properties
            .get(PROXY_HANDLER_KEY)
            .cloned()
            .unwrap_or(JsValue::Undefined);
        Ok(Some((target, handler)))
    }

    fn prevent_extensions_status_on_value(&mut self, target: JsValue) -> Result<bool, VmError> {
        match target {
            JsValue::Object(object_id) => {
                if let Some((proxy_target, proxy_handler)) = self.object_proxy_slots(object_id)? {
                    if matches!(proxy_target, JsValue::Object(id) if id == object_id) {
                        return Ok(false);
                    }
                    let empty_realm = Realm::default();
                    let trap = self.get_property_from_receiver(
                        proxy_handler.clone(),
                        "preventExtensions",
                        &empty_realm,
                    )?;
                    if matches!(trap, JsValue::Undefined) {
                        return self.prevent_extensions_status_on_value(proxy_target);
                    }
                    if !Self::is_callable_value(&trap) {
                        return Err(VmError::TypeError(
                            "Proxy preventExtensions trap must be callable",
                        ));
                    }
                    let trap_result = self.execute_callable(
                        trap,
                        Some(proxy_handler),
                        vec![proxy_target.clone()],
                        &empty_realm,
                        false,
                    )?;
                    if !self.is_truthy(&trap_result) {
                        return Ok(false);
                    }
                    return self.prevent_extensions_status_on_value(proxy_target);
                }
                let object = self
                    .objects
                    .get_mut(&object_id)
                    .ok_or(VmError::UnknownObject(object_id))?;
                object.extensible = false;
                Ok(true)
            }
            JsValue::Function(closure_id) => {
                if !self.closures.contains_key(&closure_id) {
                    return Err(VmError::UnknownClosure(closure_id));
                }
                let object = self.closure_objects.entry(closure_id).or_default();
                object.extensible = false;
                Ok(true)
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(&host_id) {
                    return Err(VmError::UnknownHostFunction(host_id));
                }
                let object = self.host_function_objects.entry(host_id).or_default();
                object.extensible = false;
                Ok(true)
            }
            _ => Ok(true),
        }
    }

    fn execute_object_prevent_extensions(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let status = self.prevent_extensions_status_on_value(target.clone())?;
        if !status {
            return Err(VmError::TypeError(
                "Object.preventExtensions trap returned false",
            ));
        }
        Ok(target)
    }

    fn execute_object_is_extensible(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let extensible = match target {
            JsValue::Object(object_id) => self
                .objects
                .get(&object_id)
                .map(|object| object.extensible)
                .unwrap_or(false),
            JsValue::Function(closure_id) => self
                .closure_objects
                .get(&closure_id)
                .map(|object| object.extensible)
                .unwrap_or(true),
            JsValue::HostFunction(host_id) => self
                .host_function_objects
                .get(&host_id)
                .map(|object| object.extensible)
                .unwrap_or(true),
            JsValue::NativeFunction(_) => true,
            _ => false,
        };
        Ok(JsValue::Bool(extensible))
    }

    fn execute_object_is(&self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let left = args.first().cloned().unwrap_or(JsValue::Undefined);
        let right = args.get(1).cloned().unwrap_or(JsValue::Undefined);
        Ok(JsValue::Bool(self.same_value(&left, &right)))
    }

    fn freeze_object_state(object: &mut JsObject) {
        object.extensible = false;
        let keys = Self::collect_own_property_keys_from_object(object, false);
        for key in keys {
            let is_data = object.properties.contains_key(&key);
            let attributes = object.property_attributes.entry(key).or_default();
            attributes.configurable = false;
            if is_data {
                attributes.writable = false;
            }
        }
    }

    fn execute_object_is_sealed(
        &mut self,
        args: &[JsValue],
        is_frozen: bool,
    ) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        let (object, extensible) = match target {
            JsValue::Object(object_id) => (
                self.objects
                    .get(&object_id)
                    .cloned()
                    .ok_or(VmError::UnknownObject(object_id))?,
                self.objects
                    .get(&object_id)
                    .map(|object| object.extensible)
                    .unwrap_or(true),
            ),
            JsValue::Function(closure_id) => {
                if !self.closures.contains_key(&closure_id) {
                    return Err(VmError::UnknownClosure(closure_id));
                }
                let object = self
                    .closure_objects
                    .get(&closure_id)
                    .cloned()
                    .unwrap_or_default();
                (object.clone(), object.extensible)
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(&host_id) {
                    return Err(VmError::UnknownHostFunction(host_id));
                }
                let object = self
                    .host_function_objects
                    .get(&host_id)
                    .cloned()
                    .unwrap_or_default();
                (object.clone(), object.extensible)
            }
            JsValue::NativeFunction(_) => {
                return Ok(JsValue::Bool(false));
            }
            _ => {
                return Ok(JsValue::Bool(true));
            }
        };
        let keys = Self::collect_own_property_keys_from_object(&object, false);
        for key in keys {
            let attributes = object
                .property_attributes
                .get(&key)
                .copied()
                .unwrap_or_default();
            if attributes.configurable {
                return Ok(JsValue::Bool(false));
            }
            if is_frozen && object.properties.contains_key(&key) && attributes.writable {
                return Ok(JsValue::Bool(false));
            }
        }
        Ok(JsValue::Bool(!extensible))
    }

    fn execute_object_freeze(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        if !self.prevent_extensions_status_on_value(target.clone())? {
            return Err(VmError::TypeError("Object.freeze trap returned false"));
        }
        match target {
            JsValue::Object(object_id) => {
                if self.has_object_marker(object_id, PROXY_OBJECT_MARKER_KEY)? {
                    return Ok(JsValue::Object(object_id));
                }
                let object = self
                    .objects
                    .get_mut(&object_id)
                    .ok_or(VmError::UnknownObject(object_id))?;
                Self::freeze_object_state(object);
                Ok(JsValue::Object(object_id))
            }
            JsValue::Function(closure_id) => {
                if !self.closures.contains_key(&closure_id) {
                    return Err(VmError::UnknownClosure(closure_id));
                }
                let object = self.closure_objects.entry(closure_id).or_default();
                Self::freeze_object_state(object);
                Ok(JsValue::Function(closure_id))
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(&host_id) {
                    return Err(VmError::UnknownHostFunction(host_id));
                }
                let object = self.host_function_objects.entry(host_id).or_default();
                Self::freeze_object_state(object);
                Ok(JsValue::HostFunction(host_id))
            }
            _ => Ok(target),
        }
    }

    fn execute_object_seal(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let target = args.first().cloned().unwrap_or(JsValue::Undefined);
        if !self.prevent_extensions_status_on_value(target.clone())? {
            return Err(VmError::TypeError("Object.seal trap returned false"));
        }
        match target {
            JsValue::Object(object_id) => {
                if self.has_object_marker(object_id, PROXY_OBJECT_MARKER_KEY)? {
                    return Ok(JsValue::Object(object_id));
                }
                let object = self
                    .objects
                    .get_mut(&object_id)
                    .ok_or(VmError::UnknownObject(object_id))?;
                object.extensible = false;
                let keys = Self::collect_own_property_keys_from_object(object, false);
                for key in keys {
                    let attributes = object.property_attributes.entry(key).or_default();
                    attributes.configurable = false;
                }
                Ok(JsValue::Object(object_id))
            }
            JsValue::Function(closure_id) => {
                if !self.closures.contains_key(&closure_id) {
                    return Err(VmError::UnknownClosure(closure_id));
                }
                let object = self.closure_objects.entry(closure_id).or_default();
                object.extensible = false;
                let keys = Self::collect_own_property_keys_from_object(object, false);
                for key in keys {
                    let attributes = object.property_attributes.entry(key).or_default();
                    attributes.configurable = false;
                }
                Ok(JsValue::Function(closure_id))
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(&host_id) {
                    return Err(VmError::UnknownHostFunction(host_id));
                }
                let object = self.host_function_objects.entry(host_id).or_default();
                object.extensible = false;
                let keys = Self::collect_own_property_keys_from_object(object, false);
                for key in keys {
                    let attributes = object.property_attributes.entry(key).or_default();
                    attributes.configurable = false;
                }
                Ok(JsValue::HostFunction(host_id))
            }
            _ => Ok(target),
        }
    }

    fn execute_object_get_template_object(&mut self, args: &[JsValue]) -> Result<JsValue, VmError> {
        let site_id = args
            .first()
            .map(|value| self.to_number(value))
            .filter(|value| value.is_finite() && *value >= 0.0)
            .unwrap_or(0.0) as u64;
        if let Some(cached) = self.template_cache.get(&site_id).cloned() {
            return Ok(cached);
        }

        let cooked = args.get(1).cloned().unwrap_or(JsValue::Undefined);
        let raw = args.get(2).cloned().unwrap_or(JsValue::Undefined);
        let cooked_id = match cooked {
            JsValue::Object(object_id) => object_id,
            _ => return Err(VmError::TypeError("template cooked object must be object")),
        };
        let raw_id = match raw {
            JsValue::Object(object_id) => object_id,
            _ => return Err(VmError::TypeError("template raw object must be object")),
        };
        {
            let cooked_object = self
                .objects
                .get_mut(&cooked_id)
                .ok_or(VmError::UnknownObject(cooked_id))?;
            cooked_object
                .properties
                .insert("raw".to_string(), JsValue::Object(raw_id));
            cooked_object.property_attributes.insert(
                "raw".to_string(),
                PropertyAttributes {
                    writable: false,
                    enumerable: false,
                    configurable: false,
                },
            );
        }
        let _ = self.execute_object_freeze(&[JsValue::Object(raw_id)])?;
        let template_object = self.execute_object_freeze(&[JsValue::Object(cooked_id)])?;
        self.template_cache.insert(site_id, template_object.clone());
        Ok(template_object)
    }

    fn create_descriptor_object(&mut self, entries: Vec<(&str, JsValue)>) -> JsValue {
        let descriptor = self.create_object_value();
        let object_id = match descriptor {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let object = self
            .objects
            .get_mut(&object_id)
            .expect("descriptor object should exist");
        for (key, value) in entries {
            object.properties.insert(key.to_string(), value);
        }
        JsValue::Object(object_id)
    }

    fn create_data_property_or_throw(
        &mut self,
        target: JsValue,
        key: String,
        value: JsValue,
        realm: &Realm,
    ) -> Result<(), VmError> {
        let descriptor = self.create_descriptor_object(vec![
            ("value", value),
            ("writable", JsValue::Bool(true)),
            ("enumerable", JsValue::Bool(true)),
            ("configurable", JsValue::Bool(true)),
        ]);
        let _ = self
            .execute_object_define_property(&[target, JsValue::String(key), descriptor], realm)?;
        Ok(())
    }

    fn execute_inline_chunk(
        &mut self,
        chunk: &Chunk,
        realm: &Realm,
        force_strict: bool,
    ) -> Result<JsValue, VmError> {
        let stack_depth = self.stack.len();
        let saved_handlers = std::mem::take(&mut self.exception_handlers);
        let saved_pending_exception = self.pending_exception.take();
        let saved_identifier_references = std::mem::take(&mut self.identifier_references);
        self.exception_handlers = Vec::new();
        self.pending_exception = None;
        let strict = force_strict || self.code_is_strict(&chunk.code);
        let result =
            match self.execute_code(&chunk.code, &chunk.functions, realm, false, strict, true) {
                Ok(ExecutionSignal::Halt) => Ok(self.stack.pop().unwrap_or(JsValue::Undefined)),
                Ok(ExecutionSignal::Return) => Err(VmError::TopLevelReturn),
                Err(err) => Err(err),
            };
        self.exception_handlers = saved_handlers;
        self.pending_exception = saved_pending_exception;
        self.identifier_references = saved_identifier_references;
        self.stack.truncate(stack_depth);
        result
    }

    fn route_runtime_error_to_handler(
        &mut self,
        err: VmError,
        code_len: usize,
    ) -> Result<usize, VmError> {
        match self.classify_vm_error(err) {
            VmError::UncaughtException(exception) => self.throw_to_handler(exception, code_len),
            other => {
                if self.exception_handlers.is_empty() {
                    return Err(other);
                }
                if let Some(exception) = self.runtime_error_exception_value(&other) {
                    self.throw_to_handler(exception, code_len)
                } else {
                    Err(other)
                }
            }
        }
    }

    fn runtime_error_exception_value(&mut self, err: &VmError) -> Option<JsValue> {
        match self.classify_vm_error(err.clone()) {
            VmError::UnknownIdentifier(name) => Some(self.create_error_exception(
                NativeFunction::ReferenceErrorConstructor,
                "ReferenceError",
                format!("{name} is not defined"),
            )),
            VmError::TypeError(message) => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                (*message).to_string(),
            )),
            VmError::NotCallable => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                "NotCallable".to_string(),
            )),
            VmError::InvalidHandle(_) => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                Self::handle_error_type_message(HandleErrorKind::InvalidHandle).to_string(),
            )),
            VmError::StaleHandle(_) => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                Self::handle_error_type_message(HandleErrorKind::StaleHandle).to_string(),
            )),
            VmError::RuntimeIntegrity(message) => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                message.to_string(),
            )),
            VmError::ImmutableBinding(name) => Some(self.create_error_exception(
                NativeFunction::TypeErrorConstructor,
                "TypeError",
                format!("immutable binding '{name}'"),
            )),
            VmError::VariableAlreadyDefined(name) => Some(self.create_error_exception(
                NativeFunction::SyntaxErrorConstructor,
                "SyntaxError",
                format!("Identifier '{name}' has already been declared"),
            )),
            _ => None,
        }
    }

    fn create_error_exception(
        &mut self,
        constructor: NativeFunction,
        name: &str,
        message: String,
    ) -> JsValue {
        let error = self.create_object_value();
        let JsValue::Object(object_id) = error else {
            unreachable!();
        };
        let prototype = self.error_prototype_for_constructor(constructor);
        if let Some(object) = self.objects.get_mut(&object_id) {
            object.prototype = prototype;
            object.prototype_value = None;
            object.properties.insert(
                "constructor".to_string(),
                JsValue::NativeFunction(constructor),
            );
            object
                .properties
                .insert("name".to_string(), JsValue::String(name.to_string()));
            object
                .properties
                .insert("message".to_string(), JsValue::String(message));
            object.property_attributes.insert(
                "constructor".to_string(),
                PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: true,
                },
            );
            object.property_attributes.insert(
                "name".to_string(),
                PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: true,
                },
            );
            object.property_attributes.insert(
                "message".to_string(),
                PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: true,
                },
            );
        }
        JsValue::Object(object_id)
    }

    fn throw_to_handler(&mut self, exception: JsValue, code_len: usize) -> Result<usize, VmError> {
        while let Some(handler) = self.exception_handlers.pop() {
            self.unwind_to(handler.scope_depth, handler.stack_depth, handler.with_depth)?;

            if let Some(catch_target) = handler.catch_target {
                if catch_target >= code_len {
                    return Err(VmError::InvalidJump(catch_target));
                }
                self.pending_exception = Some(exception);
                return Ok(catch_target);
            }
            if let Some(finally_target) = handler.finally_target {
                if finally_target >= code_len {
                    return Err(VmError::InvalidJump(finally_target));
                }
                self.pending_exception = Some(exception);
                return Ok(finally_target);
            }
        }
        Err(VmError::UncaughtException(exception))
    }

    fn unwind_to(
        &mut self,
        scope_depth: usize,
        stack_depth: usize,
        with_depth: usize,
    ) -> Result<(), VmError> {
        while self.scopes.len() > scope_depth {
            self.scopes.pop();
        }
        if self.scopes.is_empty() {
            return Err(VmError::ScopeUnderflow);
        }
        if self.stack.len() < stack_depth {
            return Err(VmError::StackUnderflow);
        }
        self.stack.truncate(stack_depth);
        while self.with_objects.len() > with_depth {
            self.with_objects.pop();
        }
        Ok(())
    }

    fn create_binding(&mut self, value: JsValue, mutable: bool) -> BindingId {
        self.create_binding_with_flags(value, mutable, false)
    }

    fn create_binding_with_flags(
        &mut self,
        value: JsValue,
        mutable: bool,
        deletable: bool,
    ) -> BindingId {
        self.create_binding_with_behavior(value, mutable, deletable, false)
    }

    fn create_binding_with_behavior(
        &mut self,
        value: JsValue,
        mutable: bool,
        deletable: bool,
        sloppy_readonly_write_ignored: bool,
    ) -> BindingId {
        let id = self.next_binding_id;
        self.next_binding_id += 1;
        self.bindings.push(Some(Binding {
            value,
            mutable,
            deletable,
            sloppy_readonly_write_ignored,
        }));
        self.global_property_sync_bindings.push(false);
        id
    }

    #[inline(always)]
    fn binding(&self, binding_id: BindingId) -> Option<&Binding> {
        self.bindings.get(binding_id)?.as_ref()
    }

    #[inline(always)]
    fn binding_mut(&mut self, binding_id: BindingId) -> Option<&mut Binding> {
        self.bindings.get_mut(binding_id)?.as_mut()
    }

    fn remove_binding_entry(&mut self, binding_id: BindingId) -> Option<Binding> {
        self.bindings.get_mut(binding_id)?.take()
    }

    fn create_object_value(&mut self) -> JsValue {
        let id = self.allocate_object_id();
        self.objects.insert(
            id,
            JsObject {
                prototype: self.object_prototype_id,
                ..JsObject::default()
            },
        );
        self.gc_peak_objects = self.gc_peak_objects.max(self.objects.len());
        JsValue::Object(id)
    }

    fn create_array_value(&mut self) -> JsValue {
        let array = self.create_object_value();
        let JsValue::Object(object_id) = array else {
            unreachable!();
        };
        if self.array_prototype_id.is_none() {
            let _ = self.array_prototype_value();
        }
        if let Some(object) = self.objects.get_mut(&object_id) {
            object.prototype = self.array_prototype_id;
            object.prototype_value = None;
            object.array_length = Some(0);
            object.is_array_object = true;
            object.properties.insert(
                "constructor".to_string(),
                JsValue::NativeFunction(NativeFunction::ArrayConstructor),
            );
            object.property_attributes.insert(
                "constructor".to_string(),
                PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: true,
                },
            );
            Self::set_object_array_length(object, 0);
            object.property_attributes.insert(
                "length".to_string(),
                PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: false,
                },
            );
            object
                .properties
                .insert(ARRAY_OBJECT_MARKER_KEY.to_string(), JsValue::Bool(true));
            object.property_attributes.insert(
                ARRAY_OBJECT_MARKER_KEY.to_string(),
                PropertyAttributes {
                    writable: false,
                    enumerable: false,
                    configurable: false,
                },
            );
        }
        JsValue::Object(object_id)
    }

    fn instantiate_function(
        &mut self,
        function_id: usize,
        functions: &[CompiledFunction],
        enclosing_strict: bool,
    ) -> Result<JsValue, VmError> {
        let function = functions
            .get(function_id)
            .ok_or(VmError::UnknownFunction(function_id))?;
        let strict = enclosing_strict || self.function_is_strict(function);
        let closure_id = self.next_closure_id;
        self.next_closure_id += 1;
        let mut captured_scopes = self.scopes.clone();
        let captured_with_objects = self.with_objects.clone();
        if self.function_is_named_function_expression(function) && function.name != "<anonymous>" {
            let mut name_scope: Scope = HashMap::default();
            let function_name_binding = self.create_binding_with_behavior(
                JsValue::Function(closure_id),
                false,
                false,
                true,
            );
            name_scope.insert(function.name.clone(), function_name_binding);
            captured_scopes.push(Rc::new(RefCell::new(name_scope)));
        }
        self.closures.insert(
            closure_id,
            Closure {
                function_id,
                functions: Rc::new(functions.to_vec()),
                captured_scopes,
                captured_with_objects,
                strict,
            },
        );
        Ok(JsValue::Function(closure_id))
    }

    fn current_scope_ref(&self) -> Result<ScopeRef, VmError> {
        self.scopes.last().cloned().ok_or(VmError::ScopeUnderflow)
    }

    fn current_var_scope_ref(&self) -> Result<ScopeRef, VmError> {
        let Some(scope_index) = self.var_scope_stack.last().copied() else {
            return self.current_scope_ref();
        };
        self.scopes
            .get(scope_index)
            .cloned()
            .ok_or(VmError::ScopeUnderflow)
    }

    fn ensure_annex_b_eval_var_binding(&mut self, name: &str) -> Result<(), VmError> {
        let var_scope = self.current_var_scope_ref()?;
        let existing_binding_id = var_scope.borrow().get(name).copied();
        if existing_binding_id.is_none() {
            let binding_id = self.create_binding_with_flags(
                JsValue::Undefined,
                true,
                self.eval_deletable_binding_depth > 0,
            );
            var_scope.borrow_mut().insert(name.to_string(), binding_id);
        }
        self.define_global_var_property(name)?;
        Ok(())
    }

    fn push_annex_b_var_function_context_for_code(
        &mut self,
        code: &[Opcode],
        strict: bool,
        excluded_names: &[String],
    ) -> Result<bool, VmError> {
        if strict {
            return Ok(false);
        }
        let mut pending_syncs = self.annex_b_sync_counts_for_code(code).as_ref().clone();
        for name in excluded_names {
            pending_syncs.remove(name);
        }
        if pending_syncs.is_empty() {
            return Ok(false);
        }
        for name in pending_syncs.keys() {
            self.ensure_annex_b_eval_var_binding(name)?;
        }
        let var_scope = self.current_var_scope_ref()?;
        self.annex_b_eval_var_function_contexts
            .push(AnnexBEvalVarFunctionContext {
                pending_syncs,
                var_scope,
            });
        Ok(true)
    }

    fn sync_annex_b_eval_var_function_binding(
        &mut self,
        name: &str,
        function_value: JsValue,
    ) -> Result<(), VmError> {
        let current_scope = self.current_scope_ref()?;
        let current_var_scope = self.current_var_scope_ref()?;
        if Rc::ptr_eq(&current_scope, &current_var_scope) {
            return Ok(());
        }
        let Some(var_scope) = self.consume_annex_b_eval_var_sync_slot(name)? else {
            return Ok(());
        };
        self.maybe_set_inferred_function_name(&function_value, name);
        let existing_binding_id = var_scope.borrow().get(name).copied();
        if let Some(binding_id) = existing_binding_id {
            let binding = self
                .binding_mut(binding_id)
                .ok_or(VmError::ScopeUnderflow)?;
            if !binding.mutable {
                return Err(VmError::ImmutableBinding(name.to_string()));
            }
            binding.value = function_value;
            self.sync_global_property_from_binding(name, binding_id)?;
            return Ok(());
        }
        let binding_id = self.create_binding_with_flags(
            function_value,
            true,
            self.eval_deletable_binding_depth > 0,
        );
        var_scope.borrow_mut().insert(name.to_string(), binding_id);
        self.define_global_var_property(name)?;
        Ok(())
    }

    fn consume_annex_b_eval_var_sync_slot(
        &mut self,
        name: &str,
    ) -> Result<Option<ScopeRef>, VmError> {
        let current_var_scope = self.current_var_scope_ref()?;
        for context in self.annex_b_eval_var_function_contexts.iter_mut().rev() {
            if !Rc::ptr_eq(&context.var_scope, &current_var_scope) {
                continue;
            }
            let remove_slot = {
                let Some(remaining) = context.pending_syncs.get_mut(name) else {
                    continue;
                };
                if *remaining == 0 {
                    continue;
                }
                *remaining = remaining.saturating_sub(1);
                *remaining == 0
            };
            if remove_slot {
                context.pending_syncs.remove(name);
            }
            return Ok(Some(context.var_scope.clone()));
        }
        Ok(None)
    }

    fn packet_d_slot_for_opcode(
        metadata: &[Option<IdentifierSlotMetadata>],
        pc: usize,
        family: IdentifierOpcodeFamily,
    ) -> Option<u32> {
        let entry = metadata.get(pc).and_then(|entry| *entry);
        #[cfg(not(debug_assertions))]
        let _ = family;
        #[cfg(debug_assertions)]
        if let Some(entry) = entry {
            debug_assert_eq!(entry.family, family);
        }
        entry.map(|entry| entry.slot)
    }

