    fn boxed_primitive_value(&self, object_id: ObjectId) -> Option<JsValue> {
        self.objects
            .get(&object_id)
            .and_then(|object| object.properties.get(BOXED_PRIMITIVE_VALUE_KEY))
            .cloned()
    }

    fn is_date_object(&self, object_id: ObjectId) -> bool {
        self.objects
            .get(&object_id)
            .and_then(|object| object.properties.get(DATE_OBJECT_MARKER_KEY))
            .is_some_and(|value| matches!(value, JsValue::Bool(true)))
    }

    fn primitive_for_add(
        &mut self,
        value: JsValue,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        match value {
            JsValue::Object(object_id) => {
                if let Some(boxed) = self.boxed_primitive_value(object_id) {
                    return Ok(boxed);
                }
                if self.objects.get(&object_id).is_some_and(|object| {
                    object.properties.contains_key("length")
                        && object.prototype == self.array_prototype_id
                }) {
                    return self.execute_array_join(object_id, ",");
                }
                self.ordinary_to_primitive_for_add(
                    object_id,
                    self.is_date_object(object_id),
                    realm,
                    caller_strict,
                )
            }
            JsValue::Function(closure_id) => {
                self.ordinary_to_primitive_for_function(closure_id, false, realm, caller_strict)
            }
            other => Ok(other),
        }
    }

    fn coerce_to_string_runtime(
        &mut self,
        value: JsValue,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<String, VmError> {
        match value {
            JsValue::Object(object_id) => {
                if let Some(boxed) = self.boxed_primitive_value(object_id) {
                    return Ok(self.coerce_to_string(&boxed));
                }
                if self.objects.get(&object_id).is_some_and(|object| {
                    object.properties.contains_key("length")
                        && object.prototype == self.array_prototype_id
                }) {
                    return match self.execute_array_join(object_id, ",")? {
                        JsValue::String(text) => Ok(text),
                        other => Ok(self.coerce_to_string(&other)),
                    };
                }
                let primitive =
                    self.ordinary_to_primitive_for_add(object_id, true, realm, caller_strict)?;
                Ok(self.coerce_to_string(&primitive))
            }
            JsValue::Function(closure_id) => {
                let primitive = self.ordinary_to_primitive_for_function(
                    closure_id,
                    true,
                    realm,
                    caller_strict,
                )?;
                Ok(self.coerce_to_string(&primitive))
            }
            other => Ok(self.coerce_to_string(&other)),
        }
    }

    fn ordinary_to_primitive_for_add(
        &mut self,
        object_id: ObjectId,
        prefer_string: bool,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let method_names = if prefer_string {
            ["toString", "valueOf"]
        } else {
            ["valueOf", "toString"]
        };
        let mut invoked_callable = false;

        for method_name in method_names {
            let method = self.get_object_property(object_id, method_name, realm)?;
            if !Self::is_callable_value(&method) {
                continue;
            }
            invoked_callable = true;
            let result = self.execute_callable(
                method,
                Some(JsValue::Object(object_id)),
                Vec::new(),
                realm,
                caller_strict,
            )?;
            if !matches!(result, JsValue::Object(_)) {
                return Ok(result);
            }
        }

        if invoked_callable {
            return Err(VmError::TypeError(
                "cannot convert object to primitive value",
            ));
        }

        Ok(JsValue::String("[object Object]".to_string()))
    }

    fn ordinary_to_primitive_for_property_key(
        &mut self,
        object_id: ObjectId,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        for method_name in ["toString", "valueOf"] {
            let method = self.get_object_property(object_id, method_name, realm)?;
            if !Self::is_callable_value(&method) {
                continue;
            }
            let result = self.execute_callable(
                method,
                Some(JsValue::Object(object_id)),
                Vec::new(),
                realm,
                caller_strict,
            )?;
            if !matches!(
                result,
                JsValue::Object(_)
                    | JsValue::Function(_)
                    | JsValue::NativeFunction(_)
                    | JsValue::HostFunction(_)
            ) {
                return Ok(result);
            }
        }
        Err(VmError::TypeError("cannot convert object to property key"))
    }

    fn ordinary_to_primitive_for_function(
        &mut self,
        closure_id: u64,
        prefer_string: bool,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let method_names = if prefer_string {
            ["toString", "valueOf"]
        } else {
            ["valueOf", "toString"]
        };
        let mut invoked_callable = false;

        for method_name in method_names {
            let method = self.get_function_property(closure_id, method_name, realm)?;
            if !Self::is_callable_value(&method) {
                continue;
            }
            invoked_callable = true;
            let result = self.execute_callable(
                method,
                Some(JsValue::Function(closure_id)),
                Vec::new(),
                realm,
                caller_strict,
            )?;
            if !matches!(
                result,
                JsValue::Object(_)
                    | JsValue::Function(_)
                    | JsValue::NativeFunction(_)
                    | JsValue::HostFunction(_)
            ) {
                return Ok(result);
            }
        }

        if invoked_callable {
            return Err(VmError::TypeError(
                "cannot convert object to primitive value",
            ));
        }

        Ok(JsValue::String("[function]".to_string()))
    }

    fn coerce_this_for_sloppy(&mut self, this_arg: Option<JsValue>) -> JsValue {
        match this_arg {
            None | Some(JsValue::Null) | Some(JsValue::Undefined) => self.global_this_value(),
            Some(primitive @ (JsValue::Number(_) | JsValue::Bool(_) | JsValue::String(_))) => {
                self.box_primitive_receiver(primitive)
            }
            Some(value) => value,
        }
    }

    fn object_prototype_this_object(
        &mut self,
        this_arg: Option<JsValue>,
        null_undefined_error: &'static str,
    ) -> Result<JsValue, VmError> {
        let value = this_arg.unwrap_or(JsValue::Undefined);
        self.coerce_object_for_object_builtins(value, null_undefined_error)
    }

    fn object_to_string_tag(
        &mut self,
        this_arg: Option<JsValue>,
        realm: &Realm,
    ) -> Result<String, VmError> {
        let value = this_arg.unwrap_or(JsValue::Undefined);
        match value {
            JsValue::Undefined | JsValue::Uninitialized => return Ok("Undefined".to_string()),
            JsValue::Null => return Ok("Null".to_string()),
            JsValue::Bool(_) => return Ok("Boolean".to_string()),
            JsValue::Number(_) => return Ok("Number".to_string()),
            JsValue::String(_) => return Ok("String".to_string()),
            JsValue::Function(_) | JsValue::NativeFunction(_) | JsValue::HostFunction(_) => {
                return Ok("Function".to_string());
            }
            JsValue::Object(object_id) => {
                if let Some(boxed) = self.boxed_primitive_value(object_id) {
                    return Ok(match boxed {
                        JsValue::Bool(_) => "Boolean",
                        JsValue::Number(_) => "Number",
                        JsValue::String(_) => "String",
                        _ => "Object",
                    }
                    .to_string());
                }
                if self.has_object_marker(object_id, "__uint8ArrayTag")? {
                    return Ok("Uint8Array".to_string());
                }
                if self.has_object_marker(object_id, ARGUMENTS_OBJECT_MARKER_KEY)? {
                    return Ok("Arguments".to_string());
                }
                if self.has_object_marker(object_id, "__regexpTag")? {
                    return Ok("RegExp".to_string());
                }
                if self.has_object_marker(object_id, DATE_OBJECT_MARKER_KEY)? {
                    return Ok("Date".to_string());
                }
                if let Some(array_prototype_id) = self.array_prototype_id {
                    if self.object_inherits_prototype(object_id, array_prototype_id)? {
                        return Ok("Array".to_string());
                    }
                }
                if let Some(error_prototype_id) = self.error_prototype_id {
                    if self.object_inherits_prototype(object_id, error_prototype_id)? {
                        return Ok("Error".to_string());
                    }
                }
                let to_string_tag = self.get_property_from_receiver(
                    JsValue::Object(object_id),
                    "Symbol.toStringTag",
                    realm,
                )?;
                if let JsValue::String(tag) = to_string_tag {
                    if !tag.is_empty() {
                        return Ok(tag);
                    }
                }
            }
        }
        Ok("Object".to_string())
    }

    fn box_primitive_receiver(&mut self, primitive: JsValue) -> JsValue {
        let receiver = self.create_object_value();
        let object_id = match receiver {
            JsValue::Object(id) => id,
            _ => unreachable!(),
        };
        let prototype_id = match primitive {
            JsValue::Number(_) => match self.number_prototype_value() {
                JsValue::Object(id) => Some(id),
                _ => None,
            },
            JsValue::Bool(_) => match self.boolean_prototype_value() {
                JsValue::Object(id) => Some(id),
                _ => None,
            },
            JsValue::String(_) => match self.string_prototype_value() {
                JsValue::Object(id) => Some(id),
                _ => None,
            },
            _ => None,
        };
        if let Some(object) = self.objects.get_mut(&object_id) {
            let primitive_for_properties = primitive.clone();
            object.prototype = prototype_id;
            object.prototype_value = None;
            object.properties.insert(
                BOXED_PRIMITIVE_VALUE_KEY.to_string(),
                primitive_for_properties.clone(),
            );
            object.property_attributes.insert(
                BOXED_PRIMITIVE_VALUE_KEY.to_string(),
                PropertyAttributes {
                    writable: false,
                    enumerable: false,
                    configurable: false,
                },
            );
            if let JsValue::String(value) = primitive_for_properties {
                object.properties.insert(
                    "length".to_string(),
                    JsValue::Number(Self::utf16_code_unit_length(&value) as f64),
                );
                object.property_attributes.insert(
                    "length".to_string(),
                    PropertyAttributes {
                        writable: false,
                        enumerable: false,
                        configurable: false,
                    },
                );
                for (index, ch) in value.chars().enumerate() {
                    let key = index.to_string();
                    object
                        .properties
                        .insert(key.clone(), JsValue::String(ch.to_string()));
                    object.property_attributes.insert(
                        key,
                        PropertyAttributes {
                            writable: false,
                            enumerable: true,
                            configurable: false,
                        },
                    );
                }
            }
        }
        JsValue::Object(object_id)
    }

    fn function_is_strict(&self, function: &CompiledFunction) -> bool {
        self.code_is_strict(&function.code)
    }

    fn function_is_arrow(&self, function: &CompiledFunction) -> bool {
        self.code_has_marker(&function.code, ARROW_FUNCTION_MARKER)
    }

    fn function_is_generator(&self, function: &CompiledFunction) -> bool {
        self.code_has_marker(&function.code, GENERATOR_FUNCTION_MARKER)
    }

    fn function_uses_yield_identifier(&self, function: &CompiledFunction) -> bool {
        function.code.iter().any(|opcode| {
            matches!(
                opcode,
                Opcode::LoadIdentifier(name)
                    | Opcode::ResolveIdentifierReference(name)
                    | Opcode::TypeofIdentifier(name)
                    if name == "yield"
            )
        })
    }

    fn function_is_async(&self, function: &CompiledFunction) -> bool {
        self.code_has_marker(&function.code, ASYNC_FUNCTION_MARKER)
    }

    fn function_is_named_function_expression(&self, function: &CompiledFunction) -> bool {
        self.code_has_marker(&function.code, NAMED_FUNCTION_EXPR_MARKER)
    }

    fn function_has_non_simple_params(&self, function: &CompiledFunction) -> bool {
        self.code_has_marker(&function.code, NON_SIMPLE_PARAMS_MARKER)
    }

    fn function_rest_param_index(&self, function: &CompiledFunction) -> Option<usize> {
        let mut cursor = 0usize;
        while cursor + 1 < function.code.len() {
            match (&function.code[cursor], &function.code[cursor + 1]) {
                (Opcode::LoadString(value), Opcode::Pop) => {
                    if let Some(raw_index) = value.strip_prefix(REST_PARAM_MARKER_PREFIX) {
                        if let Ok(index) = raw_index.parse::<usize>() {
                            return Some(index);
                        }
                    }
                    cursor += 2;
                }
                _ => cursor += 1,
            }
        }
        None
    }

    fn closure_is_arrow(&self, closure_id: u64) -> Result<bool, VmError> {
        let closure = self
            .closures
            .get(&closure_id)
            .ok_or(VmError::UnknownClosure(closure_id))?;
        let function = closure
            .functions
            .get(closure.function_id)
            .ok_or(VmError::UnknownFunction(closure.function_id))?;
        Ok(self.function_is_arrow(function))
    }

    fn closure_is_generator(&self, closure_id: u64) -> Result<bool, VmError> {
        let closure = self
            .closures
            .get(&closure_id)
            .ok_or(VmError::UnknownClosure(closure_id))?;
        let function = closure
            .functions
            .get(closure.function_id)
            .ok_or(VmError::UnknownFunction(closure.function_id))?;
        Ok(self.function_is_generator(function))
    }

    fn closure_uses_yield_identifier(&self, closure_id: u64) -> Result<bool, VmError> {
        let closure = self
            .closures
            .get(&closure_id)
            .ok_or(VmError::UnknownClosure(closure_id))?;
        let function = closure
            .functions
            .get(closure.function_id)
            .ok_or(VmError::UnknownFunction(closure.function_id))?;
        Ok(self.function_uses_yield_identifier(function))
    }

    fn closure_is_class_constructor(&self, closure_id: u64) -> bool {
        self.closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get(CLASS_CONSTRUCTOR_MARKER))
            .is_some_and(|marker| matches!(marker, JsValue::Bool(true)))
    }

    fn closure_is_derived_class_constructor(&self, closure_id: u64) -> bool {
        self.closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get(CLASS_DERIVED_CONSTRUCTOR_MARKER))
            .is_some_and(|marker| matches!(marker, JsValue::Bool(true)))
    }

    fn closure_marks_restricted_caller_arguments(&self, closure_id: u64) -> bool {
        self.closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get(CLASS_HERITAGE_RESTRICTED_MARKER))
            .is_some_and(|marker| matches!(marker, JsValue::Bool(true)))
    }

    fn closure_has_no_prototype(&self, closure_id: u64) -> bool {
        if self
            .closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get(CLASS_METHOD_NO_PROTOTYPE_MARKER))
            .is_some_and(|marker| matches!(marker, JsValue::Bool(true)))
        {
            return true;
        }
        let Some(closure) = self.closures.get(&closure_id) else {
            return false;
        };
        let Some(function) = closure.functions.get(closure.function_id) else {
            return false;
        };
        self.code_has_marker(&function.code, CLASS_METHOD_NO_PROTOTYPE_MARKER)
    }

    fn code_is_strict(&self, code: &[Opcode]) -> bool {
        let cursor = Self::skip_prologue_prefix(code);
        if matches!(code.get(cursor), Some(Opcode::MarkStrict)) {
            return true;
        }
        if cursor != 0 && matches!(code.first(), Some(Opcode::MarkStrict)) {
            return true;
        }
        false
    }

    fn code_has_marker(&self, code: &[Opcode], marker: &str) -> bool {
        let mut cursor = 0usize;
        while cursor + 1 < code.len() {
            match (&code[cursor], &code[cursor + 1]) {
                (Opcode::LoadString(value), Opcode::Pop) => {
                    if value == marker {
                        return true;
                    }
                    cursor += 2;
                }
                _ => cursor += 1,
            }
        }
        false
    }

    fn skip_prologue_prefix(code: &[Opcode]) -> usize {
        let mut cursor = 0usize;
        if matches!(code.get(cursor), Some(Opcode::MarkStrict)) {
            cursor += 1;
        }
        while cursor < code.len() {
            match &code[cursor] {
                Opcode::DefineFunction { .. } | Opcode::DefineVar(_) => cursor += 1,
                _ => break,
            }
        }
        while cursor + 1 < code.len() {
            match (&code[cursor], &code[cursor + 1]) {
                (Opcode::LoadUndefined, Opcode::DefineVariable { .. })
                | (Opcode::LoadUninitialized, Opcode::DefineVariable { .. }) => cursor += 2,
                _ => break,
            }
        }
        cursor
    }

    fn annex_b_var_function_sync_counts_from_code(code: &[Opcode]) -> BTreeMap<String, usize> {
        let mut candidate_sync_counts = BTreeMap::new();
        let mut lexical_scopes: Vec<BTreeSet<String>> = vec![BTreeSet::new()];
        let mut scope_depth = 0usize;
        for (index, opcode) in code.iter().enumerate() {
            match opcode {
                Opcode::EnterScope => {
                    scope_depth = scope_depth.saturating_add(1);
                    lexical_scopes.push(BTreeSet::new());
                }
                Opcode::ExitScope => {
                    scope_depth = scope_depth.saturating_sub(1);
                    if lexical_scopes.len() > 1 {
                        lexical_scopes.pop();
                    }
                }
                Opcode::EnterParamInitScope => {
                    scope_depth = scope_depth.saturating_sub(1);
                    if lexical_scopes.len() > 1 {
                        lexical_scopes.pop();
                    }
                }
                Opcode::ExitParamInitScope => {
                    scope_depth = scope_depth.saturating_add(1);
                    lexical_scopes.push(BTreeSet::new());
                }
                Opcode::DefineVariable { name, .. } => {
                    let is_catch_binding_identifier =
                        index > 0 && matches!(code.get(index - 1), Some(Opcode::LoadException));
                    if !is_catch_binding_identifier {
                        if let Some(current_scope) = lexical_scopes.last_mut() {
                            current_scope.insert(name.clone());
                        }
                    }
                }
                Opcode::DefineFunction { name, .. } => {
                    if scope_depth > 0 {
                        let has_conflict = lexical_scopes
                            .iter()
                            .any(|lexical_names| lexical_names.contains(name));
                        if !has_conflict {
                            *candidate_sync_counts.entry(name.clone()).or_insert(0) += 1;
                        }
                        if let Some(current_scope) = lexical_scopes.last_mut() {
                            current_scope.insert(name.clone());
                        }
                    }
                }
                _ => {}
            }
        }
        candidate_sync_counts
    }

    fn current_eval_context_rejects_arguments_declaration(&self) -> bool {
        let Some(context) = self.eval_contexts.last() else {
            return false;
        };
        (context.non_simple_params && !context.is_arrow_function) || context.has_arguments_param
    }

    fn script_declares_arguments_binding(script: &Script) -> bool {
        script
            .statements
            .iter()
            .any(Self::statement_declares_arguments_binding)
    }

    fn script_annex_b_eval_var_function_names(script: &Script) -> BTreeSet<String> {
        let lexical_names = Self::script_lexical_declaration_names(script);
        let mut candidate_names = BTreeSet::new();
        for statement in &script.statements {
            Self::collect_annex_b_eval_var_function_names_from_statement(
                statement,
                true,
                &mut candidate_names,
            );
        }
        candidate_names.retain(|name| !lexical_names.contains(name));
        candidate_names
    }

    fn collect_annex_b_eval_var_function_names_from_statement(
        statement: &Stmt,
        in_script_or_function_statement_list: bool,
        names: &mut BTreeSet<String>,
    ) {
        match statement {
            Stmt::FunctionDeclaration(declaration) => {
                if !in_script_or_function_statement_list {
                    names.insert(declaration.name.0.clone());
                }
            }
            Stmt::Block(statements) => {
                for statement in statements {
                    Self::collect_annex_b_eval_var_function_names_from_statement(
                        statement, false, names,
                    );
                }
            }
            Stmt::If {
                consequent,
                alternate,
                ..
            } => {
                Self::collect_annex_b_eval_var_function_names_from_statement(
                    consequent, false, names,
                );
                if let Some(alternate) = alternate {
                    Self::collect_annex_b_eval_var_function_names_from_statement(
                        alternate, false, names,
                    );
                }
            }
            Stmt::While { body, .. }
            | Stmt::With { body, .. }
            | Stmt::DoWhile { body, .. }
            | Stmt::Labeled { body, .. } => {
                Self::collect_annex_b_eval_var_function_names_from_statement(body, false, names)
            }
            Stmt::For { body, .. } => {
                Self::collect_annex_b_eval_var_function_names_from_statement(body, false, names);
            }
            Stmt::Switch { cases, .. } => {
                for case in cases {
                    for statement in &case.consequent {
                        Self::collect_annex_b_eval_var_function_names_from_statement(
                            statement, false, names,
                        );
                    }
                }
            }
            Stmt::Try {
                try_block,
                catch_block,
                finally_block,
                ..
            } => {
                for statement in try_block {
                    Self::collect_annex_b_eval_var_function_names_from_statement(
                        statement, false, names,
                    );
                }
                if let Some(catch_block) = catch_block {
                    for statement in catch_block {
                        Self::collect_annex_b_eval_var_function_names_from_statement(
                            statement, false, names,
                        );
                    }
                }
                if let Some(finally_block) = finally_block {
                    for statement in finally_block {
                        Self::collect_annex_b_eval_var_function_names_from_statement(
                            statement, false, names,
                        );
                    }
                }
            }
            Stmt::VariableDeclaration(_)
            | Stmt::VariableDeclarations(_)
            | Stmt::Empty
            | Stmt::Return(_)
            | Stmt::Expression(_)
            | Stmt::Throw(_)
            | Stmt::Break
            | Stmt::BreakLabel(_)
            | Stmt::Continue
            | Stmt::ContinueLabel(_) => {}
        }
    }

    fn script_lexical_declaration_names(script: &Script) -> BTreeSet<String> {
        let mut names = BTreeSet::new();
        for statement in &script.statements {
            Self::collect_lexical_declaration_names_from_statement(statement, &mut names);
        }
        names
    }

    fn collect_lexical_declaration_names_from_statement(
        statement: &Stmt,
        names: &mut BTreeSet<String>,
    ) {
        match statement {
            Stmt::VariableDeclaration(VariableDeclaration {
                kind: BindingKind::Let | BindingKind::Const,
                name: Identifier(name),
                ..
            }) => {
                names.insert(name.clone());
            }
            Stmt::VariableDeclaration(VariableDeclaration {
                kind: BindingKind::Var,
                ..
            }) => {}
            Stmt::VariableDeclarations(declarations) => {
                for declaration in declarations {
                    if matches!(declaration.kind, BindingKind::Let | BindingKind::Const) {
                        names.insert(declaration.name.0.clone());
                    }
                }
            }
            Stmt::FunctionDeclaration(_) => {}
            Stmt::Block(statements) => {
                for statement in statements {
                    Self::collect_lexical_declaration_names_from_statement(statement, names);
                }
            }
            Stmt::If {
                consequent,
                alternate,
                ..
            } => {
                Self::collect_lexical_declaration_names_from_statement(consequent, names);
                if let Some(alternate) = alternate {
                    Self::collect_lexical_declaration_names_from_statement(alternate, names);
                }
            }
            Stmt::While { body, .. }
            | Stmt::With { body, .. }
            | Stmt::DoWhile { body, .. }
            | Stmt::Labeled { body, .. } => {
                Self::collect_lexical_declaration_names_from_statement(body, names);
            }
            Stmt::For {
                initializer, body, ..
            } => {
                if let Some(initializer) = initializer {
                    match initializer {
                        ForInitializer::VariableDeclaration(declaration) => {
                            if matches!(declaration.kind, BindingKind::Let | BindingKind::Const) {
                                names.insert(declaration.name.0.clone());
                            }
                        }
                        ForInitializer::VariableDeclarations(declarations) => {
                            for declaration in declarations {
                                if matches!(declaration.kind, BindingKind::Let | BindingKind::Const)
                                {
                                    names.insert(declaration.name.0.clone());
                                }
                            }
                        }
                        ForInitializer::Expression(_) => {}
                    }
                }
                Self::collect_lexical_declaration_names_from_statement(body, names);
            }
            Stmt::Switch { cases, .. } => {
                for case in cases {
                    for statement in &case.consequent {
                        Self::collect_lexical_declaration_names_from_statement(statement, names);
                    }
                }
            }
            Stmt::Try {
                try_block,
                catch_block,
                finally_block,
                ..
            } => {
                for statement in try_block {
                    Self::collect_lexical_declaration_names_from_statement(statement, names);
                }
                if let Some(catch_block) = catch_block {
                    for statement in catch_block {
                        Self::collect_lexical_declaration_names_from_statement(statement, names);
                    }
                }
                if let Some(finally_block) = finally_block {
                    for statement in finally_block {
                        Self::collect_lexical_declaration_names_from_statement(statement, names);
                    }
                }
            }
            Stmt::Empty
            | Stmt::Return(_)
            | Stmt::Expression(_)
            | Stmt::Throw(_)
            | Stmt::Break
            | Stmt::BreakLabel(_)
            | Stmt::Continue
            | Stmt::ContinueLabel(_) => {}
        }
    }

    fn statement_declares_arguments_binding(statement: &Stmt) -> bool {
        match statement {
            Stmt::VariableDeclaration(VariableDeclaration {
                kind: BindingKind::Var,
                name: Identifier(name),
                ..
            }) => name == "arguments",
            Stmt::VariableDeclaration(VariableDeclaration {
                kind: BindingKind::Let | BindingKind::Const,
                ..
            }) => false,
            Stmt::VariableDeclarations(declarations) => declarations.iter().any(|declaration| {
                declaration.kind == BindingKind::Var && declaration.name.0 == "arguments"
            }),
            Stmt::FunctionDeclaration(declaration) => declaration.name.0 == "arguments",
            Stmt::Block(statements) => statements
                .iter()
                .any(Self::statement_declares_arguments_binding),
            Stmt::If {
                consequent,
                alternate,
                ..
            } => {
                if Self::statement_declares_arguments_binding(consequent) {
                    return true;
                }
                alternate
                    .as_ref()
                    .is_some_and(|alternate| Self::statement_declares_arguments_binding(alternate))
            }
            Stmt::While { body, .. }
            | Stmt::With { body, .. }
            | Stmt::DoWhile { body, .. }
            | Stmt::Labeled { body, .. } => Self::statement_declares_arguments_binding(body),
            Stmt::For {
                initializer, body, ..
            } => {
                let initializer_declares_arguments =
                    initializer
                        .as_ref()
                        .is_some_and(|initializer| match initializer {
                            ForInitializer::VariableDeclaration(declaration) => {
                                declaration.kind == BindingKind::Var
                                    && declaration.name.0 == "arguments"
                            }
                            ForInitializer::VariableDeclarations(declarations) => {
                                declarations.iter().any(|declaration| {
                                    declaration.kind == BindingKind::Var
                                        && declaration.name.0 == "arguments"
                                })
                            }
                            ForInitializer::Expression(_) => false,
                        });
                initializer_declares_arguments || Self::statement_declares_arguments_binding(body)
            }
            Stmt::Switch { cases, .. } => cases.iter().any(|case| {
                case.consequent
                    .iter()
                    .any(Self::statement_declares_arguments_binding)
            }),
            Stmt::Try {
                try_block,
                catch_block,
                finally_block,
                ..
            } => {
                if try_block
                    .iter()
                    .any(Self::statement_declares_arguments_binding)
                {
                    return true;
                }
                if catch_block.as_ref().is_some_and(|catch_block| {
                    catch_block
                        .iter()
                        .any(Self::statement_declares_arguments_binding)
                }) {
                    return true;
                }
                finally_block.as_ref().is_some_and(|finally_block| {
                    finally_block
                        .iter()
                        .any(Self::statement_declares_arguments_binding)
                })
            }
            Stmt::Empty
            | Stmt::Return(_)
            | Stmt::Expression(_)
            | Stmt::Throw(_)
            | Stmt::Break
            | Stmt::BreakLabel(_)
            | Stmt::Continue
            | Stmt::ContinueLabel(_) => false,
        }
    }

    fn script_declares_restricted_global_function(script: &Script) -> bool {
        script.statements.iter().any(|statement| {
            let Stmt::FunctionDeclaration(declaration) = statement else {
                return false;
            };
            matches!(
                declaration.name.0.as_str(),
                "NaN" | "Infinity" | "undefined"
            )
        })
    }

    fn create_host_function_value(&mut self, host: HostFunction) -> JsValue {
        let id = self.next_host_function_id;
        self.next_host_function_id += 1;
        self.host_functions.insert(id, host);
        JsValue::HostFunction(id)
    }

    fn set_builtin_function_length(&mut self, function: &JsValue, length: f64) {
        let JsValue::HostFunction(host_id) = function else {
            return;
        };
        let object = self.host_function_objects.entry(*host_id).or_default();
        object
            .properties
            .insert("length".to_string(), JsValue::Number(length));
        object.property_attributes.insert(
            "length".to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: true,
            },
        );
    }

    fn set_builtin_function_name(&mut self, function: &JsValue, name: &str) {
        let JsValue::HostFunction(host_id) = function else {
            return;
        };
        let object = self.host_function_objects.entry(*host_id).or_default();
        object
            .properties
            .insert("name".to_string(), JsValue::String(name.to_string()));
        object.property_attributes.insert(
            "name".to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: true,
            },
        );
    }

    fn shared_object_to_string_function(&mut self) -> JsValue {
        if let Some(host_id) = self.object_to_string_host_id {
            return JsValue::HostFunction(host_id);
        }
        let id = self.next_host_function_id;
        self.next_host_function_id += 1;
        self.host_functions.insert(id, HostFunction::ObjectToString);
        self.object_to_string_host_id = Some(id);
        JsValue::HostFunction(id)
    }

    fn get_object_property(
        &mut self,
        object_id: ObjectId,
        property: &str,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        if property == "hasOwnProperty" {
            if self.object_prototype_id == Some(object_id) {
                if let Some(value) = self
                    .objects
                    .get(&object_id)
                    .and_then(|object| object.properties.get(property))
                    .cloned()
                {
                    return Ok(value);
                }
            }
            return Ok(
                self.create_host_function_value(HostFunction::HasOwnProperty {
                    target: JsValue::Object(object_id),
                }),
            );
        }
        if property == "isPrototypeOf" {
            if self.object_prototype_id == Some(object_id) {
                if let Some(value) = self
                    .objects
                    .get(&object_id)
                    .and_then(|object| object.properties.get(property))
                    .cloned()
                {
                    return Ok(value);
                }
            }
            return Ok(
                self.create_host_function_value(HostFunction::IsPrototypeOf {
                    target: JsValue::Object(object_id),
                }),
            );
        }
        if let Some(value) = self.get_object_own_property_with_receiver(
            object_id,
            property,
            JsValue::Object(object_id),
            realm,
        )? {
            return Ok(value);
        }
        let is_array_prototype = self.array_prototype_id == Some(object_id);
        let is_array_like = self
            .is_array_length_tracking_object(object_id)
            .unwrap_or(false);
        if let Some(JsValue::String(value)) = self.boxed_primitive_value(object_id) {
            if property == "length" {
                return Ok(JsValue::Number(Self::utf16_code_unit_length(&value) as f64));
            }
            if let Ok(index) = property.parse::<usize>() {
                return Ok(value
                    .chars()
                    .nth(index)
                    .map(|ch| JsValue::String(ch.to_string()))
                    .unwrap_or(JsValue::Undefined));
            }
        }
        if property == "push" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayPushThis));
        }
        if property == "pop" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayPopThis));
        }
        if property == "shift" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayShiftThis));
        }
        if property == "unshift" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayUnshiftThis));
        }
        if property == "concat" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayConcatThis));
        }
        if property == "every" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayEveryThis));
        }
        if property == "some" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArraySomeThis));
        }
        if property == "filter" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayFilterThis));
        }
        if property == "map" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayMapThis));
        }
        if property == "fill" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayFillThis));
        }
        if property == "find" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayFindThis));
        }
        if property == "findIndex" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayFindIndexThis));
        }
        if property == "copyWithin" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayCopyWithinThis));
        }
        if property == "forEach" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayForEachThis));
        }
        if property == "reduce" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayReduceThis));
        }
        if property == "reduceRight" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayReduceRightThis));
        }
        if property == "join" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayJoinThis));
        }
        if property == "splice" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArraySpliceThis));
        }
        if property == "slice" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArraySliceThis));
        }
        if property == "reverse" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayReverseThis));
        }
        if property == "sort" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArraySortThis));
        }
        if property == "keys" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayKeysThis));
        }
        if property == "entries" && is_array_like && !is_array_prototype {
            return Ok(self.create_host_function_value(HostFunction::ArrayEntriesThis));
        }
        if (property == "values" || property == "Symbol.iterator")
            && is_array_like
            && !is_array_prototype
        {
            return Ok(self.create_host_function_value(HostFunction::ArrayValuesThis));
        }
        let receiver = JsValue::Object(object_id);
        let mut current_id = Some(object_id);
        while let Some(id) = current_id {
            let (getter, setter_exists, value, next, prototype_value) = {
                let object = self
                    .objects
                    .get(&id)
                    .ok_or_else(|| self.classify_unknown_object_error(id))?;
                (
                    object.getters.get(property).cloned(),
                    object.setters.contains_key(property),
                    object.properties.get(property).cloned(),
                    object.prototype,
                    object.prototype_value.clone(),
                )
            };
            if let Some(getter) = getter {
                if matches!(getter, JsValue::Undefined) {
                    return Ok(JsValue::Undefined);
                }
                return self.execute_callable(
                    getter,
                    Some(receiver.clone()),
                    Vec::new(),
                    realm,
                    false,
                );
            }
            if setter_exists {
                return Ok(JsValue::Undefined);
            }
            if let Some(value) = value {
                return Ok(value);
            }
            if let Some(next) = next {
                current_id = Some(next);
                continue;
            }
            if let Some(prototype_value) = prototype_value {
                return self.get_property_from_base_with_receiver(
                    prototype_value,
                    property,
                    receiver.clone(),
                    realm,
                );
            }
            current_id = None;
        }
        Ok(JsValue::Undefined)
    }

    fn get_object_own_property_with_receiver(
        &mut self,
        object_id: ObjectId,
        property: &str,
        receiver: JsValue,
        realm: &Realm,
    ) -> Result<Option<JsValue>, VmError> {
        let (mapped_binding, getter, setter_exists, value) = {
            let object = self
                .objects
                .get(&object_id)
                .ok_or_else(|| self.classify_unknown_object_error(object_id))?;
            (
                object.argument_mappings.get(property).copied(),
                object.getters.get(property).cloned(),
                object.setters.contains_key(property),
                object.properties.get(property).cloned(),
            )
        };
        if let Some(binding_id) = mapped_binding
            && let Some(binding) = self.binding(binding_id)
        {
            return Ok(Some(binding.value.clone()));
        }
        if let Some(getter) = getter {
            if matches!(getter, JsValue::Undefined) {
                return Ok(Some(JsValue::Undefined));
            }
            let value = self.execute_callable(getter, Some(receiver), Vec::new(), realm, false)?;
            return Ok(Some(value));
        }
        if setter_exists {
            return Ok(Some(JsValue::Undefined));
        }
        Ok(value)
    }

    fn set_object_property(
        &mut self,
        object_id: ObjectId,
        property: String,
        value: JsValue,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        self.mark_packet_b_prototype_chain_maybe_indexed(object_id, &property);
        let (mapped_binding_id, own_setter, own_getter_exists, own_data_writable, own_prototype) = {
            let object = self
                .objects
                .get(&object_id)
                .ok_or_else(|| self.classify_unknown_object_error(object_id))?;
            (
                object.argument_mappings.get(&property).copied(),
                object.setters.get(&property).cloned(),
                object.getters.contains_key(&property),
                object.properties.get(&property).map(|_| {
                    object
                        .property_attributes
                        .get(&property)
                        .is_none_or(|attributes| attributes.writable)
                }),
                object.prototype,
            )
        };

        if let Some(setter) = own_setter {
            if matches!(setter, JsValue::Undefined) {
                return Ok(value);
            }
            let _ = self.execute_callable(
                setter,
                Some(JsValue::Object(object_id)),
                vec![value.clone()],
                realm,
                false,
            )?;
            return Ok(value);
        }
        if own_getter_exists {
            return Ok(value);
        }
        if own_data_writable == Some(false) {
            return Ok(value);
        }

        if own_data_writable.is_none() {
            let mut current = own_prototype;
            while let Some(proto_id) = current {
                let (setter, getter_exists, data_writable, next) = {
                    let object = self
                        .objects
                        .get(&proto_id)
                        .ok_or_else(|| self.classify_unknown_object_error(proto_id))?;
                    (
                        object.setters.get(&property).cloned(),
                        object.getters.contains_key(&property),
                        object.properties.get(&property).map(|_| {
                            object
                                .property_attributes
                                .get(&property)
                                .is_none_or(|attributes| attributes.writable)
                        }),
                        object.prototype,
                    )
                };

                if let Some(setter) = setter {
                    if matches!(setter, JsValue::Undefined) {
                        return Ok(value);
                    }
                    let _ = self.execute_callable(
                        setter,
                        Some(JsValue::Object(object_id)),
                        vec![value.clone()],
                        realm,
                        false,
                    )?;
                    return Ok(value);
                }
                if getter_exists {
                    return Ok(value);
                }
                if data_writable == Some(false) {
                    return Ok(value);
                }
                if data_writable == Some(true) {
                    break;
                }
                current = next;
            }
        }

        if let Some(binding_id) = mapped_binding_id {
            if let Some(binding) = self.binding_mut(binding_id) {
                binding.value = value.clone();
            }
        }
        let can_write_property = {
            let object = self
                .objects
                .get(&object_id)
                .ok_or_else(|| self.classify_unknown_object_error(object_id))?;
            object.extensible
                || object.properties.contains_key(&property)
                || object.getters.contains_key(&property)
                || object.setters.contains_key(&property)
        };
        if !can_write_property {
            return Ok(value);
        }
        if self.has_object_marker(object_id, "__uint8ArrayTag")? {
            if let Some(index) = Self::canonical_array_index(&property) {
                self.set_uint8_array_index_property(object_id, index, &value)?;
                return Ok(value);
            }
            if matches!(property.as_str(), "length" | "byteLength") {
                return Ok(value);
            }
        }
        if self.is_array_length_tracking_object(object_id)? {
            if property == "length" {
                let requested_length =
                    self.coerce_valid_array_length_or_throw(value.clone(), realm, false)?;
                self.set_array_length_property(object_id, requested_length, false)?;
                return Ok(value);
            }
            if let Some(index) = Self::canonical_array_index(&property) {
                self.set_array_index_property(object_id, index, property, value.clone())?;
                return Ok(value);
            }
        }
        let object = match self.objects.get_mut(&object_id) {
            Some(object) => object,
            None => return Err(self.classify_unknown_object_error(object_id)),
        };
        object.properties.insert(property.clone(), value.clone());
        self.sync_global_binding_from_property_write(object_id, &property, &value)?;
        Ok(value)
    }

    fn set_closure_property(
        &mut self,
        closure_id: u64,
        property: String,
        value: JsValue,
    ) -> JsValue {
        let object = self.closure_objects.entry(closure_id).or_default();
        object.properties.insert(property.clone(), value.clone());
        value
    }

    fn maybe_set_inferred_function_name(&mut self, value: &JsValue, binding_name: &str) {
        let JsValue::Function(closure_id) = value else {
            return;
        };
        if binding_name.starts_with("$__class_ctor_") {
            return;
        }
        let existing_name = self
            .closure_objects
            .get(closure_id)
            .and_then(|object| object.properties.get("name"));
        let should_keep_existing_name = match existing_name {
            Some(JsValue::String(name)) => {
                !name.is_empty() && name != "<anonymous>" && !name.starts_with("$__class_ctor_")
            }
            Some(_) => true,
            None => false,
        };
        if should_keep_existing_name {
            return;
        }
        let inferred = self
            .closures
            .get(closure_id)
            .and_then(|closure| closure.functions.get(closure.function_id))
            .map(|function| function.name.as_str())
            .filter(|name| !name.is_empty() && *name != "<anonymous>")
            .map(ToOwned::to_owned)
            .unwrap_or_else(|| binding_name.to_string());
        let object = self.closure_objects.entry(*closure_id).or_default();
        object
            .properties
            .insert("name".to_string(), JsValue::String(inferred));
        object.property_attributes.insert(
            "name".to_string(),
            PropertyAttributes {
                writable: false,
                enumerable: false,
                configurable: true,
            },
        );
    }

    fn set_function_property(
        &mut self,
        closure_id: u64,
        property: String,
        value: JsValue,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        let (setter, getter_exists, data_writable) = self
            .closure_objects
            .get(&closure_id)
            .map(|object| {
                (
                    object.setters.get(&property).cloned(),
                    object.getters.contains_key(&property),
                    object.properties.get(&property).map(|_| {
                        object
                            .property_attributes
                            .get(&property)
                            .is_none_or(|attributes| attributes.writable)
                    }),
                )
            })
            .unwrap_or((None, false, None));

        if let Some(setter) = setter {
            let _ = self.execute_callable(
                setter,
                Some(JsValue::Function(closure_id)),
                vec![value.clone()],
                realm,
                false,
            )?;
            return Ok(value);
        }
        if getter_exists {
            return Ok(value);
        }
        if data_writable == Some(false) {
            return Ok(value);
        }
        if data_writable.is_none() {
            let mut current = self.get_prototype_of_value(&JsValue::Function(closure_id))?;
            while Self::is_object_like_value(&current) {
                let (setter, inherited_getter_exists, inherited_data_writable) = match &current {
                    JsValue::Object(object_id) => {
                        let object = self
                            .objects
                            .get(object_id)
                            .ok_or(VmError::UnknownObject(*object_id))?;
                        (
                            object.setters.get(&property).cloned(),
                            object.getters.contains_key(&property),
                            object.properties.get(&property).map(|_| {
                                object
                                    .property_attributes
                                    .get(&property)
                                    .is_none_or(|attributes| attributes.writable)
                            }),
                        )
                    }
                    JsValue::Function(proto_closure_id) => {
                        let object = self.closure_objects.get(proto_closure_id);
                        (
                            object.and_then(|object| object.setters.get(&property).cloned()),
                            object.is_some_and(|object| object.getters.contains_key(&property)),
                            object.and_then(|object| {
                                object.properties.get(&property).map(|_| {
                                    object
                                        .property_attributes
                                        .get(&property)
                                        .is_none_or(|attributes| attributes.writable)
                                })
                            }),
                        )
                    }
                    JsValue::HostFunction(proto_host_id) => {
                        let object = self.host_function_objects.get(proto_host_id);
                        (
                            object.and_then(|object| object.setters.get(&property).cloned()),
                            object.is_some_and(|object| object.getters.contains_key(&property)),
                            object.and_then(|object| {
                                object.properties.get(&property).map(|_| {
                                    object
                                        .property_attributes
                                        .get(&property)
                                        .is_none_or(|attributes| attributes.writable)
                                })
                            }),
                        )
                    }
                    JsValue::NativeFunction(proto_native) => {
                        if self.native_function_has_own_property_runtime(*proto_native, &property) {
                            (
                                None,
                                false,
                                Some(self.native_function_is_property_writable(
                                    *proto_native,
                                    &property,
                                )),
                            )
                        } else {
                            (None, false, None)
                        }
                    }
                    _ => (None, false, None),
                };

                if let Some(setter) = setter {
                    if matches!(setter, JsValue::Undefined) {
                        return Ok(value);
                    }
                    let _ = self.execute_callable(
                        setter,
                        Some(JsValue::Function(closure_id)),
                        vec![value.clone()],
                        realm,
                        false,
                    )?;
                    return Ok(value);
                }
                if inherited_getter_exists {
                    return Ok(value);
                }
                if inherited_data_writable == Some(false) {
                    return Ok(value);
                }
                if inherited_data_writable == Some(true) {
                    break;
                }
                current = self.get_prototype_of_value(&current)?;
            }
        }

        Ok(self.set_closure_property(closure_id, property, value))
    }

    fn set_host_function_property(
        &mut self,
        host_id: u64,
        property: String,
        value: JsValue,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        if !self.host_functions.contains_key(&host_id) {
            return Err(VmError::UnknownHostFunction(host_id));
        }

        let (setter, getter_exists, data_writable, own_exists, extensible) = self
            .host_function_objects
            .get(&host_id)
            .map(|object| {
                (
                    object.setters.get(&property).cloned(),
                    object.getters.contains_key(&property),
                    object.properties.get(&property).map(|_| {
                        object
                            .property_attributes
                            .get(&property)
                            .is_none_or(|attributes| attributes.writable)
                    }),
                    object.properties.contains_key(&property)
                        || object.getters.contains_key(&property)
                        || object.setters.contains_key(&property),
                    object.extensible,
                )
            })
            .unwrap_or((None, false, None, false, true));

        if let Some(setter) = setter {
            if matches!(setter, JsValue::Undefined) {
                return Ok(value);
            }
            let _ = self.execute_callable(
                setter,
                Some(JsValue::HostFunction(host_id)),
                vec![value.clone()],
                realm,
                false,
            )?;
            return Ok(value);
        }
        if getter_exists {
            return Ok(value);
        }
        if data_writable == Some(false) {
            return Ok(value);
        }
        if data_writable.is_none() {
            let mut current = self.get_prototype_of_value(&JsValue::HostFunction(host_id))?;
            while Self::is_object_like_value(&current) {
                let (setter, inherited_getter_exists, inherited_data_writable) = match &current {
                    JsValue::Object(object_id) => {
                        let object = self
                            .objects
                            .get(object_id)
                            .ok_or(VmError::UnknownObject(*object_id))?;
                        (
                            object.setters.get(&property).cloned(),
                            object.getters.contains_key(&property),
                            object.properties.get(&property).map(|_| {
                                object
                                    .property_attributes
                                    .get(&property)
                                    .is_none_or(|attributes| attributes.writable)
                            }),
                        )
                    }
                    JsValue::Function(proto_closure_id) => {
                        let object = self.closure_objects.get(proto_closure_id);
                        (
                            object.and_then(|object| object.setters.get(&property).cloned()),
                            object.is_some_and(|object| object.getters.contains_key(&property)),
                            object.and_then(|object| {
                                object.properties.get(&property).map(|_| {
                                    object
                                        .property_attributes
                                        .get(&property)
                                        .is_none_or(|attributes| attributes.writable)
                                })
                            }),
                        )
                    }
                    JsValue::HostFunction(proto_host_id) => {
                        let object = self.host_function_objects.get(proto_host_id);
                        (
                            object.and_then(|object| object.setters.get(&property).cloned()),
                            object.is_some_and(|object| object.getters.contains_key(&property)),
                            object.and_then(|object| {
                                object.properties.get(&property).map(|_| {
                                    object
                                        .property_attributes
                                        .get(&property)
                                        .is_none_or(|attributes| attributes.writable)
                                })
                            }),
                        )
                    }
                    JsValue::NativeFunction(proto_native) => {
                        if self.native_function_has_own_property_runtime(*proto_native, &property) {
                            (
                                None,
                                false,
                                Some(self.native_function_is_property_writable(
                                    *proto_native,
                                    &property,
                                )),
                            )
                        } else {
                            (None, false, None)
                        }
                    }
                    _ => (None, false, None),
                };

                if let Some(setter) = setter {
                    if matches!(setter, JsValue::Undefined) {
                        return Ok(value);
                    }
                    let _ = self.execute_callable(
                        setter,
                        Some(JsValue::HostFunction(host_id)),
                        vec![value.clone()],
                        realm,
                        false,
                    )?;
                    return Ok(value);
                }
                if inherited_getter_exists {
                    return Ok(value);
                }
                if inherited_data_writable == Some(false) {
                    return Ok(value);
                }
                if inherited_data_writable == Some(true) {
                    break;
                }
                current = self.get_prototype_of_value(&current)?;
            }
        }
        if !own_exists && !extensible {
            return Ok(value);
        }
        let object = self.host_function_objects.entry(host_id).or_default();
        object.properties.insert(property.clone(), value.clone());
        object.property_attributes.entry(property).or_default();
        Ok(value)
    }

    fn get_or_create_function_prototype_property(
        &mut self,
        closure_id: u64,
    ) -> Result<JsValue, VmError> {
        if !self.closures.contains_key(&closure_id) {
            return Err(VmError::UnknownClosure(closure_id));
        }
        if let Some(existing) = self
            .closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get("prototype"))
            .cloned()
        {
            return Ok(existing);
        }

        let prototype = self.create_object_value();
        if let JsValue::Object(prototype_id) = prototype {
            if let Some(prototype_object) = self.objects.get_mut(&prototype_id) {
                prototype_object
                    .properties
                    .insert("constructor".to_string(), JsValue::Function(closure_id));
                prototype_object.property_attributes.insert(
                    "constructor".to_string(),
                    PropertyAttributes {
                        writable: true,
                        enumerable: false,
                        configurable: true,
                    },
                );
            }
        }

        let object = self.closure_objects.entry(closure_id).or_default();
        object
            .properties
            .insert("prototype".to_string(), prototype.clone());
        object.property_attributes.insert(
            "prototype".to_string(),
            PropertyAttributes {
                writable: true,
                enumerable: false,
                configurable: false,
            },
        );

        Ok(prototype)
    }

    fn closure_has_own_property(&self, closure_id: u64, property: &str) -> bool {
        self.closure_objects.get(&closure_id).is_some_and(|object| {
            object.properties.contains_key(property)
                || object.getters.contains_key(property)
                || object.setters.contains_key(property)
        })
    }

    fn function_rejects_caller_arguments(&self, closure_id: u64) -> Result<bool, VmError> {
        let closure = self
            .closures
            .get(&closure_id)
            .ok_or(VmError::UnknownClosure(closure_id))?;
        let function = closure
            .functions
            .get(closure.function_id)
            .ok_or(VmError::UnknownFunction(closure.function_id))?;
        Ok(closure.strict
            || self.function_is_arrow(function)
            || self.closure_is_class_constructor(closure_id)
            || self.closure_marks_restricted_caller_arguments(closure_id))
    }

    fn is_restricted_function_property(property: &str) -> bool {
        matches!(property, "caller" | "arguments")
    }

    fn has_own_property(&self, target: &JsValue, property: &str) -> Result<bool, VmError> {
        match target {
            JsValue::Object(object_id) => {
                let object = self
                    .objects
                    .get(object_id)
                    .ok_or(VmError::UnknownObject(*object_id))?;
                Ok(object.properties.contains_key(property)
                    || object.getters.contains_key(property)
                    || object.setters.contains_key(property))
            }
            JsValue::Function(closure_id) => {
                if self.closure_has_own_property(*closure_id, property) {
                    return Ok(true);
                }
                if property == "length" {
                    return Ok(true);
                }
                if property == "prototype" {
                    return Ok(!self.closure_is_arrow(*closure_id)?
                        && !self.closure_has_no_prototype(*closure_id));
                }
                Ok(false)
            }
            JsValue::NativeFunction(native) => {
                Ok(self.native_function_has_own_property_runtime(*native, property))
            }
            JsValue::HostFunction(host_id) => {
                if !self.host_functions.contains_key(host_id) {
                    return Err(VmError::UnknownHostFunction(*host_id));
                }
                if let Some(object) = self.host_function_objects.get(host_id) {
                    return Ok(object.properties.contains_key(property)
                        || object.getters.contains_key(property)
                        || object.setters.contains_key(property));
                }
                Ok(Self::host_function_has_default_property(property))
            }
            _ => Ok(false),
        }
    }

    fn host_function_has_default_property(property: &str) -> bool {
        matches!(
            property,
            "length"
                | "call"
                | "apply"
                | "bind"
                | "toString"
                | "valueOf"
                | "hasOwnProperty"
                | "constructor"
        )
    }

    fn native_function_has_own_property_runtime(
        &self,
        native: NativeFunction,
        property: &str,
    ) -> bool {
        if self
            .native_function_deleted
            .contains(&(native, property.to_string()))
        {
            return false;
        }
        if self
            .native_function_objects
            .get(&native)
            .is_some_and(|object| {
                object.properties.contains_key(property)
                    || object.getters.contains_key(property)
                    || object.setters.contains_key(property)
            })
        {
            return true;
        }
        self.native_function_has_own_property(native, property)
    }

    fn native_function_default_property_attributes(
        &self,
        native: NativeFunction,
        property: &str,
    ) -> Option<PropertyAttributes> {
        if !self.native_function_has_own_property(native, property) {
            return None;
        }
        Some(PropertyAttributes {
            writable: self.native_function_default_property_writable(native, property),
            enumerable: false,
            configurable: self.native_function_default_property_configurable(native, property),
        })
    }

    fn native_function_default_property_writable(
        &self,
        native: NativeFunction,
        property: &str,
    ) -> bool {
        if matches!(property, "length" | "name") {
            return false;
        }
        if property == "prototype" && Self::native_function_is_constructor(native) {
            return false;
        }
        !matches!(
            (native, property),
            (
                NativeFunction::NumberConstructor,
                "NaN"
                    | "POSITIVE_INFINITY"
                    | "NEGATIVE_INFINITY"
                    | "MAX_VALUE"
                    | "MIN_VALUE"
                    | "MAX_SAFE_INTEGER"
                    | "MIN_SAFE_INTEGER"
            )
        )
    }

    fn native_function_default_property_configurable(
        &self,
        native: NativeFunction,
        property: &str,
    ) -> bool {
        if property == "prototype" && Self::native_function_is_constructor(native) {
            return false;
        }
        !matches!(
            (native, property),
            (
                NativeFunction::NumberConstructor,
                "NaN"
                    | "POSITIVE_INFINITY"
                    | "NEGATIVE_INFINITY"
                    | "MAX_VALUE"
                    | "MIN_VALUE"
                    | "MAX_SAFE_INTEGER"
                    | "MIN_SAFE_INTEGER"
            )
        )
    }

    fn native_function_is_property_writable(&self, native: NativeFunction, property: &str) -> bool {
        if let Some(object) = self.native_function_objects.get(&native) {
            if object.properties.contains_key(property) {
                return object
                    .property_attributes
                    .get(property)
                    .is_none_or(|attributes| attributes.writable);
            }
            if object.getters.contains_key(property) || object.setters.contains_key(property) {
                return false;
            }
        }
        self.native_function_default_property_writable(native, property)
    }

    fn native_function_has_own_property(&self, native: NativeFunction, property: &str) -> bool {
        matches!(
            (native, property),
            (NativeFunction::ObjectConstructor, "defineProperty")
                | (NativeFunction::ObjectConstructor, "defineProperties")
                | (NativeFunction::ObjectConstructor, "keys")
                | (NativeFunction::ObjectConstructor, "entries")
                | (NativeFunction::ObjectConstructor, "values")
                | (NativeFunction::ObjectConstructor, "getOwnPropertyNames")
                | (NativeFunction::ObjectConstructor, "create")
                | (NativeFunction::ObjectConstructor, "assign")
                | (NativeFunction::ObjectConstructor, "setPrototypeOf")
                | (NativeFunction::ObjectConstructor, "preventExtensions")
                | (NativeFunction::ObjectConstructor, "__forInKeys")
                | (NativeFunction::ObjectConstructor, "__forOfValues")
                | (NativeFunction::ObjectConstructor, "__forOfIterator")
                | (NativeFunction::ObjectConstructor, "__forOfStep")
                | (NativeFunction::ObjectConstructor, "__forOfClose")
                | (NativeFunction::ObjectConstructor, "__getTemplateObject")
                | (NativeFunction::ObjectConstructor, "__tdzMarker")
                | (
                    NativeFunction::ObjectConstructor,
                    "getOwnPropertyDescriptor"
                )
                | (
                    NativeFunction::ObjectConstructor,
                    "getOwnPropertyDescriptors"
                )
                | (NativeFunction::ArrayConstructor, "isArray")
                | (NativeFunction::ArrayConstructor, "from")
                | (NativeFunction::ArrayConstructor, "of")
                | (NativeFunction::ObjectConstructor, "getPrototypeOf")
                | (NativeFunction::ObjectConstructor, "isExtensible")
                | (NativeFunction::ObjectConstructor, "isSealed")
                | (NativeFunction::ObjectConstructor, "isFrozen")
                | (NativeFunction::ObjectConstructor, "is")
                | (NativeFunction::ObjectConstructor, "seal")
                | (NativeFunction::ObjectConstructor, "freeze")
                | (NativeFunction::ObjectConstructor, "toString")
                | (NativeFunction::ObjectConstructor, "valueOf")
                | (NativeFunction::DateConstructor, "parse")
                | (NativeFunction::DateConstructor, "UTC")
                | (NativeFunction::ProxyConstructor, "revocable")
                | (NativeFunction::StringConstructor, "fromCharCode")
                | (NativeFunction::NumberConstructor, "NaN")
                | (NativeFunction::NumberConstructor, "POSITIVE_INFINITY")
                | (NativeFunction::NumberConstructor, "NEGATIVE_INFINITY")
                | (NativeFunction::NumberConstructor, "MAX_VALUE")
                | (NativeFunction::NumberConstructor, "MIN_VALUE")
                | (NativeFunction::NumberConstructor, "MAX_SAFE_INTEGER")
                | (NativeFunction::NumberConstructor, "MIN_SAFE_INTEGER")
                | (NativeFunction::NumberConstructor, "isNaN")
                | (NativeFunction::NumberConstructor, "isFinite")
                | (NativeFunction::NumberConstructor, "isInteger")
                | (NativeFunction::NumberConstructor, "isSafeInteger")
                | (NativeFunction::SymbolConstructor, "iterator")
                | (NativeFunction::SymbolConstructor, "asyncIterator")
                | (NativeFunction::SymbolConstructor, "hasInstance")
                | (NativeFunction::SymbolConstructor, "isConcatSpreadable")
                | (NativeFunction::SymbolConstructor, "match")
                | (NativeFunction::SymbolConstructor, "matchAll")
                | (NativeFunction::SymbolConstructor, "replace")
                | (NativeFunction::SymbolConstructor, "search")
                | (NativeFunction::SymbolConstructor, "species")
                | (NativeFunction::SymbolConstructor, "split")
                | (NativeFunction::SymbolConstructor, "toPrimitive")
                | (NativeFunction::SymbolConstructor, "toStringTag")
                | (NativeFunction::SymbolConstructor, "unscopables")
                | (NativeFunction::Assert, "sameValue")
                | (NativeFunction::Assert, "notSameValue")
                | (NativeFunction::Assert, "throws")
                | (NativeFunction::Assert, "compareArray")
                | (NativeFunction::FunctionConstructor, "prototype")
                | (NativeFunction::GeneratorFunctionConstructor, "prototype")
                | (NativeFunction::Test262Error, "prototype")
                | (NativeFunction::ObjectConstructor, "prototype")
                | (NativeFunction::ArrayConstructor, "prototype")
                | (NativeFunction::StringConstructor, "prototype")
                | (NativeFunction::NumberConstructor, "prototype")
                | (NativeFunction::BooleanConstructor, "prototype")
                | (NativeFunction::ErrorConstructor, "prototype")
                | (NativeFunction::TypeErrorConstructor, "prototype")
                | (NativeFunction::ReferenceErrorConstructor, "prototype")
                | (NativeFunction::SyntaxErrorConstructor, "prototype")
                | (NativeFunction::EvalErrorConstructor, "prototype")
                | (NativeFunction::RangeErrorConstructor, "prototype")
                | (NativeFunction::URIErrorConstructor, "prototype")
                | (NativeFunction::DateConstructor, "prototype")
                | (NativeFunction::ArrayBufferConstructor, "prototype")
                | (NativeFunction::DataViewConstructor, "prototype")
                | (NativeFunction::MapConstructor, "prototype")
                | (NativeFunction::SetConstructor, "prototype")
                | (NativeFunction::WeakMapConstructor, "prototype")
                | (NativeFunction::WeakSetConstructor, "prototype")
                | (NativeFunction::PromiseConstructor, "prototype")
                | (NativeFunction::Uint8ArrayConstructor, "prototype")
                | (NativeFunction::RegExpConstructor, "prototype")
                | (NativeFunction::SymbolConstructor, "prototype")
                | (_, "name")
                | (_, "length")
                | (_, "constructor")
        )
    }

    fn is_array_length_tracking_object(&self, object_id: ObjectId) -> Result<bool, VmError> {
        let object = self
            .objects
            .get(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        if !object.properties.contains_key("length") {
            return Ok(false);
        }
        let Some(attributes) = object.property_attributes.get("length") else {
            return Ok(false);
        };
        if attributes.enumerable || attributes.configurable {
            return Ok(false);
        }
        let Some(array_prototype_id) = self.array_prototype_id else {
            return Ok(false);
        };
        self.object_inherits_prototype(object_id, array_prototype_id)
    }

    fn object_inherits_prototype(
        &self,
        object_id: ObjectId,
        target_prototype: ObjectId,
    ) -> Result<bool, VmError> {
        let mut current = Some(object_id);
        while let Some(id) = current {
            if id == target_prototype {
                return Ok(true);
            }
            current = self
                .objects
                .get(&id)
                .ok_or(VmError::UnknownObject(id))?
                .prototype;
        }
        Ok(false)
    }

    fn canonical_array_index(property: &str) -> Option<usize> {
        if property.is_empty() {
            return None;
        }
        if property != "0" && property.starts_with('0') {
            return None;
        }
        let index = property.parse::<u64>().ok()?;
        if index >= u32::MAX as u64 {
            return None;
        }
        if index.to_string() != property {
            return None;
        }
        Some(index as usize)
    }

    fn array_index_decimal_key(index: usize, buf: &mut [u8; 20]) -> &str {
        let mut cursor = buf.len();
        let mut remaining = index;
        loop {
            cursor = cursor.saturating_sub(1);
            buf[cursor] = b'0' + (remaining % 10) as u8;
            remaining /= 10;
            if remaining == 0 {
                break;
            }
        }
        // digits were generated from decimal ASCII bytes
        std::str::from_utf8(&buf[cursor..]).expect("array index decimal conversion must be utf-8")
    }

    fn canonical_array_index_from_property_value(value: &JsValue) -> Option<usize> {
        match value {
            JsValue::Number(number)
                if number.is_finite() && *number >= 0.0 && number.fract() == 0.0 =>
            {
                let index = *number as u64;
                if index >= u32::MAX as u64 {
                    return None;
                }
                Some(index as usize)
            }
            JsValue::String(property) => Self::canonical_array_index(property),
            _ => None,
        }
    }

    fn coerce_valid_array_length_or_throw(
        &mut self,
        value: JsValue,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<usize, VmError> {
        let number = self.coerce_number_runtime(value, realm, caller_strict)?;
        let uint = Self::to_uint32_number(number) as f64;
        if !number.is_finite() || number < 0.0 || number != uint {
            return Err(VmError::UncaughtException(self.create_error_exception(
                NativeFunction::RangeErrorConstructor,
                "RangeError",
                "Invalid array length".to_string(),
            )));
        }
        Ok(uint as usize)
    }

    fn set_array_length_property(
        &mut self,
        object_id: ObjectId,
        requested_length: usize,
        throw_on_failure: bool,
    ) -> Result<(), VmError> {
        let current_length = self.array_length(object_id)?;
        {
            let object = self
                .objects
                .get_mut(&object_id)
                .ok_or(VmError::UnknownObject(object_id))?;
            if object
                .property_attributes
                .get("length")
                .is_some_and(|attributes| !attributes.writable)
            {
                if requested_length == current_length {
                    return Ok(());
                }
                if throw_on_failure {
                    return Err(VmError::TypeError("array length is non-writable"));
                }
                return Ok(());
            }
            Self::set_object_array_length(object, requested_length);
            object
                .property_attributes
                .entry("length".to_string())
                .or_insert(PropertyAttributes {
                    writable: true,
                    enumerable: false,
                    configurable: false,
                });
        }
        if requested_length >= current_length {
            return Ok(());
        }
        let mut array_indices_to_delete: BTreeSet<usize> = BTreeSet::new();
        {
            let object = self
                .objects
                .get(&object_id)
                .ok_or(VmError::UnknownObject(object_id))?;
            for key in object
                .properties
                .keys()
                .chain(object.getters.keys())
                .chain(object.setters.keys())
                .chain(object.property_attributes.keys())
            {
                if let Some(index) = Self::canonical_array_index(key) {
                    if index >= requested_length && index < current_length {
                        array_indices_to_delete.insert(index);
                    }
                }
            }
        }
        for index in array_indices_to_delete.into_iter().rev() {
            let key = index.to_string();
            let object = self
                .objects
                .get_mut(&object_id)
                .ok_or(VmError::UnknownObject(object_id))?;
            if object
                .property_attributes
                .get(&key)
                .is_some_and(|attributes| !attributes.configurable)
            {
                Self::set_object_array_length(object, index + 1);
                if throw_on_failure {
                    return Err(VmError::TypeError(
                        "cannot delete non-configurable array element",
                    ));
                }
                return Ok(());
            }
            object.properties.remove(&key);
            object.getters.remove(&key);
            object.setters.remove(&key);
            object.property_attributes.remove(&key);
        }
        Ok(())
    }

    fn set_array_index_property(
        &mut self,
        object_id: ObjectId,
        index: usize,
        property: String,
        value: JsValue,
    ) -> Result<(), VmError> {
        let current_length = self.array_length(object_id)?;
        let next_length = (index + 1).max(current_length);
        let object = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        object.properties.insert(property.clone(), value);
        if next_length != current_length {
            Self::set_object_array_length(object, next_length);
        }
        Ok(())
    }

    fn set_uint8_array_index_property(
        &mut self,
        object_id: ObjectId,
        index: usize,
        value: &JsValue,
    ) -> Result<(), VmError> {
        let length = self
            .objects
            .get(&object_id)
            .and_then(|object| object.properties.get("length"))
            .map(|value| self.length_value_to_usize(value))
            .unwrap_or(0);
        if index >= length {
            return Ok(());
        }
        let numeric = self.to_number(value);
        let clamped = if !numeric.is_finite() || numeric == 0.0 {
            0.0
        } else {
            let integer = numeric.trunc() as i64;
            let wrapped = ((integer % 256) + 256) % 256;
            wrapped as f64
        };
        let object = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        let key = index.to_string();
        object
            .properties
            .insert(key.clone(), JsValue::Number(clamped));
        object
            .property_attributes
            .entry(key)
            .or_insert(PropertyAttributes {
                writable: true,
                enumerable: true,
                configurable: false,
            });
        Ok(())
    }

    fn current_array_literal_target(&self) -> Result<ObjectId, VmError> {
        match self.stack.last() {
            Some(JsValue::Object(object_id)) => Ok(*object_id),
            Some(_) => Err(VmError::TypeError("array literal target expects object")),
            None => Err(VmError::StackUnderflow),
        }
    }

    fn array_push_value(&mut self, object_id: ObjectId, value: JsValue) -> Result<(), VmError> {
        let index = self.array_length(object_id)?;
        let object = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        let key = index.to_string();
        object.properties.insert(key.clone(), value);
        Self::set_object_array_length(object, index + 1);
        Ok(())
    }

    fn array_advance_length(&mut self, object_id: ObjectId, by: usize) -> Result<(), VmError> {
        let index = self.array_length(object_id)?;
        let object = self
            .objects
            .get_mut(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        Self::set_object_array_length(object, index + by);
        Ok(())
    }

    fn array_length(&self, object_id: ObjectId) -> Result<usize, VmError> {
        let object = self
            .objects
            .get(&object_id)
            .ok_or(VmError::UnknownObject(object_id))?;
        if let Some(length) = object.array_length {
            return Ok(length);
        }
        let length = object
            .properties
            .get("length")
            .map(|value| self.length_value_to_usize(value))
            .unwrap_or(0);
        Ok(length)
    }

    #[inline(always)]
    fn length_value_to_usize(&self, value: &JsValue) -> usize {
        let length = match value {
            JsValue::Number(number) => *number,
            other => self.to_number(other),
        };
        length.max(0.0) as usize
    }

    #[inline(always)]
    fn set_object_array_length(object: &mut JsObject, length: usize) {
        object.array_length = Some(length);
        if let Some(current) = object.properties.get_mut("length") {
            *current = JsValue::Number(length as f64);
            return;
        }
        object
            .properties
            .insert("length".to_string(), JsValue::Number(length as f64));
    }

    #[inline(always)]
    fn mark_packet_b_prototype_chain_maybe_indexed(&mut self, object_id: ObjectId, property: &str) {
        if self.packet_b_prototype_chain_may_have_indexed_property {
            return;
        }
        if !matches!(self.array_prototype_id, Some(id) if id == object_id)
            && !matches!(self.object_prototype_id, Some(id) if id == object_id)
        {
            return;
        }
        if Self::canonical_array_index(property).is_some() {
            self.packet_b_prototype_chain_may_have_indexed_property = true;
        }
    }

    fn to_length_from_number(number: f64) -> i64 {
        if number.is_nan() || number <= 0.0 {
            return 0;
        }
        if number.is_infinite() {
            return MAX_SAFE_INTEGER_F64 as i64;
        }
        number.floor().min(MAX_SAFE_INTEGER_F64) as i64
    }

    fn array_like_length_from_value(
        &mut self,
        value: &JsValue,
        realm: &Realm,
    ) -> Result<i64, VmError> {
        let length_value = self.get_property_from_receiver(value.clone(), "length", realm)?;
        Ok(Self::to_length_from_number(self.to_number(&length_value)))
    }

    fn execute_array_index_lookup(
        &mut self,
        this_arg: Option<JsValue>,
        args: &[JsValue],
        realm: &Realm,
        from_end: bool,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        fn to_integer_or_infinity(number: f64) -> f64 {
            if number.is_nan() || number == 0.0 {
                0.0
            } else if number.is_infinite() {
                number
            } else {
                number.trunc()
            }
        }

        let target = self.object_prototype_this_object(
            this_arg,
            "Array.prototype indexOf/lastIndexOf receiver must be object",
        )?;
        let search = args.first().cloned().unwrap_or(JsValue::Undefined);
        let length_value = self.get_property_from_receiver(target.clone(), "length", realm)?;
        let length_number = self.coerce_number_runtime(length_value, realm, caller_strict)?;
        let length = Self::to_length_from_number(length_number);
        if length <= 0 {
            return Ok(JsValue::Number(-1.0));
        }

        let from_index = match args.get(1) {
            Some(value) => to_integer_or_infinity(self.coerce_number_runtime(
                value.clone(),
                realm,
                caller_strict,
            )?),
            None => {
                if from_end {
                    (length - 1) as f64
                } else {
                    0.0
                }
            }
        };

        let mut current = if from_end {
            let index = if from_index >= 0.0 {
                from_index.min((length - 1) as f64)
            } else {
                (length as f64) + from_index
            };
            if index < 0.0 {
                return Ok(JsValue::Number(-1.0));
            }
            index as i64
        } else {
            let index = if from_index >= 0.0 {
                from_index
            } else {
                ((length as f64) + from_index).max(0.0)
            };
            if index >= length as f64 {
                return Ok(JsValue::Number(-1.0));
            }
            index as i64
        };

        if from_end && current < 0 {
            return Ok(JsValue::Number(-1.0));
        }

        loop {
            if !from_end && current >= length {
                break;
            }
            if from_end && current < 0 {
                break;
            }
            let key = current.to_string();
            if self.has_property_on_receiver(&target, &key, realm)? {
                let candidate = self.get_property_from_receiver(target.clone(), &key, realm)?;
                if self.strict_equality_compare(&candidate, &search) {
                    return Ok(JsValue::Number(current as f64));
                }
            }
            if from_end {
                current -= 1;
            } else {
                current += 1;
            }
        }

        Ok(JsValue::Number(-1.0))
    }

    fn execute_array_join(
        &mut self,
        object_id: ObjectId,
        separator: &str,
    ) -> Result<JsValue, VmError> {
        let length = self.array_length(object_id)?;
        let mut parts = Vec::with_capacity(length);
        for index in 0..length {
            let key = index.to_string();
            let value = self
                .objects
                .get(&object_id)
                .and_then(|object| object.properties.get(&key).cloned());
            let part = match value {
                None | Some(JsValue::Undefined) | Some(JsValue::Null) => String::new(),
                Some(JsValue::Object(nested_id))
                    if self.objects.get(&nested_id).is_some_and(|object| {
                        object.properties.contains_key("length")
                            && object.prototype == self.array_prototype_id
                    }) =>
                {
                    match self.execute_array_join(nested_id, ",")? {
                        JsValue::String(text) => text,
                        other => self.coerce_to_string(&other),
                    }
                }
                Some(value) => self.coerce_to_string(&value),
            };
            parts.push(part);
        }
        Ok(JsValue::String(parts.join(separator)))
    }

    fn execute_array_reverse_this(
        &mut self,
        this_arg: Option<JsValue>,
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        let target = self.object_prototype_this_object(
            this_arg,
            "Array.prototype.reverse called on null or undefined",
        )?;
        let length_value = self.get_property_from_receiver(target.clone(), "length", realm)?;
        let length_number = self.coerce_number_runtime(length_value, realm, caller_strict)?;
        let length = Self::to_length_from_number(length_number);
        let middle = length / 2;

        for lower in 0..middle {
            let upper = length - lower - 1;
            let lower_key = lower.to_string();
            let upper_key = upper.to_string();
            let lower_exists = self.has_property_on_receiver(&target, &lower_key, realm)?;
            let lower_value = if lower_exists {
                Some(self.get_property_from_receiver(target.clone(), &lower_key, realm)?)
            } else {
                None
            };
            let upper_exists = self.has_property_on_receiver(&target, &upper_key, realm)?;
            let upper_value = if upper_exists {
                Some(self.get_property_from_receiver(target.clone(), &upper_key, realm)?)
            } else {
                None
            };

            match (lower_value, upper_value) {
                (Some(lower_value), Some(upper_value)) => {
                    self.ensure_assign_target_writable(&target, &lower_key)?;
                    let _ = self.set_property_on_receiver(
                        target.clone(),
                        lower_key,
                        upper_value,
                        realm,
                    )?;
                    self.ensure_assign_target_writable(&target, &upper_key)?;
                    let _ = self.set_property_on_receiver(
                        target.clone(),
                        upper_key,
                        lower_value,
                        realm,
                    )?;
                }
                (None, Some(upper_value)) => {
                    self.ensure_assign_target_writable(&target, &lower_key)?;
                    let _ = self.set_property_on_receiver(
                        target.clone(),
                        lower_key,
                        upper_value,
                        realm,
                    )?;
                    let deleted = self.delete_property(target.clone(), upper_key)?;
                    if !deleted {
                        return Err(VmError::TypeError(
                            "Array.prototype.reverse could not delete property",
                        ));
                    }
                }
                (Some(lower_value), None) => {
                    let deleted = self.delete_property(target.clone(), lower_key)?;
                    if !deleted {
                        return Err(VmError::TypeError(
                            "Array.prototype.reverse could not delete property",
                        ));
                    }
                    self.ensure_assign_target_writable(&target, &upper_key)?;
                    let _ = self.set_property_on_receiver(
                        target.clone(),
                        upper_key,
                        lower_value,
                        realm,
                    )?;
                }
                (None, None) => {}
            }
        }
        Ok(target)
    }

    fn execute_array_sort_this(
        &mut self,
        this_arg: Option<JsValue>,
        args: &[JsValue],
        realm: &Realm,
        caller_strict: bool,
    ) -> Result<JsValue, VmError> {
        struct ArraySortSlot {
            value: JsValue,
            pos: i64,
            string_key: Option<String>,
        }

        let target = self.object_prototype_this_object(
            this_arg,
            "Array.prototype.sort called on null or undefined",
        )?;
        let length_value = self.get_property_from_receiver(target.clone(), "length", realm)?;
        let length_number = self.coerce_number_runtime(length_value, realm, caller_strict)?;
        let length = Self::to_length_from_number(length_number);

        let compare_fn = match args.first() {
            None | Some(JsValue::Undefined) => None,
            Some(value) if Self::is_callable_value(value) => Some(value.clone()),
            Some(_) => return Err(VmError::TypeError("Array.prototype.sort comparefn")),
        };

        let mut slots = Vec::new();
        let mut undefined_count = 0i64;
        for index in 0..length {
            let key = index.to_string();
            if !self.has_property_on_receiver(&target, &key, realm)? {
                continue;
            }
            let value = self.get_property_from_receiver(target.clone(), &key, realm)?;
            if matches!(value, JsValue::Undefined) {
                undefined_count += 1;
                continue;
            }
            slots.push(ArraySortSlot {
                value,
                pos: index,
                string_key: None,
            });
        }

        if let Some(compare_fn) = compare_fn {
            let mut comparison_error: Option<VmError> = None;
            slots.sort_by(|left, right| {
                if comparison_error.is_some() {
                    return std::cmp::Ordering::Equal;
                }
                let comparison = match self.execute_callable(
                    compare_fn.clone(),
                    Some(JsValue::Undefined),
                    vec![left.value.clone(), right.value.clone()],
                    realm,
                    caller_strict,
                ) {
                    Ok(value) => value,
                    Err(error) => {
                        comparison_error = Some(error);
                        return std::cmp::Ordering::Equal;
                    }
                };
                let number = match self.coerce_number_runtime(comparison, realm, caller_strict) {
                    Ok(value) => value,
                    Err(error) => {
                        comparison_error = Some(error);
                        return std::cmp::Ordering::Equal;
                    }
                };
                let ordering = if number.is_nan() {
                    std::cmp::Ordering::Equal
                } else if number < 0.0 {
                    std::cmp::Ordering::Less
                } else if number > 0.0 {
                    std::cmp::Ordering::Greater
                } else {
                    std::cmp::Ordering::Equal
                };
                if ordering == std::cmp::Ordering::Equal {
                    left.pos.cmp(&right.pos)
                } else {
                    ordering
                }
            });
            if let Some(error) = comparison_error {
                return Err(error);
            }
        } else {
            for slot in &mut slots {
                slot.string_key = Some(self.coerce_to_string_runtime(
                    slot.value.clone(),
                    realm,
                    caller_strict,
                )?);
            }
            slots.sort_by(|left, right| {
                let left_key = left.string_key.as_deref().unwrap_or("");
                let right_key = right.string_key.as_deref().unwrap_or("");
                match left_key.cmp(right_key) {
                    std::cmp::Ordering::Equal => left.pos.cmp(&right.pos),
                    ordering => ordering,
                }
            });
        }

        let mut write_index = 0i64;
        for slot in slots {
            if slot.pos != write_index {
                let key = write_index.to_string();
                self.ensure_assign_target_writable(&target, &key)?;
                let _ = self.set_property_on_receiver(target.clone(), key, slot.value, realm)?;
            }
            write_index += 1;
        }
        for _ in 0..undefined_count {
            let key = write_index.to_string();
            self.ensure_assign_target_writable(&target, &key)?;
            let _ =
                self.set_property_on_receiver(target.clone(), key, JsValue::Undefined, realm)?;
            write_index += 1;
        }
        while write_index < length {
            let deleted = self.delete_property(target.clone(), write_index.to_string())?;
            if !deleted {
                return Err(VmError::TypeError(
                    "Array.prototype.sort could not delete property",
                ));
            }
            write_index += 1;
        }

        Ok(target)
    }

    fn evaluate_in_operator(
        &mut self,
        key: String,
        right: JsValue,
        realm: &Realm,
    ) -> Result<bool, VmError> {
        match right {
            JsValue::Object(object_id) => self.object_has_property_in_chain(object_id, &key, realm),
            JsValue::Function(closure_id) => {
                self.has_property_on_receiver(&JsValue::Function(closure_id), &key, realm)
            }
            JsValue::NativeFunction(native) => {
                self.has_property_on_receiver(&JsValue::NativeFunction(native), &key, realm)
            }
            JsValue::HostFunction(host_id) => {
                self.has_property_on_receiver(&JsValue::HostFunction(host_id), &key, realm)
            }
            _ => Err(VmError::TypeError("right-hand side of 'in' expects object")),
        }
    }

    fn evaluate_instanceof_operator(
        &mut self,
        left: JsValue,
        right: JsValue,
        realm: &Realm,
    ) -> Result<bool, VmError> {
        if !Self::is_callable_value(&right) {
            return Err(VmError::TypeError(
                "right-hand side of 'instanceof' is not callable",
            ));
        }

        if matches!(
            &right,
            JsValue::NativeFunction(NativeFunction::Test262Error)
        ) {
            return match left {
                JsValue::String(message) => {
                    Ok(Self::error_message_matches(&message, "Test262Error"))
                }
                JsValue::Object(object_id) => {
                    let constructor = self.get_object_property(object_id, "constructor", realm)?;
                    Ok(matches!(
                        constructor,
                        JsValue::NativeFunction(NativeFunction::Test262Error)
                    ))
                }
                _ => Ok(false),
            };
        }

        match left {
            JsValue::String(message) => match right {
                JsValue::NativeFunction(NativeFunction::ErrorConstructor) => {
                    Ok(Self::is_error_string(&message))
                }
                JsValue::NativeFunction(NativeFunction::TypeErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "TypeError"))
                }
                JsValue::NativeFunction(NativeFunction::ReferenceErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "ReferenceError"))
                }
                JsValue::NativeFunction(NativeFunction::SyntaxErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "SyntaxError"))
                }
                JsValue::NativeFunction(NativeFunction::EvalErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "EvalError"))
                }
                JsValue::NativeFunction(NativeFunction::RangeErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "RangeError"))
                }
                JsValue::NativeFunction(NativeFunction::URIErrorConstructor) => {
                    Ok(Self::error_message_matches(&message, "URIError"))
                }
                _ => Ok(false),
            },
            _ => {
                if !Self::is_object_like_value(&left) {
                    return Ok(false);
                }
                let prototype = if let JsValue::HostFunction(host_id) = right {
                    if Some(host_id) == self.function_prototype_host_id {
                        if let Some(getter) = self.function_prototype_prototype_getter.clone() {
                            self.execute_callable(
                                getter,
                                Some(JsValue::HostFunction(host_id)),
                                Vec::new(),
                                realm,
                                false,
                            )?
                        } else {
                            self.get_property_from_receiver(
                                JsValue::HostFunction(host_id),
                                "prototype",
                                realm,
                            )?
                        }
                    } else {
                        self.get_property_from_receiver(
                            JsValue::HostFunction(host_id),
                            "prototype",
                            realm,
                        )?
                    }
                } else {
                    self.get_property_from_receiver(right.clone(), "prototype", realm)?
                };
                if !Self::is_object_like_value(&prototype) {
                    return Err(VmError::TypeError(
                        "Function has non-object prototype in instanceof",
                    ));
                }
                if let JsValue::Object(object_id) = left {
                    let constructor = self.get_object_property(object_id, "constructor", realm)?;
                    if self.same_value(&constructor, &right) {
                        return Ok(true);
                    }
                }
                let mut current = self.get_prototype_of_value(&left)?;
                while Self::is_object_like_value(&current) {
                    if self.same_value(&current, &prototype) {
                        return Ok(true);
                    }
                    current = self.get_prototype_of_value(&current)?;
                }
                Ok(false)
            }
        }
    }

    fn is_callable_value(value: &JsValue) -> bool {
        matches!(
            value,
            JsValue::Function(_) | JsValue::NativeFunction(_) | JsValue::HostFunction(_)
        )
    }

    fn object_is_prototype_of(
        &mut self,
        prototype: JsValue,
        value: JsValue,
    ) -> Result<bool, VmError> {
        if !Self::is_object_like_value(&prototype) {
            return Ok(false);
        }
        let mut current = self.get_prototype_of_value(&value)?;
        while Self::is_object_like_value(&current) {
            if self.same_value(&current, &prototype) {
                return Ok(true);
            }
            current = self.get_prototype_of_value(&current)?;
        }
        Ok(false)
    }

    fn is_object_like_value(value: &JsValue) -> bool {
        matches!(
            value,
            JsValue::Object(_)
                | JsValue::Function(_)
                | JsValue::NativeFunction(_)
                | JsValue::HostFunction(_)
        )
    }

    fn get_prototype_of_value(&mut self, value: &JsValue) -> Result<JsValue, VmError> {
        match value {
            JsValue::Object(object_id) => {
                let object = self
                    .objects
                    .get(object_id)
                    .ok_or(VmError::UnknownObject(*object_id))?;
                Ok(object
                    .prototype_value
                    .clone()
                    .or_else(|| object.prototype.map(JsValue::Object))
                    .unwrap_or(JsValue::Null))
            }
            JsValue::Function(closure_id) => {
                if let Some(closure_object) = self.closure_objects.get(closure_id) {
                    if closure_object.prototype_overridden {
                        return Ok(closure_object
                            .prototype_value
                            .clone()
                            .or_else(|| closure_object.prototype.map(JsValue::Object))
                            .unwrap_or(JsValue::Null));
                    }
                    if let Some(parent) = closure_object
                        .properties
                        .get(CLASS_CONSTRUCTOR_PARENT_MARKER)
                        .cloned()
                    {
                        return Ok(parent);
                    }
                }
                if self.closure_is_generator(*closure_id)? {
                    return Ok(self.generator_function_prototype_value());
                }
                Ok(self.function_prototype_value())
            }
            JsValue::HostFunction(host_id) => {
                if let Some(host_object) = self.host_function_objects.get(host_id) {
                    if host_object.prototype_overridden {
                        return Ok(host_object
                            .prototype_value
                            .clone()
                            .or_else(|| host_object.prototype.map(JsValue::Object))
                            .unwrap_or(JsValue::Null));
                    }
                }
                if matches!(value, JsValue::HostFunction(host_id) if Some(*host_id) == self.function_prototype_host_id)
                {
                    Ok(self.object_prototype_value())
                } else {
                    Ok(self.function_prototype_value())
                }
            }
            JsValue::NativeFunction(native) => {
                if let Some(native_object) = self.native_function_objects.get(native) {
                    if native_object.prototype_overridden {
                        return Ok(native_object
                            .prototype_value
                            .clone()
                            .or_else(|| native_object.prototype.map(JsValue::Object))
                            .unwrap_or(JsValue::Null));
                    }
                }
                match native {
                    NativeFunction::TypeErrorConstructor
                    | NativeFunction::ReferenceErrorConstructor
                    | NativeFunction::SyntaxErrorConstructor
                    | NativeFunction::EvalErrorConstructor
                    | NativeFunction::RangeErrorConstructor
                    | NativeFunction::URIErrorConstructor => {
                        Ok(JsValue::NativeFunction(NativeFunction::ErrorConstructor))
                    }
                    _ => Ok(self.function_prototype_value()),
                }
            }
            _ => Ok(JsValue::Null),
        }
    }

    fn is_error_string(message: &str) -> bool {
        Self::error_message_matches(message, "TypeError")
            || Self::error_message_matches(message, "ReferenceError")
            || Self::error_message_matches(message, "SyntaxError")
            || Self::error_message_matches(message, "Test262Error")
            || Self::error_message_matches(message, "EvalError")
            || Self::error_message_matches(message, "RangeError")
            || Self::error_message_matches(message, "URIError")
            || Self::error_message_matches(message, "Error")
    }

    fn error_message_matches(message: &str, name: &str) -> bool {
        message == name || message.starts_with(&format!("{name}:"))
    }

    fn delete_property(&mut self, receiver: JsValue, property: String) -> Result<bool, VmError> {
        match receiver {
            JsValue::Object(object_id) => self.delete_object_property(object_id, &property),
            JsValue::Function(closure_id) => {
                Ok(self.delete_closure_property(closure_id, &property))
            }
            JsValue::HostFunction(host_id) => {
                Ok(self.delete_host_function_property(host_id, &property))
            }
            JsValue::NativeFunction(native) => {
                Ok(self.delete_native_function_property(native, &property))
            }
            JsValue::Null | JsValue::Undefined | JsValue::Uninitialized => {
                Err(VmError::TypeError("property access expects object"))
            }
            _ => Ok(true),
        }
    }

    fn delete_object_property(
        &mut self,
        object_id: ObjectId,
        property: &str,
    ) -> Result<bool, VmError> {
        let is_configurable = self
            .objects
            .get(&object_id)
            .ok_or_else(|| self.classify_unknown_object_error(object_id))?
            .property_attributes
            .get(property)
            .map(|attributes| attributes.configurable)
            .unwrap_or(true);
        if !is_configurable {
            return Ok(false);
        }
        let object = match self.objects.get_mut(&object_id) {
            Some(object) => object,
            None => return Err(self.classify_unknown_object_error(object_id)),
        };
        object.properties.remove(property);
        object.getters.remove(property);
        object.setters.remove(property);
        object.property_attributes.remove(property);
        object.argument_mappings.remove(property);
        Ok(true)
    }

    fn delete_closure_property(&mut self, closure_id: u64, property: &str) -> bool {
        let Some(object) = self.closure_objects.get_mut(&closure_id) else {
            return true;
        };
        let is_configurable = object
            .property_attributes
            .get(property)
            .map(|attributes| attributes.configurable)
            .unwrap_or(true);
        if !is_configurable {
            return false;
        }
        object.properties.remove(property);
        object.getters.remove(property);
        object.setters.remove(property);
        object.property_attributes.remove(property);
        object.argument_mappings.remove(property);
        true
    }

    fn delete_host_function_property(&mut self, host_id: u64, property: &str) -> bool {
        if !self.host_functions.contains_key(&host_id) {
            return false;
        }
        let Some(object) = self.host_function_objects.get_mut(&host_id) else {
            return true;
        };
        let is_configurable = object
            .property_attributes
            .get(property)
            .map(|attributes| attributes.configurable)
            .unwrap_or(true);
        if !is_configurable {
            return false;
        }
        object.properties.remove(property);
        object.getters.remove(property);
        object.setters.remove(property);
        object.property_attributes.remove(property);
        object.argument_mappings.remove(property);
        true
    }

    fn delete_native_function_property(&mut self, native: NativeFunction, property: &str) -> bool {
        if let Some(object) = self.native_function_objects.get_mut(&native) {
            if object.properties.contains_key(property)
                || object.getters.contains_key(property)
                || object.setters.contains_key(property)
            {
                let configurable = object
                    .property_attributes
                    .get(property)
                    .map(|attributes| attributes.configurable)
                    .unwrap_or(true);
                if !configurable {
                    return false;
                }
                object.properties.remove(property);
                object.getters.remove(property);
                object.setters.remove(property);
                object.property_attributes.remove(property);
                object.argument_mappings.remove(property);
                self.native_function_deleted
                    .remove(&(native, property.to_string()));
                return true;
            }
        }
        if self
            .native_function_deleted
            .contains(&(native, property.to_string()))
        {
            return true;
        }
        if !self.native_function_has_own_property(native, property) {
            return true;
        }
        if !self.native_function_default_property_configurable(native, property) {
            return false;
        }
        self.native_function_deleted
            .insert((native, property.to_string()));
        true
    }

    fn get_host_function_property(
        &mut self,
        host_id: u64,
        property: &str,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        if !self.host_functions.contains_key(&host_id) {
            return Err(VmError::UnknownHostFunction(host_id));
        }

        let (data_value, getter_value, has_setter, has_shadow_object) = self
            .host_function_objects
            .get(&host_id)
            .map(|object| {
                (
                    object.properties.get(property).cloned(),
                    object.getters.get(property).cloned(),
                    object.setters.contains_key(property),
                    true,
                )
            })
            .unwrap_or((None, None, false, false));
        if let Some(getter) = getter_value {
            return self.execute_callable(
                getter,
                Some(JsValue::HostFunction(host_id)),
                Vec::new(),
                realm,
                false,
            );
        }
        if has_setter {
            return Ok(JsValue::Undefined);
        }
        if let Some(value) = data_value {
            return Ok(value);
        }
        if has_shadow_object && matches!(property, "length" | "name") {
            return Ok(JsValue::Undefined);
        }

        match property {
            "hasOwnProperty" => Ok(
                self.create_host_function_value(HostFunction::HasOwnProperty {
                    target: JsValue::HostFunction(host_id),
                }),
            ),
            "isPrototypeOf" => Ok(
                self.create_host_function_value(HostFunction::IsPrototypeOf {
                    target: JsValue::HostFunction(host_id),
                }),
            ),
            "call" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::HostFunction(host_id),
                method: FunctionMethod::Call,
            })),
            "apply" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::HostFunction(host_id),
                method: FunctionMethod::Apply,
            })),
            "bind" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::HostFunction(host_id),
                method: FunctionMethod::Bind,
            })),
            "length" => Ok(JsValue::Number(0.0)),
            "toString" => Ok(
                self.create_host_function_value(HostFunction::FunctionToString {
                    target: JsValue::HostFunction(host_id),
                }),
            ),
            "valueOf" => Ok(
                self.create_host_function_value(HostFunction::FunctionValueOf {
                    target: JsValue::HostFunction(host_id),
                }),
            ),
            "constructor" => Ok(JsValue::NativeFunction(NativeFunction::FunctionConstructor)),
            _ => {
                let prototype = self.get_prototype_of_value(&JsValue::HostFunction(host_id))?;
                if Self::is_object_like_value(&prototype) {
                    self.get_property_from_base_with_receiver(
                        prototype,
                        property,
                        JsValue::HostFunction(host_id),
                        realm,
                    )
                } else {
                    Ok(JsValue::Undefined)
                }
            }
        }
    }

    fn get_string_property(&mut self, receiver: &str, property: &str) -> JsValue {
        match property {
            "length" => JsValue::Number(Self::utf16_code_unit_length(receiver) as f64),
            "replace" => self.create_host_function_value(HostFunction::StringReplaceThis),
            "match" => self.create_host_function_value(HostFunction::StringMatchThis),
            "search" => self.create_host_function_value(HostFunction::StringSearchThis),
            "indexOf" => self.create_host_function_value(HostFunction::StringIndexOfThis),
            "split" => self.create_host_function_value(HostFunction::StringSplitThis),
            "toLowerCase" => self.create_host_function_value(HostFunction::StringToLowerCaseThis),
            "toUpperCase" => self.create_host_function_value(HostFunction::StringToUpperCase),
            "toString" => self.create_host_function_value(HostFunction::StringToString),
            "valueOf" => self.create_host_function_value(HostFunction::StringValueOf),
            "charAt" => self.create_host_function_value(HostFunction::StringCharAt),
            "charCodeAt" => self.create_host_function_value(HostFunction::StringCharCodeAt),
            "lastIndexOf" => self.create_host_function_value(HostFunction::StringLastIndexOf),
            "substring" => self.create_host_function_value(HostFunction::StringSubstring),
            "substr" => self.create_host_function_value(HostFunction::StringSubstr),
            "trim" => self.create_host_function_value(HostFunction::StringTrim),
            "anchor" => self.create_host_function_value(HostFunction::StringAnchor),
            "big" => self.create_host_function_value(HostFunction::StringBig),
            "blink" => self.create_host_function_value(HostFunction::StringBlink),
            "bold" => self.create_host_function_value(HostFunction::StringBold),
            "fixed" => self.create_host_function_value(HostFunction::StringFixed),
            "fontcolor" => self.create_host_function_value(HostFunction::StringFontColor),
            "fontsize" => self.create_host_function_value(HostFunction::StringFontSize),
            "italics" => self.create_host_function_value(HostFunction::StringItalics),
            "link" => self.create_host_function_value(HostFunction::StringLink),
            "small" => self.create_host_function_value(HostFunction::StringSmall),
            "strike" => self.create_host_function_value(HostFunction::StringStrike),
            "sub" => self.create_host_function_value(HostFunction::StringSub),
            "sup" => self.create_host_function_value(HostFunction::StringSup),
            "constructor" => JsValue::NativeFunction(NativeFunction::StringConstructor),
            _ => match property.parse::<usize>() {
                Ok(index) => receiver
                    .chars()
                    .nth(index)
                    .map(|ch| JsValue::String(ch.to_string()))
                    .unwrap_or(JsValue::Undefined),
                Err(_) => JsValue::Undefined,
            },
        }
    }

    fn utf16_code_unit_length(value: &str) -> usize {
        value.encode_utf16().count()
    }

    fn utf16_code_unit_at(value: &str, index: usize) -> Option<u16> {
        value.encode_utf16().nth(index)
    }

    fn get_function_property(
        &mut self,
        closure_id: u64,
        property: &str,
        realm: &Realm,
    ) -> Result<JsValue, VmError> {
        if self.function_rejects_caller_arguments(closure_id)?
            && matches!(property, "caller" | "arguments")
            && !self.closure_has_own_property(closure_id, property)
        {
            return Err(VmError::TypeError("restricted function property access"));
        }
        if let Some(getter) = self
            .closure_objects
            .get(&closure_id)
            .and_then(|object| object.getters.get(property))
            .cloned()
        {
            return self.execute_callable(
                getter,
                Some(JsValue::Function(closure_id)),
                Vec::new(),
                realm,
                false,
            );
        }
        if self
            .closure_objects
            .get(&closure_id)
            .is_some_and(|object| object.setters.contains_key(property))
        {
            return Ok(JsValue::Undefined);
        }
        if let Some(value) = self
            .closure_objects
            .get(&closure_id)
            .and_then(|object| object.properties.get(property))
            .cloned()
        {
            return Ok(value);
        }
        match property {
            "length" => {
                let closure = self
                    .closures
                    .get(&closure_id)
                    .ok_or(VmError::UnknownClosure(closure_id))?;
                let function = closure
                    .functions
                    .get(closure.function_id)
                    .ok_or(VmError::UnknownFunction(closure.function_id))?;
                Ok(JsValue::Number(function.length as f64))
            }
            "hasOwnProperty" => Ok(
                self.create_host_function_value(HostFunction::HasOwnProperty {
                    target: JsValue::Function(closure_id),
                }),
            ),
            "isPrototypeOf" => Ok(
                self.create_host_function_value(HostFunction::IsPrototypeOf {
                    target: JsValue::Function(closure_id),
                }),
            ),
            "call" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::Function(closure_id),
                method: FunctionMethod::Call,
            })),
            "apply" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::Function(closure_id),
                method: FunctionMethod::Apply,
            })),
            "bind" => Ok(self.create_host_function_value(HostFunction::BoundMethod {
                target: JsValue::Function(closure_id),
                method: FunctionMethod::Bind,
            })),
            "prototype" => {
                if self.closure_is_arrow(closure_id)? || self.closure_has_no_prototype(closure_id) {
                    Ok(JsValue::Undefined)
                } else {
                    self.get_or_create_function_prototype_property(closure_id)
                }
            }
            "constructor" => Ok(JsValue::NativeFunction(NativeFunction::FunctionConstructor)),
            "toString" => Ok(
                self.create_host_function_value(HostFunction::FunctionToString {
                    target: JsValue::Function(closure_id),
                }),
            ),
            "valueOf" => Ok(
                self.create_host_function_value(HostFunction::FunctionValueOf {
                    target: JsValue::Function(closure_id),
                }),
            ),
            _ => {
                let prototype = self.get_prototype_of_value(&JsValue::Function(closure_id))?;
                if Self::is_object_like_value(&prototype) {
                    self.get_property_from_base_with_receiver(
                        prototype,
                        property,
                        JsValue::Function(closure_id),
                        realm,
                    )
                } else {
                    Ok(JsValue::Undefined)
                }
            }
        }
    }

    fn function_name_for_display(&self, value: &JsValue) -> String {
        match value {
            JsValue::Function(closure_id) => self
                .closures
                .get(closure_id)
                .and_then(|closure| closure.functions.get(closure.function_id))
                .map(|function| function.name.clone())
                .filter(|name| !name.is_empty())
                .unwrap_or_else(|| "anonymous".to_string()),
            JsValue::NativeFunction(_) | JsValue::HostFunction(_) => "native".to_string(),
            _ => "anonymous".to_string(),
        }
    }

